// Scan a compute graph for MUL_MAT_ID nodes, register experts with the unified cache,
// and set up prefetcher + predictor.
// Called once per device via std::call_once.
static void moe_hybrid_init_once(ggml_backend_sycl_context & ctx, ggml_cgraph * cgraph) {
    const int     device = ctx.device;
    sycl::queue & q      = *ctx.stream();

    // Scan graph for MUL_MAT_ID nodes to discover MoE architecture
    int     n_moe_layers        = 0;
    int     n_experts_per_layer = 0;
    int     n_experts_used      = 0;  // top-K from ids tensor
    size_t  expert_weight_bytes = 0;
    int64_t max_K               = 0;  // max input dimension (ne00)
    int64_t max_N               = 0;  // max output dimension (ne01)
    int     max_dispatch_count  = 0;  // max total expert dispatches per MUL_MAT_ID

    struct moe_expert_info {
        int                    layer_id;
        int                    expert_idx;
        const void *           host_ptr;
        size_t                 bytes;
        const ggml_tensor *    tensor;    // src0 tensor for cache key generation
        ggml_tensor_extra_gpu * extra;    // tensor extra for cache UUID
    };
    std::vector<moe_expert_info> expert_list;

    for (int i = 0; i < cgraph->n_nodes; i++) {
        const ggml_tensor * node = cgraph->nodes[i];
        if (node->op != GGML_OP_MUL_MAT_ID) {
            continue;
        }
        const ggml_tensor * src0 = node->src[0];
        if (!src0 || !src0->data) {
            continue;
        }

        // Use name-hash based layer_id so each distinct tensor
        // (gate/up/down within the same block) gets a unique cache key.
        int layer_id = moe_cache_layer_id(src0->name);

        // Build hash→sequential mapping for ExpertPredictor
        if (g_moe_layer_seq[device].find(layer_id) == g_moe_layer_seq[device].end()) {
            g_moe_layer_seq[device][layer_id] = static_cast<int>(g_moe_layer_seq[device].size());
        }

        const int64_t n_experts = src0->ne[2] > 0 ? src0->ne[2] : 1;
        const size_t  nb02      = src0->nb[2];

        // Extract top-K (n_experts_used) from the ids tensor (src[2]).
        // Use the minimum across MUL_MAT_ID nodes: warmup graphs may inflate
        // ids->ne[0] to n_experts (all experts), while normal graphs use the
        // actual top-K from the model's expert_used_count.
        const ggml_tensor * ids = node->src[2];
        if (ids && ids->ne[0] > 0) {
            int ids_k = static_cast<int>(ids->ne[0]);
            if (n_experts_used <= 0 || ids_k < n_experts_used) {
                n_experts_used = ids_k;
            }
        }

        if (n_experts > n_experts_per_layer) {
            n_experts_per_layer = static_cast<int>(n_experts);
        }
        if (nb02 > expert_weight_bytes) {
            expert_weight_bytes = nb02;
        }
        if (src0->ne[0] > max_K) {
            max_K = src0->ne[0];
        }
        if (src0->ne[1] > max_N) {
            max_N = src0->ne[1];
        }
        // Track max dispatch count (top-K * tokens) for pinned buffer sizing
        if (ids) {
            int dispatch = static_cast<int>(ids->ne[0] * std::max(ids->ne[1], (int64_t) 1));
            if (dispatch > max_dispatch_count) {
                max_dispatch_count = dispatch;
            }
        }
        n_moe_layers++;

        // Register each expert's host pointer + tensor info for eager upload
        auto * src0_extra = static_cast<ggml_tensor_extra_gpu *>(src0->extra);
        for (int e = 0; e < n_experts; e++) {
            const void * host_ptr = static_cast<const char *>(src0->data)
                                    + static_cast<size_t>(e) * nb02;
            expert_list.push_back({ layer_id, e, host_ptr, nb02, src0, src0_extra });
        }
    }

    if (n_moe_layers == 0) {
        GGML_LOG_INFO("[MOE-HYBRID] No MUL_MAT_ID nodes found, MoE hybrid disabled\n");
        return;
    }

    // Check how many experts are host-resident vs device-resident.
    // Uses ggml_sycl_is_device_vram_buffer() which checks the buffer's managed_alloc.tier
    // (ground truth from unified cache) instead of sycl::get_pointer_type() which returns
    // 'unknown' in multi-device Level Zero contexts.
    int n_host_experts = 0;
    for (const auto & info : expert_list) {
        if (!ggml_sycl_is_device_vram_buffer(info.tensor)) {
            n_host_experts++;
        }
    }

    GGML_LOG_INFO(
        "[MOE-HYBRID] Detected MoE: %d layers, %d experts/layer, top-%d, %.1f KB/expert, "
        "%d/%zu host-resident\n",
        n_moe_layers, n_experts_per_layer, n_experts_used, expert_weight_bytes / 1024.0, n_host_experts,
        expert_list.size());

    // -----------------------------------------------------------------------
    // Initialize ExpertPlacementTable with discovered dimensions
    // -----------------------------------------------------------------------
    auto & placement_table = ggml_sycl::get_expert_placement_table();
    placement_table.init(n_moe_layers, n_experts_per_layer);
    GGML_SYCL_DEBUG("[MOE-HYBRID] ExpertPlacementTable initialized: %d layers, %d experts/layer\n",
                    n_moe_layers, n_experts_per_layer);

    // Populate placement table — initially all experts are CPU-only
    for (const auto & info : expert_list) {
        ggml_sycl::ExpertPlacement placement{};
        placement.device_id       = -1;  // CPU-only initially
        placement.host_ptr        = const_cast<void *>(info.host_ptr);
        placement.weight_bytes    = info.bytes;
        placement.popularity_rank = -1;  // Unranked initially (profiling will update)
        placement_table.set(info.layer_id, info.expert_idx, placement);
    }
    GGML_SYCL_DEBUG("[MOE-HYBRID] ExpertPlacementTable populated with %zu expert entries\n", expert_list.size());

    // -----------------------------------------------------------------------
    // Early multi-GPU setup: register unified caches for secondary GPUs BEFORE
    // the eager VRAM upload so the upload loop can distribute experts across
    // all devices. The full multi-GPU init (staging buffers etc.) runs later.
    // -----------------------------------------------------------------------
    if (device == 0) {
        const char * multi_gpu_env_early = std::getenv("GGML_SYCL_MOE_MULTI_GPU");
        const bool   multi_gpu_early     = multi_gpu_env_early && std::atoi(multi_gpu_env_early) != 0;
        const int    total_devices_early = ggml_sycl_info().device_count;

        if (multi_gpu_early && total_devices_early >= 2) {
            int n_early_ok = 0;
            for (int gpu_d = 1; gpu_d < total_devices_early && gpu_d < GGML_SYCL_MAX_DEVICES; gpu_d++) {
                try {
                    auto & dev_d = ggml_sycl_get_device(gpu_d);
                    g_secondary_queues[gpu_d] = &dev_d.default_queue();
                    ggml_sycl::unified_cache_register_for_queue(gpu_d, *g_secondary_queues[gpu_d]);
                    n_early_ok++;
                } catch (...) {
                    GGML_SYCL_DEBUG("[MOE-MULTI-GPU] Early init: device %d unavailable\n", gpu_d);
                }
            }
            if (n_early_ok > 0) {
                g_moe_multi_gpu_active.store(true, std::memory_order_release);
            }
        }
    }

    // -----------------------------------------------------------------------
    // Eager VRAM upload: two-pass distribution across ALL available GPUs.
    //
    // Phase 1: Default-assign ALL experts to GPU0 (device_id=0, device_ptr=nullptr).
    //   The dispatch code resolves actual VRAM pointers at runtime via the unified
    //   cache (update_moe_ptr_table → prestage_routed_experts → expert_ptrs_host).
    //   This is the same path used for single-GPU MoE inference.
    //
    // Phase 2: Distribute experts to secondary GPUs using greedy bin-packing by
    //   available VRAM.  Experts placed on secondary GPUs get explicit device_ptr
    //   and override the Phase 1 GPU0 assignment.  Remaining experts stay on GPU0.
    // -----------------------------------------------------------------------
    {
        using namespace ggml_sycl;

        const int n_gpu = g_moe_multi_gpu_active.load(std::memory_order_acquire)
                              ? ggml_sycl_info().device_count
                              : 1;

        std::vector<bool> placed(expert_list.size(), false);
        size_t            n_gpu0 = 0;
        size_t            total_uploaded = 0;

        // --- Phase 1: default-assign experts to GPU0 ----------------------------
        // At init time, expert weights haven't been materialized into VRAM yet
        // (the unified cache does this lazily during the first graph_compute).
        // We set device_id=0 with device_ptr=nullptr — the dispatch code resolves
        // the actual VRAM pointer via update_moe_ptr_table/expert_ptrs_host at
        // runtime. Phase 2 may override some experts to secondary GPUs.
        //
        // Mark experts as placed[] when GPU0's cache budget can hold the full model.
        // This prevents Phase 2 from overriding them to secondary GPUs when it's not
        // beneficial (20B fits entirely in GPU0's VRAM).  For oversized models (120B),
        // placed[] is NOT set — Phase 2 distributes excess to secondary GPUs.
        const size_t total_expert_bytes = expert_list.size() * expert_weight_bytes;
        const size_t gpu0_cache_budget  = unified_cache_total_managed(0);
        const bool   gpu0_can_hold_all  = (gpu0_cache_budget > 0)
                                            && (total_expert_bytes <= gpu0_cache_budget);
        if (expert_weight_bytes > 0) {
            for (size_t ei = 0; ei < expert_list.size(); ei++) {
                const auto & info = expert_list[ei];
                if (!info.extra) {
                    continue;
                }
                auto p      = placement_table.get(info.layer_id, info.expert_idx);
                p.device_id = 0;
                placement_table.set(info.layer_id, info.expert_idx, p);
                n_gpu0++;
                if (gpu0_can_hold_all) {
                    placed[ei] = true;
                }
            }
            GGML_LOG_INFO("[MOE-HYBRID] Phase 1: GPU0 cache budget=%.1f MB, expert total=%.1f MB -> %s\n",
                          gpu0_cache_budget / (1024.0 * 1024.0), total_expert_bytes / (1024.0 * 1024.0),
                          gpu0_can_hold_all ? "all on GPU0 (fits)" : "overflow, Phase 2 distributes");
        }

        // --- Phase 2: distribute experts to secondary GPUs --------------------
        // Upload experts to secondary device VRAM (using ensure_cached_layout).
        // Experts placed here override Phase 1's GPU0 assignment with an explicit
        // device_ptr on the secondary GPU.  Remaining experts stay on GPU0 (cache-resolved).
        struct device_budget {
            int             dev;
            size_t          n_slots;
            size_t          n_uploaded;
            unified_cache * cache;
        };
        std::vector<device_budget> budgets;

        for (int d = 1; d < n_gpu && d < GGML_SYCL_MAX_DEVICES; d++) {
            size_t avail   = unified_cache_available_for_compute(d);
            unified_cache * cache_d = get_unified_cache_for_device(d);
            if (!cache_d || expert_weight_bytes == 0) {
                continue;
            }
            size_t slots = avail / expert_weight_bytes;
            if (slots > 0) {
                budgets.push_back({ d, slots, 0, cache_d });
            }
        }

        if (!budgets.empty()) {
            // Secondary GPU dispatch uses SOA MMVQ kernels, so experts must be
            // cached in SOA layout with proper AOS→SOA reordering.
            ggml_sycl_reorder_fill_ctx reorder_ctx{};

            for (size_t ei = 0; ei < expert_list.size(); ei++) {
                if (placed[ei]) {
                    continue;
                }
                const auto & info = expert_list[ei];
                if (!info.extra) {
                    continue;
                }

                // Find secondary device with most remaining slots
                int    best_idx   = -1;
                size_t best_slots = 0;
                for (int i = 0; i < static_cast<int>(budgets.size()); i++) {
                    if (budgets[i].n_slots > best_slots) {
                        best_idx   = i;
                        best_slots = budgets[i].n_slots;
                    }
                }
                if (best_idx < 0) {
                    break;  // All secondary devices full
                }

                ggml_sycl_cache_id key = ggml_sycl_get_moe_expert_cache_key(
                    info.tensor, info.extra, info.expert_idx);
                if (!key.valid) {
                    continue;
                }

                // Compute SOA layout size for this expert type
                const int64_t ncols       = info.tensor->ne[0];
                const int64_t nrows       = info.tensor->ne[1];
                auto &        budget      = budgets[best_idx];
                const size_t  soa_bytes   = ggml_sycl_layout_bytes_for_dims(
                    info.tensor->type, ncols, nrows, GGML_LAYOUT_SOA, budget.dev);
                const size_t  dst_bytes   = (soa_bytes > 0) ? soa_bytes : info.bytes;

                // Set up reorder context for AOS→SOA conversion
                reorder_ctx             = {};
                reorder_ctx.type        = info.tensor->type;
                reorder_ctx.ncols       = ncols;
                reorder_ctx.nrows       = nrows;
                reorder_ctx.nbytes      = info.bytes;
                reorder_ctx.dst_bytes   = dst_bytes;
                reorder_ctx.layout      = GGML_LAYOUT_SOA;
                reorder_ctx.src_is_device = false;  // src is mmap'd host pointer
                reorder_ctx.device_id   = budget.dev;

                cache_layout_request req{};
                req.key              = key;
                req.src_ptr          = info.host_ptr;
                req.src_size         = info.bytes;
                req.dst_size         = dst_bytes;
                req.type             = cache_entry_type::MOE_EXPERT;
                req.layer_id         = info.layer_id;
                req.expert_id        = info.expert_idx;
                req.layout           = GGML_LAYOUT_SOA;
                req.validate_content = false;
                req.fill_fn          = ggml_sycl_fill_reordered_host;
                req.fill_ctx         = &reorder_ctx;

                cache_layout_result result = budget.cache->ensure_cached_layout(req, {});
                if (result.status == cache_layout_status::READY
                    || result.status == cache_layout_status::IN_PROGRESS) {
                    placement_table.set_device_ptr(
                        info.layer_id, info.expert_idx, budget.dev, result.device_ptr);
                    placement_table.set_popularity(
                        info.layer_id, info.expert_idx, static_cast<int>(total_uploaded));
                    budget.n_slots--;
                    budget.n_uploaded++;
                    total_uploaded++;
                    placed[ei] = true;
                }
            }
        }

        // Verify Phase 2 placement table integrity
        {
            int gpu1_count = 0;
            int gpu0_count = 0;
            int cpu_count  = 0;
            // Check first tensor's experts to see which are on GPU0 vs GPU1
            int first_lid = expert_list.empty() ? -1 : expert_list[0].layer_id;
            std::vector<int> gpu0_experts, gpu1_experts;
            for (const auto & info : expert_list) {
                auto p = placement_table.get(info.layer_id, info.expert_idx);
                if (p.device_id == 1) {
                    gpu1_count++;
                    if (info.layer_id == first_lid) gpu1_experts.push_back(info.expert_idx);
                } else if (p.device_id == 0) {
                    gpu0_count++;
                    if (info.layer_id == first_lid) gpu0_experts.push_back(info.expert_idx);
                } else {
                    cpu_count++;
                }
            }
            GGML_LOG_INFO("[MOE-HYBRID] Phase 2 verify: GPU0=%d GPU1=%d CPU=%d in placement table\n",
                          gpu0_count, gpu1_count, cpu_count);
            // Show which expert IDs are on GPU0 for first tensor
            std::string gpu0_str;
            for (int e : gpu0_experts) gpu0_str += std::to_string(e) + ",";
            GGML_LOG_INFO("[MOE-HYBRID] First tensor L%d: GPU0 experts=[%s] (%zu), GPU1 experts=%zu\n",
                          first_lid, gpu0_str.c_str(), gpu0_experts.size(), gpu1_experts.size());
        }

        // Log distribution summary
        // Phase 2 overrides some GPU0 experts → adjust count.
        size_t n_secondary = 0;
        for (const auto & b : budgets) {
            n_secondary += b.n_uploaded;
        }
        size_t n_gpu0_final = n_gpu0 > n_secondary ? n_gpu0 - n_secondary : 0;
        size_t n_cpu = expert_list.size() > (n_gpu0_final + n_secondary)
                           ? expert_list.size() - (n_gpu0_final + n_secondary) : 0;
        std::string dist_summary = "GPU0=" + std::to_string(n_gpu0_final) + "(cache)";
        for (const auto & b : budgets) {
            dist_summary += " GPU" + std::to_string(b.dev) + "=" + std::to_string(b.n_uploaded);
        }
        GGML_LOG_INFO("[MOE-HYBRID] Expert distribution: %s CPU=%zu (%zu total, %.1f KB/expert)\n",
                      dist_summary.c_str(), n_cpu, expert_list.size(),
                      expert_weight_bytes / 1024.0);
    }

    // Initialize ExpertPrefetcher
    auto & prefetcher = g_expert_prefetchers[device];
    prefetcher.init(q);

    // --- Phase 3: GPU0 expert pre-loading via prefetch pool ---
    // Pre-fill the prefetch VRAM pool with the first N experts per MoE layer.
    // Expert 0 tends to be most frequently activated, so preloading low-index
    // experts gives good coverage even without runtime frequency data.
    if (device == 0 && n_experts_per_layer > 0) {
        // Collect unique layer IDs from expert_list.
        std::map<int, std::vector<int>> layer_experts;  // sorted by layer ID for deterministic order
        for (const auto & info : expert_list) {
            layer_experts[info.layer_id].push_back(info.expert_idx);
        }

        // Sort expert IDs within each layer, then preload round-robin
        // across layers so pool slots are distributed evenly.
        // With 8 slots and 40 layers, each of the first 8 layers gets 1
        // expert (expert 0, the most frequently activated).
        int max_per_layer = 0;
        for (auto & [lid, eids] : layer_experts) {
            std::sort(eids.begin(), eids.end());
            eids.erase(std::unique(eids.begin(), eids.end()), eids.end());
            max_per_layer = std::max(max_per_layer, static_cast<int>(eids.size()));
        }
        for (int round = 0; round < max_per_layer; round++) {
            for (auto & [lid, eids] : layer_experts) {
                if (round < static_cast<int>(eids.size())) {
                    prefetcher.preload_experts(lid, { eids[round] });
                }
            }
        }
        GGML_LOG_INFO("[MOE-HYBRID] Phase 3: GPU0 prefetch pool pre-loading complete "
                      "(pool_capacity=%d)\n", prefetcher.pool_capacity());
    }

    // Initialize ExpertPredictor using top-K detected from graph ids tensor.
    // During warmup, ids->ne[0] may equal n_experts_per_layer (all experts
    // activated for JIT compilation). Cap to a sensible max in that case.
    if (ggml_sycl::ggml_sycl_expert_predict_enabled()) {
        auto & predictor = g_expert_predictors[device];
        if (n_experts_used <= 0 || n_experts_used >= n_experts_per_layer) {
            n_experts_used = std::min(8, n_experts_per_layer);
        }
        const int n_seq_layers = static_cast<int>(g_moe_layer_seq[device].size());
        predictor.init(n_seq_layers, n_experts_per_layer, n_experts_used);
        GGML_LOG_INFO("[MOE-HYBRID] Predictor initialized: %d layers, %d experts, top-%d\n",
                      n_seq_layers, n_experts_per_layer, n_experts_used);

        // Pre-gated routing: scan graph for ffn_gate_inp tensors and register
        // their device pointers so predict_pregate() can run the actual router
        // gate computation 1 layer ahead during MoE dispatch.
        // Gate weights are dense f32 tensors, always in VRAM (not quantized).
        int n_gates_registered = 0;
        for (int i = 0; i < cgraph->n_nodes; i++) {
            const ggml_tensor * node = cgraph->nodes[i];
            // Gate tensors appear as src0 of MUL_MAT ops (the router MUL_MAT)
            // and also in the weight tensor list. Check all tensor sources.
            for (int s = 0; s < GGML_MAX_SRC; s++) {
                const ggml_tensor * src = node->src[s];
                if (!src || !src->name || !src->data) {
                    continue;
                }
                if (!strstr(src->name, "ffn_gate_inp")) {
                    continue;
                }
                // Skip shared expert gate (ffn_gate_inp_shexp) and bias (ffn_gate_inp_b)
                if (strstr(src->name, "ffn_gate_inp_shexp") || strstr(src->name, "ffn_gate_inp_b")) {
                    continue;
                }

                // Extract layer number from tensor name (e.g., "blk.5.ffn_gate_inp" -> 5)
                int block_id = ggml_sycl_tp_extract_layer_number(src->name);
                if (block_id < 0) {
                    continue;
                }

                // Map block_id to sequential layer index via the same mapping
                // used by ExpertPredictor. We need to find which seq_layer_id
                // corresponds to MoE layers for this block.
                // Gate weights have shape [n_experts, n_embd] stored as f32.
                const int gate_n_experts = static_cast<int>(src->ne[1]);
                const int gate_n_embd    = static_cast<int>(src->ne[0]);

                if (gate_n_experts != n_experts_per_layer || gate_n_embd <= 0) {
                    continue;
                }

                // Get device pointer for the gate weights
                const void *     gate_ptr = nullptr;
                sycl::usm::alloc atype    = sycl::get_pointer_type(src->data, q.get_context());
                if (atype == sycl::usm::alloc::device) {
                    gate_ptr = src->data;
                } else {
                    // Try extra->data_device
                    auto * extra = static_cast<ggml_tensor_extra_gpu *>(src->extra);
                    if (extra && extra->data_device[device]) {
                        gate_ptr = extra->data_device[device];
                    }
                }

                if (!gate_ptr) {
                    GGML_SYCL_DEBUG("[MOE-HYBRID] Gate tensor %s not on device, skipping pre-gate\n", src->name);
                    continue;
                }

                // Find the sequential layer index for this block's MoE layers.
                // We can't reverse the FNV hash in g_moe_layer_seq, so scan
                // MUL_MAT_ID nodes to find one in this block and get its seq_id.
                int seq_idx = -1;
                for (int j = 0; j < cgraph->n_nodes; j++) {
                    const ggml_tensor * mmid_node = cgraph->nodes[j];
                    if (mmid_node->op != GGML_OP_MUL_MAT_ID) {
                        continue;
                    }
                    const ggml_tensor * mmid_src0 = mmid_node->src[0];
                    if (!mmid_src0 || !mmid_src0->name) {
                        continue;
                    }
                    int mmid_block = ggml_sycl_tp_extract_layer_number(mmid_src0->name);
                    if (mmid_block != block_id) {
                        continue;
                    }
                    int  hash_id = moe_cache_layer_id(mmid_src0->name);
                    auto it      = g_moe_layer_seq[device].find(hash_id);
                    if (it != g_moe_layer_seq[device].end()) {
                        seq_idx = it->second;
                        break;
                    }
                }

                if (seq_idx >= 0) {
                    predictor.register_gate_weights(seq_idx, gate_ptr, gate_n_embd);
                    n_gates_registered++;
                    GGML_SYCL_DEBUG(
                        "[MOE-HYBRID] Registered gate weights for blk.%d "
                        "(seq=%d, n_embd=%d, ptr=%p)\n",
                        block_id, seq_idx, gate_n_embd, gate_ptr);
                    break;  // Found gate for this node, move to next node
                }
            }
        }
        if (n_gates_registered > 0) {
            GGML_LOG_INFO("[MOE-HYBRID] Pre-gated routing: registered %d gate weight tensors\n", n_gates_registered);
        }
    }

    // Initialize PinnedBufferPool for O(1) acquire/release of pinned staging
    // buffers used by CPU expert dispatch (replaces per-call malloc_host/free).
    // max_experts = n_experts_used (top-K per MUL_MAT_ID) for single-token TG.
    if (max_K > 0 && max_N > 0 && max_dispatch_count > 0) {
        auto & pool = g_pinned_buffer_pools[device];
        pool.init(q, device, static_cast<size_t>(max_dispatch_count),
                  static_cast<size_t>(max_K), static_cast<size_t>(max_N));
    }

    // Initialize CPU expert thread pool for persistent async dispatch.
    // Thread count auto-detected (hardware_concurrency - 2) or overridden
    // via GGML_SYCL_CPU_EXPERT_THREADS=N.
    if (max_K > 0 && max_N > 0 && max_dispatch_count > 0) {
        auto & cpu_pool = g_cpu_expert_pools[device];
        cpu_pool.init(0 /* auto thread count */,
                      static_cast<size_t>(max_dispatch_count),
                      static_cast<size_t>(max_K),
                      static_cast<size_t>(max_N), q);
    }

    // -----------------------------------------------------------------------
    // Multi-GPU MoE: complete secondary GPU init (staging buffers, buffer pools).
    // Queues and caches were already registered in the early init block above.
    // -----------------------------------------------------------------------
    if (device == 0 && g_moe_multi_gpu_active.load(std::memory_order_acquire)) {
        const int total_devices = ggml_sycl_info().device_count;
        int       n_secondary_ok = 0;

        for (int gpu_d = 1; gpu_d < total_devices && gpu_d < GGML_SYCL_MAX_DEVICES; gpu_d++) {
            if (!g_secondary_queues[gpu_d]) {
                continue;  // Early init failed for this device
            }
            GGML_LOG_INFO("[MOE-MULTI-GPU] Initializing device %d for MoE expert dispatch\n", gpu_d);

            try {
                if (max_K > 0 && max_N > 0 && max_dispatch_count > 0) {
                    auto & pool_d = g_pinned_buffer_pools[gpu_d];
                    pool_d.init(*g_secondary_queues[gpu_d], gpu_d,
                                static_cast<size_t>(max_dispatch_count),
                                static_cast<size_t>(max_K),
                                static_cast<size_t>(max_N));
                }

                // Allocate malloc_host staging buffer for secondary GPU expert outputs.
                // malloc_host is PCIe zero-copy readable from primary GPU's compute queue.
                const size_t staging_floats = static_cast<size_t>(max_dispatch_count) * static_cast<size_t>(max_N);
                const size_t staging_bytes  = staging_floats * sizeof(float);
                try {
                    // Use device 0's context for malloc_host so primary GPU can read it
                    g_secondary_staging_buffer[gpu_d] = sycl::malloc_host<float>(staging_floats, q.get_context());
                    g_secondary_staging_size[gpu_d]   = staging_floats;
                    g_secondary_staging_max_N[gpu_d]  = static_cast<size_t>(max_N);
                    if (g_secondary_staging_buffer[gpu_d]) {
                        std::memset(g_secondary_staging_buffer[gpu_d], 0, staging_bytes);
                        GGML_LOG_INFO(
                            "[MOE-MULTI-GPU] Device %d staging buffer: %.1f KB "
                            "(max_dispatch=%d, N=%ld)\n",
                            gpu_d, staging_bytes / 1024.0, max_dispatch_count, (long) max_N);
                    }
                } catch (const sycl::exception & e) {
                    GGML_LOG_WARN("[MOE-MULTI-GPU] Failed to allocate staging buffer for device %d: %s\n",
                                  gpu_d, e.what());
                    g_secondary_staging_buffer[gpu_d] = nullptr;
                    g_secondary_staging_size[gpu_d]   = 0;
                }

                if (g_secondary_staging_buffer[gpu_d]) {
                    n_secondary_ok++;
                    GGML_LOG_INFO("[MOE-MULTI-GPU] Device %d ready for MoE dispatch\n", gpu_d);
                } else {
                    GGML_LOG_WARN("[MOE-MULTI-GPU] Device %d initialization incomplete\n", gpu_d);
                }
            } catch (const sycl::exception & e) {
                GGML_LOG_WARN("[MOE-MULTI-GPU] Failed to initialize device %d: %s\n", gpu_d, e.what());
            } catch (const std::exception & e) {
                GGML_LOG_WARN("[MOE-MULTI-GPU] Failed to initialize device %d: %s\n", gpu_d, e.what());
            }
        }

        if (n_secondary_ok > 0) {
            GGML_LOG_INFO("[MOE-MULTI-GPU] Active: primary (dev 0) + %d secondary device(s)\n",
                          n_secondary_ok);
        } else {
            // Early init registered caches but no staging buffers available.
            // Deactivate multi-GPU since activation shipping requires staging.
            g_moe_multi_gpu_active.store(false, std::memory_order_release);
            GGML_LOG_WARN("[MOE-MULTI-GPU] No secondary devices completed init, "
                          "falling back to single-GPU\n");
        }
    }
}

