static bool persistent_tg_prefer_soa_layout() {
    static int prefer = -1;
    if (prefer < 0) {
        // Default on for persistent TG: SoA consistently improves Q4_0 matmul throughput.
        // Set GGML_SYCL_PERSISTENT_TG_PREFER_SOA=0 to force legacy AoS behavior.
        const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_PREFER_SOA");
        prefer           = (env == nullptr || std::atoi(env) != 0) ? 1 : 0;
    }
    return prefer != 0;
}

static bool persistent_tg_micro_graph_enabled() {
    static int checked = -1;
    if (checked < 0) {
        const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_MICRO_GRAPH");
        // Default ON — micro-graph is production-ready; set =0 to disable
        checked = (env != nullptr && std::strcmp(env, "0") == 0) ? 0 : 1;
    }
    return checked == 1;
}

// One-time initialization of persistent TG debug configuration.
// Env vars are read-once; mutable per-call state is separate.
struct PersistentTGDebugConfig {
    bool set_rows_check;
    bool attn_validate;
    bool rms_validate;
    bool matmul_validate;
    bool add_dump;
    bool mul_dump;
    bool profile_build;
    bool log_ops;
    bool stage_host_ptrs;
    int  max_ops_limit;
    int  rms_dump_instance;

    static const PersistentTGDebugConfig & get() {
        static const PersistentTGDebugConfig cfg = init();
        return cfg;
    }

  private:
    static PersistentTGDebugConfig init() {
        PersistentTGDebugConfig c = {};
        c.set_rows_check          = (std::getenv("GGML_SYCL_PERSISTENT_TG_CHECK_SET_ROWS") != nullptr) ||
                           (std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_SET_ROWS") != nullptr);
        c.attn_validate   = (std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_ATTN") != nullptr);
        c.rms_validate    = (std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_RMS_NORM") != nullptr);
        c.matmul_validate = (std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_MATMUL") != nullptr);
        {
            const char * env = std::getenv("GGML_SYCL_TG_DUMP_ADD");
            c.add_dump       = (env && std::atoi(env) != 0);
        }
        {
            const char * env = std::getenv("GGML_SYCL_TG_DUMP_MUL");
            c.mul_dump       = (env && std::atoi(env) != 0);
        }
        c.profile_build   = (std::getenv("GGML_SYCL_PERSISTENT_TG_PROFILE_BUILD") != nullptr);
        c.log_ops         = (std::getenv("GGML_SYCL_PERSISTENT_TG_LOG_OPS") != nullptr);
        c.stage_host_ptrs = (std::getenv("GGML_SYCL_PERSISTENT_TG_STAGE_HOST_PTRS") != nullptr);
        c.max_ops_limit   = -1;
        if (const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_MAX_OPS")) {
            const int val = std::atoi(env);
            if (val > 0) {
                c.max_ops_limit = val;
            }
        }
        c.rms_dump_instance = -1;
        if (const char * env = std::getenv("GGML_SYCL_TG_DUMP_RMS_INSTANCE")) {
            if (*env) {
                char *     end = nullptr;
                const long val = std::strtol(env, &end, 10);
                if (end && end != env) {
                    c.rms_dump_instance = (int) val;
                }
            }
        }
        return c;
    }
};

// Resolve weight pointer for a specific device in multi-device persistent TG.
// For the primary device (device 0): returns the SOA layout pointer from the unified cache
// (full-N allocation; the kernel uses row_count to limit computation).
// For secondary devices: returns the partial-N SOA pointer from the split weight cache,
// loading it via D2H + unified_cache_load_partial_rows on first access.
// Returns nullptr if the weight is unavailable for the given device.
static const void * resolve_split_weight_ptr(
        const ggml_tensor * weight_tensor,
        int                 device,
        int                 primary_device,
        layout_mode         weight_layout,
        int64_t             row_start,
        int64_t             row_count) {
    if (device == primary_device) {
        // Primary device: use standard layout pointer (covers full N rows)
        return ggml_sycl_get_layout_ptr_for(weight_tensor, device, weight_layout);
    }

    // Secondary device: look up partial-N SOA in unified cache
    if (!weight_tensor->name) return nullptr;
    void * cached = ggml_sycl::unified_cache_get_split_weight_ptr(weight_tensor->name, device);
    if (cached) return cached;

    // Not cached yet — load via D2H from primary AOS + unified cache H2D + SOA reorder
    const void * src_aos = ggml_sycl_get_layout_ptr_for(weight_tensor, primary_device, GGML_LAYOUT_AOS);
    if (!src_aos) return nullptr;

    const size_t row_bytes   = ggml_row_size(weight_tensor->type, weight_tensor->ne[0]);
    const void * src_offset  = static_cast<const char *>(src_aos) + row_start * row_bytes;
    const size_t total_bytes = (size_t) row_count * row_bytes;

    // Host staging: D2H from primary device
    sycl::queue * q_primary = g_split_config.queue[0];
    void * staging = sycl::malloc_host(total_bytes, *q_primary);
    if (!staging) {
        GGML_LOG_WARN("[PERSISTENT-TG-SPLIT] malloc_host failed for weight staging (%zu bytes)\n", total_bytes);
        return nullptr;
    }
    q_primary->memcpy(staging, src_offset, total_bytes).wait();

    // Load into unified cache for target device (H2D + SOA reorder)
    void * dev_ptr = ggml_sycl::unified_cache_load_partial_rows(
        weight_tensor->name, staging, weight_tensor->type,
        weight_tensor->ne[0], row_count, device);

    sycl::free(staging, *q_primary);

    if (!dev_ptr) {
        GGML_LOG_WARN("[PERSISTENT-TG-SPLIT] unified cache load failed for %s device %d\n",
                      weight_tensor->name, device);
    } else {
        GGML_SYCL_DEBUG("[PERSISTENT-TG-SPLIT] loaded %s via unified cache device %d: %lld rows\n",
                        weight_tensor->name, device, (long long) row_count);
    }
    return dev_ptr;
}

/**
 * Build a persistent execution plan from the compute graph using UnifiedKernel API.
 *
 * Walks the graph, identifies transformer operations, and adds them to the
 * UnifiedKernel's persistent execution plan.
 *
 * @param kernel  UnifiedKernel instance to build plan on
 * @param ctx     SYCL backend context (for device pointers)
 * @param cgraph  Compute graph to extract operations from
 * @return true if plan was successfully built
 */
static bool extract_persistent_plan(ggml_sycl::UnifiedKernel &  kernel,
                                    ggml_backend_sycl_context & ctx,
                                    ggml_cgraph *               cgraph) {
    init_sycl_tg_trace();
    const auto & dbg_cfg = PersistentTGDebugConfig::get();

    if (g_sycl_tg_trace_hash) {
        g_persistent_trace_ops.clear();
        g_sycl_trace_op_index = 0;
    }
    g_persistent_debug_hash_ptr = nullptr;

    g_persistent_set_rows_dbg.enabled     = dbg_cfg.set_rows_check;
    g_persistent_set_rows_dbg.captured    = false;
    g_persistent_set_rows_dbg.debug_ptr   = nullptr;
    g_persistent_set_rows_dbg.debug_count = 0;

    g_persistent_attn_dbg.enabled      = dbg_cfg.attn_validate;
    g_persistent_attn_dbg.captured     = false;
    g_persistent_attn_dbg.node         = nullptr;
    g_persistent_attn_dbg.debug_ptr    = nullptr;
    g_persistent_attn_dbg.debug_floats = 0;
    g_persistent_attn_dbg.layer        = -1;
    static bool logged_attn_env        = false;
    if (!logged_attn_env) {
        logged_attn_env = true;
        GGML_SYCL_DEBUG("[PERSISTENT-TG] ATTN validate env=%s\n", dbg_cfg.attn_validate ? "enabled" : "disabled");
    }

    g_persistent_rms_dbg.enabled    = dbg_cfg.rms_validate;
    g_persistent_rms_dbg.captured   = false;
    g_persistent_rms_dbg.node       = nullptr;
    g_persistent_rms_dbg.debug_ptr  = nullptr;
    g_persistent_rms_dbg.debug_flag = nullptr;
    g_persistent_rms_dbg.hidden_dim = 0;
    g_persistent_rms_dbg.eps        = 0.0f;
    g_persistent_rms_dbg.layer      = -1;

    g_persistent_matmul_dbg.enabled    = dbg_cfg.matmul_validate;
    g_persistent_matmul_dbg.captured   = false;
    g_persistent_matmul_dbg.node       = nullptr;
    g_persistent_matmul_dbg.debug_ptr  = nullptr;
    g_persistent_matmul_dbg.debug_flag = nullptr;
    g_persistent_matmul_dbg.out_dim    = 0;
    g_persistent_matmul_dbg.layer      = -1;
    g_persistent_matmul_dbg.mtype      = MatmulType::GENERIC;

    g_persistent_add_dbg.enabled  = dbg_cfg.add_dump;
    g_persistent_add_dbg.captured = false;
    g_persistent_add_dbg.node     = nullptr;
    g_persistent_add_dbg.out_dim  = 0;
    g_persistent_add_dbg.layer    = -1;

    g_persistent_mul_dbg.enabled  = dbg_cfg.mul_dump;
    g_persistent_mul_dbg.captured = false;
    g_persistent_mul_dbg.node     = nullptr;
    g_persistent_mul_dbg.out_dim  = 0;
    g_persistent_mul_dbg.layer    = -1;

    std::array<int, GGML_OP_COUNT> graph_op_counts{};
    std::array<int, GGML_OP_COUNT> plan_op_counts{};
    int                            skipped_view       = 0;
    int                            skipped_reshape    = 0;
    int                            skipped_permute    = 0;
    int                            executed_get_rows  = 0;
    int                            executed_cpy       = 0;
    int64_t                        decode_kv_pos_hint = -1;
    int                            ops_added          = 0;
    const bool                     profile_build      = dbg_cfg.profile_build;
    using clock_t                                     = std::chrono::high_resolution_clock;
    const auto                        build_start     = profile_build ? clock_t::now() : clock_t::time_point{};
    std::array<double, GGML_OP_COUNT> build_ms_by_op{};
    const int                         max_ops_limit     = dbg_cfg.max_ops_limit;
    const bool                        log_ops           = dbg_cfg.log_ops;
    const int                         rms_dump_instance = dbg_cfg.rms_dump_instance;

    // 1. Extract model dimensions
    int n_layers, hidden_dim, intermediate_dim, n_heads, n_kv_heads, head_dim, quant_type;
    if (!extract_model_dimensions(cgraph, n_layers, hidden_dim, intermediate_dim, n_heads, n_kv_heads, head_dim,
                                  quant_type)) {
        GGML_LOG_ERROR("[PERSISTENT-TG] Failed to extract model dimensions from graph\n");
        return false;
    }
    int tokens = -1;
    for (int i = 0; i < cgraph->n_nodes; i++) {
        ggml_tensor * node = cgraph->nodes[i];
        if (!node || node->op != GGML_OP_MUL || node->name[0] == '\0') {
            continue;
        }
        if (std::strstr(node->name, "attn_norm") || std::strstr(node->name, "ffn_norm")) {
            tokens = (int) node->ne[1];
            break;
        }
    }
    if (tokens < 0) {
        for (int i = 0; i < cgraph->n_nodes; i++) {
            ggml_tensor * node = cgraph->nodes[i];
            if (!node || node->op != GGML_OP_MUL_MAT || node->name[0] == '\0') {
                continue;
            }
            if (std::strstr(node->name, "Qcur") != nullptr) {
                tokens = (int) node->ne[1];
                break;
            }
        }
    }
    if (tokens < 0) {
        tokens = 1;
    }
    if (tokens > 1) {
        GGML_LOG_INFO("[PERSISTENT-TG] Skipping persistent plan (n_tokens=%d > 1)\n", tokens);
        return false;
    }

    sycl::queue *                                             q = ctx.stream();
    std::unordered_map<const ggml_tensor *, void *>           materialized_ptrs;
    std::vector<int>                                          rms_seen_per_layer(n_layers, 0);
    std::unordered_map<uint64_t, std::pair<float *, float *>> rope_cache_by_pos;
    int32_t                                                   rope_position_cached = -1;

    auto get_tensor_ptr_fast = [&](const ggml_tensor * tensor) -> void * {
        if (!tensor) {
            return nullptr;
        }

        if (tensor->extra) {
            auto * extra = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
            if (extra->data_device[ctx.device] != nullptr) {
                return extra->data_device[ctx.device];
            }
        }

        // Check layer stream manager for host-resident weights
        if (ggml_sycl_tensor_is_weight(tensor) && g_model_exceeds_vram.load(std::memory_order_acquire) &&
            ggml_sycl::layer_streaming_active(ctx.device) && tensor->name) {
            void * streamed = ggml_sycl::layer_streaming_get_weight_ptr(ctx.device, tensor->name);
            if (streamed) {
                return streamed;
            }
        }

        if (tensor->data != nullptr) {
            return tensor->data;
        }

        return ggml_sycl_get_data_ptr(tensor, ctx.device);
    };

    auto get_tensor_ptr_view_fast = [&](const ggml_tensor * tensor) -> void * {
        if (!tensor) {
            return nullptr;
        }

        size_t              view_offs = 0;
        const ggml_tensor * root      = ggml_sycl_get_view_root(tensor, view_offs);
        if (!root) {
            root = tensor;
        }

        void * base_ptr = get_tensor_ptr_fast(root);
        if (!base_ptr) {
            base_ptr = ggml_sycl_get_data_ptr(root, ctx.device);
        }
        if (!base_ptr) {
            return nullptr;
        }

        return static_cast<void *>(static_cast<char *>(base_ptr) + view_offs);
    };

    auto compute_contiguous_nb = [](const ggml_tensor * tensor, int64_t nb[4]) {
        const int64_t ts = (int64_t) ggml_type_size(tensor->type);
        nb[0]            = ts;
        nb[1]            = nb[0] * tensor->ne[0];
        nb[2]            = nb[1] * tensor->ne[1];
        nb[3]            = nb[2] * tensor->ne[2];
    };
    // Helper: read a single int32_t from a tensor pointer, preferring host-side
    // read when the pointer is host-accessible (malloc_host or malloc_shared).
    // Falls back to blocking D2H memcpy only for device-only pointers.
    const sycl::context & sycl_ctx_ref = q->get_context();
    auto read_i32_host_or_d2h = [&](const int32_t * ptr) -> int32_t {
        const auto alloc_type = sycl::get_pointer_type(ptr, sycl_ctx_ref);
        if (alloc_type == sycl::usm::alloc::host || alloc_type == sycl::usm::alloc::shared) {
            return *ptr;
        }
        int32_t val;
        q->memcpy(&val, ptr, sizeof(int32_t)).wait();
        return val;
    };
    auto read_i64_host_or_d2h = [&](const void * ptr) -> int64_t {
        const auto alloc_type = sycl::get_pointer_type(ptr, sycl_ctx_ref);
        if (alloc_type == sycl::usm::alloc::host || alloc_type == sycl::usm::alloc::shared) {
            return *(const int64_t *)ptr;
        }
        int64_t val;
        q->memcpy(&val, ptr, sizeof(int64_t)).wait();
        return val;
    };
    auto log_op = [&](const char * tag, int layer, const ggml_tensor * node, const void * output_ptr) {
        if (!log_ops) {
            return;
        }
        const char * name = (node && node->name[0] != '\0') ? node->name : "(unnamed)";
        GGML_LOG_INFO("[PERSISTENT-TG] op[%d] %s layer=%d name=%s out=%p\n", ops_added, tag, layer, name, output_ptr);
    };
    auto log_tensor = [&](const char * tag, const ggml_tensor * t) {
        if (!log_ops || (max_ops_limit > 0 && ops_added < max_ops_limit - 2)) {
            return;
        }
        if (!t) {
            GGML_LOG_INFO("[PERSISTENT-TG] %s: null\n", tag);
            return;
        }
        GGML_LOG_INFO(
            "[PERSISTENT-TG] %s: name=%s type=%d ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld] contig=%d "
            "permuted=%d\n",
            tag, t->name[0] != '\0' ? t->name : "(unnamed)", (int) t->type, (long long) t->ne[0], (long long) t->ne[1],
            (long long) t->ne[2], (long long) t->ne[3], (long long) t->nb[0], (long long) t->nb[1],
            (long long) t->nb[2], (long long) t->nb[3], ggml_is_contiguous(t) ? 1 : 0, ggml_is_permuted(t) ? 1 : 0);
    };

    auto resolve_input_ptr = [&](const ggml_tensor * tensor, int layer) -> const void * {
        if (!tensor) {
            return nullptr;
        }
        auto it = materialized_ptrs.find(tensor);
        if (it != materialized_ptrs.end()) {
            return it->second;
        }

        // If this tensor is a view, prefer an already-materialized root pointer.
        // This preserves GET_ROWS stable snapshots across view/reshape chains.
        size_t              view_offs = 0;
        const ggml_tensor * view_root = ggml_sycl_get_view_root(tensor, view_offs);
        if (view_root && view_root != tensor) {
            auto root_it = materialized_ptrs.find(view_root);
            if (root_it != materialized_ptrs.end()) {
                const void * ptr = static_cast<const char *>(root_it->second) + view_offs;
                materialized_ptrs.emplace(tensor, const_cast<void *>(ptr));
                return ptr;
            }
        }

        if (ggml_is_contiguous(tensor) && !ggml_is_permuted(tensor)) {
            void * ptr = get_tensor_ptr_view_fast(tensor);
            materialized_ptrs.emplace(tensor, ptr);
            return ptr;
        }

        const size_t             bytes = ggml_nbytes(tensor);
        ggml_sycl::alloc_request mat_req;
        mat_req.queue                          = q;
        mat_req.device                         = ctx.device;
        mat_req.size                           = bytes;
        mat_req.intent.role                    = ggml_sycl::alloc_role::GRAPH_TMP;
        mat_req.intent.category                = ggml_sycl::runtime_category::GRAPH;
        mat_req.intent.constraints.must_device = true;
        ggml_sycl::alloc_handle dst_alloc{};
        if (!ggml_sycl::unified_alloc(mat_req, &dst_alloc) || dst_alloc.ptr == nullptr) {
            GGML_LOG_ERROR("[PERSISTENT-TG] Failed to allocate %zu bytes for materialized tensor\n", bytes);
            return nullptr;
        }
        void * dst_ptr = dst_alloc.ptr;
        if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
            GGML_LOG_INFO("[PERSISTENT-TG] resolve_input_ptr: alloc dst_ptr=%p bytes=%zu\n", dst_ptr, bytes);
        }
        kernel.add_temp_device_alloc_handle(dst_alloc);

        StridedCopyMeta meta = {};
        for (int d = 0; d < GGML_MAX_DIMS; d++) {
            meta.ne[d] = tensor->ne[d];
            meta.nb[d] = (int64_t) tensor->nb[d];
        }
        meta.type_size = (int32_t) ggml_type_size(tensor->type);
        meta.pad       = 0;

        if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
            GGML_LOG_INFO("[PERSISTENT-TG] resolve_input_ptr: materialize name=%s bytes=%zu\n",
                          tensor->name[0] != '\0' ? tensor->name : "(unnamed)", bytes);
        }
        const void * src_ptr = get_tensor_ptr_view_fast(tensor);
        if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
            GGML_LOG_INFO("[PERSISTENT-TG] resolve_input_ptr: src_ptr=%p\n", src_ptr);
        }
        const int64_t n_elements = ggml_nelements(tensor);
        if (n_elements > std::numeric_limits<int>::max()) {
            GGML_LOG_ERROR("[PERSISTENT-TG] Materialize tensor too large: %lld elements\n", (long long) n_elements);
            return nullptr;
        }
        const int64_t output_bytes = n_elements * meta.type_size;
        kernel.add_strided_copy(layer, src_ptr, dst_ptr, meta, (int) n_elements, output_bytes);
        log_op("STRIDED_COPY", layer, tensor, dst_ptr);
        ops_added++;

        materialized_ptrs.emplace(tensor, dst_ptr);
        return dst_ptr;
    };

    // Fast-path pointer resolver: never materialize via STRIDED_COPY.
    // If a tensor needs materialization, return nullptr so caller can fall back.
    auto resolve_input_ptr_no_materialize = [&](const ggml_tensor * tensor) -> const void * {
        if (!tensor) {
            return nullptr;
        }
        auto it = materialized_ptrs.find(tensor);
        if (it != materialized_ptrs.end()) {
            return it->second;
        }

        size_t              view_offs = 0;
        const ggml_tensor * view_root = ggml_sycl_get_view_root(tensor, view_offs);
        if (view_root && view_root != tensor) {
            auto root_it = materialized_ptrs.find(view_root);
            if (root_it != materialized_ptrs.end()) {
                const void * ptr = static_cast<const char *>(root_it->second) + view_offs;
                materialized_ptrs.emplace(tensor, const_cast<void *>(ptr));
                return ptr;
            }
        }

        if (ggml_is_contiguous(tensor) && !ggml_is_permuted(tensor)) {
            void * ptr = get_tensor_ptr_view_fast(tensor);
            materialized_ptrs.emplace(tensor, ptr);
            return ptr;
        }

        return nullptr;
    };

    auto resolve_input_ptr_with_nb = [&](const ggml_tensor * tensor, int layer, int64_t nb[4],
                                         bool allow_strided) -> const void * {
        if (!tensor) {
            return nullptr;
        }
        const bool materialize = !allow_strided && !(ggml_is_contiguous(tensor) && !ggml_is_permuted(tensor));
        if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
            GGML_LOG_INFO(
                "[PERSISTENT-TG] resolve_input_ptr_with_nb: name=%s materialize=%d allow_strided=%d contig=%d "
                "permuted=%d\n",
                tensor->name[0] != '\0' ? tensor->name : "(unnamed)", materialize ? 1 : 0, allow_strided ? 1 : 0,
                ggml_is_contiguous(tensor) ? 1 : 0, ggml_is_permuted(tensor) ? 1 : 0);
        }
        if (allow_strided) {
            void * ptr = get_tensor_ptr_view_fast(tensor);
            if (!ptr) {
                return nullptr;
            }
            for (int d = 0; d < GGML_MAX_DIMS; d++) {
                nb[d] = (int64_t) tensor->nb[d];
            }
            return ptr;
        }
        const void * ptr = resolve_input_ptr(tensor, layer);
        if (!ptr) {
            return nullptr;
        }
        if (materialize) {
            compute_contiguous_nb(tensor, nb);
        } else {
            for (int d = 0; d < GGML_MAX_DIMS; d++) {
                nb[d] = (int64_t) tensor->nb[d];
            }
        }
        return ptr;
    };

    auto get_usm_alloc_type = [&](const void * ptr) -> sycl::usm::alloc {
        if (!ptr) {
            return sycl::usm::alloc::unknown;
        }
        try {
            return sycl::get_pointer_type(ptr, q->get_context());
        } catch (...) {
            return sycl::usm::alloc::unknown;
        }
    };

    auto ensure_device_access_ptr = [&](const ggml_tensor * tensor, const void * ptr, const char * tag,
                                        size_t bytes_override = 0) -> const void * {
        if (!ptr) {
            return nullptr;
        }

        const sycl::usm::alloc alloc_type = get_usm_alloc_type(ptr);
        if (alloc_type == sycl::usm::alloc::device || alloc_type == sycl::usm::alloc::shared) {
            return ptr;
        }

        // Host-pointer staging is expensive (alloc + copy + sync per pointer).
        // Keep passthrough by default and allow opt-in staging for diagnostics.
        const bool stage_host_ptrs = PersistentTGDebugConfig::get().stage_host_ptrs;
        if (!stage_host_ptrs) {
            return ptr;
        }

        if (!tensor || !ggml_is_contiguous(tensor) || ggml_is_permuted(tensor)) {
            GGML_LOG_ERROR("[PERSISTENT-TG] %s requires contiguous tensor for host->device staging\n", tag);
            return nullptr;
        }

        const size_t bytes = bytes_override > 0 ? bytes_override : ggml_nbytes(tensor);
        if (bytes == 0) {
            return ptr;
        }

        ggml_sycl::alloc_request stage_req;
        stage_req.queue                          = q;
        stage_req.device                         = ctx.device;
        stage_req.size                           = bytes;
        stage_req.intent.role                    = ggml_sycl::alloc_role::GRAPH_TMP;
        stage_req.intent.category                = ggml_sycl::runtime_category::GRAPH;
        stage_req.intent.constraints.must_device = true;
        ggml_sycl::alloc_handle stage_alloc{};
        if (!ggml_sycl::unified_alloc(stage_req, &stage_alloc) || stage_alloc.ptr == nullptr) {
            GGML_LOG_ERROR("[PERSISTENT-TG] %s device alloc failed (%zu bytes)\n", tag, bytes);
            return nullptr;
        }
        void * dev_ptr = stage_alloc.ptr;

        kernel.add_temp_device_alloc_handle(stage_alloc);
        ggml_sycl_safe_memcpy(*q, dev_ptr, ptr, bytes, {});
        q->wait_and_throw();
        return dev_ptr;
    };

    auto record_trace = [&](ggml_op op, const ggml_tensor * tensor, const void * output_ptr, int op_index) {
        if (!g_sycl_tg_trace_hash || !tensor || !output_ptr) {
            return;
        }
        persistent_trace_entry entry;
        entry.op         = op;
        entry.tensor     = tensor;
        entry.output_ptr = output_ptr;
        entry.op_index   = op_index;
        g_persistent_trace_ops.push_back(entry);
    };

    // Fast path: reuse cached plan and refresh mutable pointers only.
    if (kernel.has_cached_plan()) {
        const bool fast_path_debug_disabled = g_sycl_tg_trace_hash || profile_build || log_ops || (max_ops_limit > 0) ||
                                              g_persistent_set_rows_dbg.enabled || g_persistent_attn_dbg.enabled ||
                                              g_persistent_rms_dbg.enabled || g_persistent_matmul_dbg.enabled ||
                                              g_persistent_add_dbg.enabled || g_persistent_mul_dbg.enabled;

        // ----------------------------------------------------------------
        // ULTRA-FAST path: skip full ggml graph walk, update only mutable ops.
        // After the first successful fast-path update builds an update recipe,
        // subsequent tokens use it to iterate only the ~130 ops that need
        // per-token pointer updates (out of ~350 plan ops and ~1158 graph nodes).
        // ----------------------------------------------------------------
        if (!fast_path_debug_disabled && kernel.has_update_recipe()) {
            kernel.begin_plan_update();

            const auto & recipe = kernel.get_update_recipe();
            bool         recipe_ok          = true;
            int          get_rows_counter   = 0;
            int32_t      rope_position_cached_r = -1;

            for (const auto & entry : recipe) {
                if (!recipe_ok) {
                    break;
                }
                // Skip CPY sentinel entries (handled separately after the loop)
                if (entry.get_rows_idx == -2) {
                    continue;
                }
                const int           oi   = entry.plan_op_idx;
                ggml_tensor *       node = cgraph->nodes[entry.graph_node_idx];

                // GET_ROWS has no plan op (plan_op_idx == -1); others use direct mutable access
                OperationDescriptor * op = (oi >= 0) ? kernel.get_op_descriptor_mut(oi) : nullptr;
                if (oi >= 0 && !op) {
                    recipe_ok = false;
                    break;
                }

                switch (entry.op_type) {
                    case OperationType::GET_ROWS:
                        {
                            // Re-execute embedding lookup (different token each time)
                            if (!node || !node->src[0] || !node->src[1]) {
                                recipe_ok = false;
                                break;
                            }
                            ggml_sycl_op_get_rows(ctx, node);
                            // In-order queue: subsequent memcpy serializes after GET_ROWS
                            const int    gr_idx     = get_rows_counter++;
                            const size_t bytes      = ggml_nbytes(node);
                            void *       stable_ptr = kernel.get_rows_stable_ptr(gr_idx, bytes);
                            const void * out_ptr    = get_tensor_ptr_view_fast(node);
                            if (!stable_ptr || !out_ptr) {
                                recipe_ok = false;
                                break;
                            }
                            q->memcpy(stable_ptr, out_ptr, bytes);
                            materialized_ptrs[node] = stable_ptr;
                            break;
                        }

                    case OperationType::ROPE:
                        {
                            // Position changes every token; recompute cos/sin tables.
                            if (!node || !node->src[0] || !node->src[1] || !op) {
                                recipe_ok = false;
                                break;
                            }
                            const int  n_dims  = ((int32_t *) node->op_params)[1];
                            const int  half_dim = n_dims / 2;
                            float      freq_base;
                            memcpy(&freq_base, (int32_t *) node->op_params + 5, sizeof(float));

                            int32_t position = rope_position_cached_r;
                            if (position < 0) {
                                const int32_t * pos_ptr = (const int32_t *) get_tensor_ptr_view_fast(node->src[1]);
                                if (!pos_ptr) {
                                    recipe_ok = false;
                                    break;
                                }
                                position               = read_i32_host_or_d2h(pos_ptr);
                                rope_position_cached_r = position;
                            }

                            const uint64_t rope_cache_key =
                                (static_cast<uint64_t>(static_cast<uint32_t>(position)) << 32) |
                                static_cast<uint64_t>(static_cast<uint32_t>(n_dims));
                            float * d_cos = nullptr;
                            float * d_sin = nullptr;
                            auto    rope_it = rope_cache_by_pos.find(rope_cache_key);
                            if (rope_it != rope_cache_by_pos.end()) {
                                d_cos = rope_it->second.first;
                                d_sin = rope_it->second.second;
                            } else {
                                std::vector<float> cos_cache(half_dim);
                                std::vector<float> sin_cache(half_dim);
                                for (int j = 0; j < half_dim; j++) {
                                    const float theta =
                                        (float) position * powf(freq_base, -2.0f * (float) j / (float) n_dims);
                                    cos_cache[j] = cosf(theta);
                                    sin_cache[j] = sinf(theta);
                                }
                                ggml_sycl::alloc_request rope_req;
                                rope_req.queue                          = q;
                                rope_req.device                         = ctx.device;
                                rope_req.size                           = half_dim * sizeof(float);
                                rope_req.intent.role                    = ggml_sycl::alloc_role::GRAPH_TMP;
                                rope_req.intent.category                = ggml_sycl::runtime_category::GRAPH;
                                rope_req.intent.constraints.must_device = true;
                                ggml_sycl::alloc_handle cos_alloc{};
                                ggml_sycl::alloc_handle sin_alloc{};
                                if (!ggml_sycl::unified_alloc(rope_req, &cos_alloc) ||
                                    !ggml_sycl::unified_alloc(rope_req, &sin_alloc) || cos_alloc.ptr == nullptr ||
                                    sin_alloc.ptr == nullptr) {
                                    (void) ggml_sycl::unified_free(cos_alloc);
                                    (void) ggml_sycl::unified_free(sin_alloc);
                                    recipe_ok = false;
                                    break;
                                }
                                d_cos = static_cast<float *>(cos_alloc.ptr);
                                d_sin = static_cast<float *>(sin_alloc.ptr);
                                q->memcpy(d_cos, cos_cache.data(), half_dim * sizeof(float));
                                q->memcpy(d_sin, sin_cache.data(), half_dim * sizeof(float));
                                kernel.add_temp_device_alloc_handle(cos_alloc);
                                kernel.add_temp_device_alloc_handle(sin_alloc);
                                rope_cache_by_pos.emplace(rope_cache_key, std::make_pair(d_cos, d_sin));
                            }

                            const int mode      = ((int32_t *) node->op_params)[2];
                            const bool is_neox   = mode & GGML_ROPE_TYPE_NEOX;

                            // Direct in-place update (no copy-modify-copy pattern)
                            op->weights    = d_cos;
                            op->aux        = d_sin;
                            op->M          = position;
                            op->scale      = is_neox ? 1.0f : 0.0f;
                            break;
                        }

                    case OperationType::SOFTMAX:
                        {
                            // Mask pointer changes each token
                            if (!node || !op) {
                                recipe_ok = false;
                                break;
                            }
                            const ggml_tensor * mask = node->src[1];
                            if (mask) {
                                int64_t mask_nb[GGML_MAX_DIMS] = {};
                                const void * mask_ptr = resolve_input_ptr_with_nb(mask, op->layer, mask_nb, true);
                                if (!mask_ptr) {
                                    recipe_ok = false;
                                    break;
                                }
                                op->mask     = mask_ptr;
                                op->mask_nb0 = mask_nb[0];
                                op->mask_nb1 = mask_nb[1];
                                op->mask_nb2 = mask_nb[2];
                                op->mask_nb3 = mask_nb[3];
                                op->mask_ne2 = (int) mask->ne[2];
                                op->mask_ne3 = (int) mask->ne[3];
                            }
                            op->N = (int) node->src[0]->ne[0];
                            break;
                        }

                    case OperationType::ATTENTION_F16:
                    case OperationType::ATTENTION_F32:
                        {
                            // K/V cache pointers, mask, and seq_len change each token
                            if (!node || !node->src[1] || !node->src[2] || !op) {
                                recipe_ok = false;
                                break;
                            }
                            const ggml_tensor * K_fa = node->src[1];
                            const ggml_tensor * V_fa = node->src[2];
                            const ggml_tensor * mask = node->src[3];

                            int64_t k_nb[GGML_MAX_DIMS] = {};
                            int64_t v_nb[GGML_MAX_DIMS] = {};
                            const void * k_ptr = resolve_input_ptr_with_nb(K_fa, op->layer, k_nb, true);
                            const void * v_ptr = resolve_input_ptr_with_nb(V_fa, op->layer, v_nb, true);
                            if (!k_ptr || !v_ptr) {
                                recipe_ok = false;
                                break;
                            }

                            int seq_len_attn = (int) K_fa->ne[1];  // k_seq_axis = 1
                            if (decode_kv_pos_hint >= 0 && decode_kv_pos_hint + 1 < (int64_t) seq_len_attn) {
                                seq_len_attn = (int) (decode_kv_pos_hint + 1);
                            }

                            op->weights = k_ptr;
                            op->aux     = const_cast<void *>(v_ptr);
                            op->M       = seq_len_attn;
                            op->k_nb0   = k_nb[0];
                            op->k_nb1   = k_nb[1];  // k_seq_axis
                            op->k_nb2   = k_nb[2];  // k_head_axis
                            op->k_nb3   = k_nb[3];
                            op->v_nb0   = v_nb[0];
                            op->v_nb1   = v_nb[1];  // v_seq_axis
                            op->v_nb2   = v_nb[2];  // v_head_axis
                            op->v_nb3   = v_nb[3];

                            if (mask) {
                                int64_t mask_nb[GGML_MAX_DIMS] = {};
                                const void * mask_ptr = resolve_input_ptr_with_nb(mask, op->layer, mask_nb, true);
                                if (!mask_ptr) {
                                    recipe_ok = false;
                                    break;
                                }
                                op->mask     = mask_ptr;
                                op->mask_nb0 = mask_nb[0];
                                op->mask_nb1 = mask_nb[1];
                                op->mask_nb2 = mask_nb[2];
                                op->mask_nb3 = mask_nb[3];
                                op->mask_ne2 = (int) mask->ne[2];
                                op->mask_ne3 = (int) mask->ne[3];
                            }
                            break;
                        }

                    case OperationType::SET_ROWS:
                        {
                            // Index pointer and KV write position change each token
                            if (!node || !node->src[0] || !node->src[1] || !op) {
                                recipe_ok = false;
                                break;
                            }
                            const ggml_tensor * src1 = node->src[1];

                            const void * idx_ptr = get_tensor_ptr_view_fast(src1);
                            void *       dst_ptr = get_tensor_ptr_view_fast(node);
                            if (!dst_ptr && node->src[2]) {
                                dst_ptr = get_tensor_ptr_view_fast(node->src[2]);
                            }
                            if (!idx_ptr || !dst_ptr) {
                                recipe_ok = false;
                                break;
                            }

                            // Read KV position from index tensor (needed for seq_len hint)
                            if (decode_kv_pos_hint < 0) {
                                const int32_t idx_type =
                                    (src1->type == GGML_TYPE_I64) ? 1 : (src1->type == GGML_TYPE_I32 ? 0 : -1);
                                if (idx_type == 1) {
                                    int64_t idx0 = read_i64_host_or_d2h(idx_ptr);
                                    if (idx0 >= 0) {
                                        decode_kv_pos_hint = idx0;
                                    }
                                } else if (idx_type == 0) {
                                    int32_t idx0 = read_i32_host_or_d2h(static_cast<const int32_t *>(idx_ptr));
                                    if (idx0 >= 0) {
                                        decode_kv_pos_hint = idx0;
                                    }
                                }
                            }

                            // Direct in-place update of mutable fields
                            op->aux    = const_cast<void *>(idx_ptr);
                            op->output = dst_ptr;
                            // Strides from ggml tensors (may change between tokens)
                            op->set_rows_meta.nb0  = (int64_t) node->nb[0];
                            op->set_rows_meta.nb1  = (int64_t) node->nb[1];
                            op->set_rows_meta.nb2  = (int64_t) node->nb[2];
                            op->set_rows_meta.nb3  = (int64_t) node->nb[3];
                            op->set_rows_meta.nb10 = (int64_t) src1->nb[0];
                            op->set_rows_meta.nb11 = (int64_t) src1->nb[1];
                            op->set_rows_meta.nb12 = (int64_t) src1->nb[2];
                            break;
                        }

                    case OperationType::STRIDED_COPY:
                        {
                            // CONT ops: re-resolve input/output from ggml tensors
                            if (!node || !node->src[0] || !op) {
                                recipe_ok = false;
                                break;
                            }
                            const void * src_ptr = get_tensor_ptr_view_fast(node->src[0]);
                            void *       dst_ptr = get_tensor_ptr_view_fast(node);
                            if (!src_ptr || !dst_ptr) {
                                recipe_ok = false;
                                break;
                            }
                            op->input  = src_ptr;
                            op->output = dst_ptr;
                            break;
                        }

                    default:
                        // Unexpected op type in recipe — fall back
                        recipe_ok = false;
                        break;
                }

            }

            if (recipe_ok) {
                // Re-add deferred copies (CPY nodes) from the recipe
                kernel.clear_deferred_copies();
                for (const auto & entry : recipe) {
                    if (entry.op_type == OperationType::GET_ROWS && entry.get_rows_idx == -2) {
                        // Sentinel: this is a CPY entry stored in the recipe
                        ggml_tensor * cpy_node = cgraph->nodes[entry.graph_node_idx];
                        if (cpy_node && cpy_node->src[0] && cpy_node->src[1]) {
                            int    source_op_idx = entry.plan_op_idx;
                            void * src_ptr       = ggml_sycl_get_data_ptr(cpy_node->src[0], ctx.device);
                            void * dst_ptr       = ggml_sycl_get_data_ptr(cpy_node->src[1], ctx.device);
                            size_t nbytes        = ggml_nbytes(cpy_node->src[0]);
                            kernel.add_deferred_copy(source_op_idx, src_ptr, dst_ptr, nbytes);
                        }
                    }
                }

                kernel.finish_plan_update();
                // Reset DAG counters only for monolithic kernel's DAG dispatch mode.
                // Micro-graph path uses per-op tile counters + generation counter instead;
                // resetting DAG counters wastes 4 queue ops + a blocking wait per token.
                if (kernel.has_dag() && !kernel.uses_micro_graph()) {
                    kernel.reset_dag_counters();
                }
                GGML_SYCL_DEBUG("[PERSISTENT-TG] Using RECIPE update: %zu mutable ops (of %d plan ops)\n",
                                recipe.size(), kernel.cached_op_count());
                return true;
            }

            // Recipe failed — invalidate and go straight to full rebuild
            GGML_LOG_WARN("[PERSISTENT-TG] Recipe update failed, falling back to full rebuild\n");
            kernel.invalidate_update_recipe();
            kernel.invalidate_plan_cache();
            kernel.cancel_persistent();
            goto full_build;
        }

        if (!fast_path_debug_disabled && kernel.has_cached_plan()) {
            kernel.begin_plan_update();

            auto is_matmul_type = [](OperationType type) -> bool {
                switch (type) {
                    case OperationType::MATMUL_Q_PROJ:
                    case OperationType::MATMUL_K_PROJ:
                    case OperationType::MATMUL_V_PROJ:
                    case OperationType::MATMUL_OUT_PROJ:
                    case OperationType::MATMUL_GATE:
                    case OperationType::MATMUL_UP:
                    case OperationType::MATMUL_DOWN:
                        return true;
                    default:
                        return false;
                }
            };

            // Resolve output pointer: use scratch pool if available, else ggml buffer.
            // Scratch pool eliminates buffer aliasing in the persistent kernel.
            auto resolve_output_ptr = [&](int op_idx, const ggml_tensor * node) -> void * {
                void * scratch = kernel.scratch_output(op_idx);
                if (scratch) {
                    return scratch;
                }
                return get_tensor_ptr_view_fast(node);
            };

            bool fast_path_ok      = true;
            int  op_idx            = 0;
            int  last_layer_fast   = -1;
            int  get_rows_counter  = 0;

            // Track mutable ops for recipe building (only on first fast-path)
            const bool building_recipe = !kernel.has_update_recipe();
            std::vector<UpdateRecipeEntry> recipe_entries;

            for (int i = 0; i < cgraph->n_nodes && fast_path_ok; i++) {
                ggml_tensor * node = cgraph->nodes[i];
                if (!node) {
                    continue;
                }

                int layer = -1;
                if (node->name[0] != '\0') {
                    layer = extract_layer_index(node->name);
                }
                for (int s = 0; s < GGML_MAX_SRC && layer < 0; s++) {
                    if (!node->src[s]) {
                        break;
                    }
                    if (node->src[s]->name[0] != '\0') {
                        layer = extract_layer_index(node->src[s]->name);
                    }
                    if (layer < 0 && node->src[s]->src[0] && node->src[s]->src[0]->name[0] != '\0') {
                        layer = extract_layer_index(node->src[s]->src[0]->name);
                    }
                }
                if (layer < 0) {
                    layer = (last_layer_fast >= 0) ? last_layer_fast : 0;
                } else {
                    last_layer_fast = layer;
                }

                OperationDescriptor op_desc = {};

                switch (node->op) {
                    case GGML_OP_GET_ROWS:
                        {
                            if (!node->src[0] || !node->src[1]) {
                                fast_path_ok = false;
                                break;
                            }
                            if (node->src[1]->type != GGML_TYPE_I32 || node->type != GGML_TYPE_F32) {
                                fast_path_ok = false;
                                break;
                            }
                            // Non-weight GET_ROWS: forward src[0] pointer (identity in TG M=1 mode)
                            if (!ggml_sycl_tensor_is_weight(node->src[0])) {
                                const void * src_ptr = resolve_input_ptr_no_materialize(node->src[0]);
                                if (src_ptr) {
                                    materialized_ptrs[node] = const_cast<void *>(src_ptr);
                                } else {
                                    fast_path_ok = false;
                                }
                                break;
                            }
                            ggml_sycl_op_get_rows(ctx, node);
                            // In-order queue: subsequent memcpy serializes after GET_ROWS
                            if (ggml_is_contiguous(node) && !ggml_is_permuted(node)) {
                                const int    gr_idx     = get_rows_counter++;
                                const size_t bytes      = ggml_nbytes(node);
                                void *       stable_ptr = kernel.get_rows_stable_ptr(gr_idx, bytes);
                                const void * out_ptr    = get_tensor_ptr_view_fast(node);
                                if (!stable_ptr || !out_ptr) {
                                    fast_path_ok = false;
                                    break;
                                }
                                // No .wait() needed: in-order queue ensures D2D copy completes before kernel
                                q->memcpy(stable_ptr, out_ptr, bytes);
                                materialized_ptrs[node] = stable_ptr;
                                if (building_recipe) {
                                    recipe_entries.push_back({-1, OperationType::GET_ROWS,
                                                              PtrSource::STABLE, PtrSource::STABLE,
                                                              PtrSource::STABLE, PtrSource::STABLE,
                                                              i, gr_idx - 1});
                                }
                            }
                            break;
                        }

                    case GGML_OP_RMS_NORM:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_RMS_NORM") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const void * input  = resolve_input_ptr_no_materialize(node->src[0]);
                            void *       output = resolve_output_ptr(op_idx, node);
                            if (!input || !output || !ggml_is_contiguous(node)) {
                                fast_path_ok = false;
                                break;
                            }
                            input  = ensure_device_access_ptr(node->src[0], input, "RMS_NORM input");
                            output = const_cast<void *>(
                                ensure_device_access_ptr(node, output, "RMS_NORM output", ggml_nbytes(node)));
                            if (!input || !output) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::RMS_NORM) {
                                fast_path_ok = false;
                                break;
                            }
                            float eps = 1e-5f;
                            memcpy(&eps, node->op_params, sizeof(float));
                            op_desc.input      = input;
                            op_desc.output     = output;
                            op_desc.eps        = eps;
                            op_desc.hidden_dim = node->src[0] ? (int) node->src[0]->ne[0] : op_desc.hidden_dim;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = output;
                            op_idx++;
                            break;
                        }

                    case GGML_OP_MUL_MAT:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MATMUL") != nullptr ||
                                std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MATMUL_NAME") != nullptr ||
                                std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MATMUL_LAYER") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const ggml_tensor * weight_tensor = node->src[0];
                            if (!weight_tensor || !node->src[1]) {
                                fast_path_ok = false;
                                break;
                            }
                            const int  weight_type = weight_tensor->type;
                            const bool is_quantized_weight =
                                (weight_type == GGML_TYPE_Q4_0 || weight_type == GGML_TYPE_Q6_K);
                            const bool is_f16_weight = (weight_type == GGML_TYPE_F16);
                            if (!is_quantized_weight && !is_f16_weight) {
                                fast_path_ok = false;
                                break;
                            }

                            const void * input        = nullptr;
                            int64_t      input_nb[4]  = { 0, 0, 0, 0 };
                            int64_t      output_nb[4] = {
                                (int64_t) node->nb[0],
                                (int64_t) node->nb[1],
                                (int64_t) node->nb[2],
                                (int64_t) node->nb[3],
                            };
                            void * output = resolve_output_ptr(op_idx, node);
                            if (is_quantized_weight) {
                                input = resolve_input_ptr_no_materialize(node->src[1]);
                                if (!input || !output || !ggml_is_contiguous(node)) {
                                    fast_path_ok = false;
                                    break;
                                }
                            } else {
                                input = resolve_input_ptr_with_nb(node->src[1], layer, input_nb, true);
                                if (!input || !output) {
                                    fast_path_ok = false;
                                    break;
                                }
                            }

                            if (!kernel.get_op_descriptor(op_idx, op_desc) || !is_matmul_type(op_desc.type)) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input  = input;
                            op_desc.output = output;
                            op_desc.M      = (int) node->src[1]->ne[1];
                            if (is_f16_weight) {
                                op_desc.k_nb0 = input_nb[0];
                                op_desc.k_nb1 = input_nb[1];
                                op_desc.k_nb2 = input_nb[2];
                                op_desc.k_nb3 = input_nb[3];
                                op_desc.v_nb0 = output_nb[0];
                                op_desc.v_nb1 = output_nb[1];
                                op_desc.v_nb2 = output_nb[2];
                                op_desc.v_nb3 = output_nb[3];
                            }
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = output;
                            op_idx++;
                            break;
                        }

                    case GGML_OP_MUL:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MUL") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const void *  src0       = resolve_input_ptr_no_materialize(node->src[0]);
                            const void *  src1       = resolve_input_ptr_no_materialize(node->src[1]);
                            void *        mul_out    = resolve_output_ptr(op_idx, node);
                            const int64_t n_elements = ggml_nelements(node);
                            if (!src0 || !src1 || !mul_out || n_elements <= 0 ||
                                n_elements > std::numeric_limits<int>::max()) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::MUL) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input  = src0;
                            op_desc.aux    = const_cast<void *>(src1);
                            op_desc.output = mul_out;
                            op_desc.M      = (int) n_elements;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = mul_out;
                            op_idx++;
                            break;
                        }

                    case GGML_OP_ADD:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_ADD") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const void *  src0       = resolve_input_ptr_no_materialize(node->src[0]);
                            const void *  src1       = resolve_input_ptr_no_materialize(node->src[1]);
                            void *        add_out    = resolve_output_ptr(op_idx, node);
                            const int64_t n_elements = ggml_nelements(node);
                            if (!src0 || !src1 || !add_out || n_elements <= 0 ||
                                n_elements > std::numeric_limits<int>::max()) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::ADD) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input  = src0;
                            op_desc.aux    = const_cast<void *>(src1);
                            op_desc.output = add_out;
                            op_desc.M      = (int) n_elements;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = add_out;
                            op_idx++;
                            break;
                        }

                    case GGML_OP_GLU:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_GLU") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const void * gate    = resolve_input_ptr_no_materialize(node->src[0]);
                            const void * up      = resolve_input_ptr_no_materialize(node->src[1]);
                            void *       glu_out = resolve_output_ptr(op_idx, node);
                            if (!gate || !up || !glu_out) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::SILU_MUL) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input  = gate;
                            op_desc.aux    = const_cast<void *>(up);
                            op_desc.output = glu_out;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = glu_out;
                            op_idx++;
                            break;
                        }

                    case GGML_OP_ROPE:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_ROPE") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const int  n_dims    = ((int32_t *) node->op_params)[1];
                            const int  mode      = ((int32_t *) node->op_params)[2];
                            const bool is_neox   = mode & GGML_ROPE_TYPE_NEOX;
                            const bool is_normal = (mode == GGML_ROPE_TYPE_NORMAL);
                            if (!is_neox && !is_normal) {
                                fast_path_ok = false;
                                break;
                            }
                            float freq_base;
                            float freq_scale;
                            float ext_factor;
                            float attn_factor;
                            memcpy(&freq_base, (int32_t *) node->op_params + 5, sizeof(float));
                            memcpy(&freq_scale, (int32_t *) node->op_params + 6, sizeof(float));
                            memcpy(&ext_factor, (int32_t *) node->op_params + 7, sizeof(float));
                            memcpy(&attn_factor, (int32_t *) node->op_params + 8, sizeof(float));
                            if (freq_scale != 1.0f || ext_factor != 0.0f || attn_factor != 1.0f ||
                                node->src[2] != nullptr) {
                                fast_path_ok = false;
                                break;
                            }

                            const int head_dim_rope = (int) node->src[0]->ne[0];
                            const int n_heads_rope  = (int) node->src[0]->ne[1];
                            if (n_dims != head_dim_rope) {
                                fast_path_ok = false;
                                break;
                            }
                            const int half_dim = n_dims / 2;
                            int32_t   position = rope_position_cached;
                            if (position < 0) {
                                const int32_t * pos_ptr = (const int32_t *) get_tensor_ptr_view_fast(node->src[1]);
                                if (!pos_ptr) {
                                    fast_path_ok = false;
                                    break;
                                }
                                position             = read_i32_host_or_d2h(pos_ptr);
                                rope_position_cached = position;
                            }

                            const uint64_t rope_cache_key =
                                (static_cast<uint64_t>(static_cast<uint32_t>(position)) << 32) |
                                static_cast<uint64_t>(static_cast<uint32_t>(n_dims));
                            float * d_cos   = nullptr;
                            float * d_sin   = nullptr;
                            auto    rope_it = rope_cache_by_pos.find(rope_cache_key);
                            if (rope_it != rope_cache_by_pos.end()) {
                                d_cos = rope_it->second.first;
                                d_sin = rope_it->second.second;
                            } else {
                                std::vector<float> cos_cache(half_dim);
                                std::vector<float> sin_cache(half_dim);
                                for (int j = 0; j < half_dim; j++) {
                                    const float theta =
                                        (float) position * powf(freq_base, -2.0f * (float) j / (float) n_dims);
                                    cos_cache[j] = cosf(theta);
                                    sin_cache[j] = sinf(theta);
                                }
                                ggml_sycl::alloc_request rope_req;
                                rope_req.queue                          = q;
                                rope_req.device                         = ctx.device;
                                rope_req.size                           = half_dim * sizeof(float);
                                rope_req.intent.role                    = ggml_sycl::alloc_role::GRAPH_TMP;
                                rope_req.intent.category                = ggml_sycl::runtime_category::GRAPH;
                                rope_req.intent.constraints.must_device = true;
                                ggml_sycl::alloc_handle cos_alloc{};
                                ggml_sycl::alloc_handle sin_alloc{};
                                if (!ggml_sycl::unified_alloc(rope_req, &cos_alloc) ||
                                    !ggml_sycl::unified_alloc(rope_req, &sin_alloc) || cos_alloc.ptr == nullptr ||
                                    sin_alloc.ptr == nullptr) {
                                    (void) ggml_sycl::unified_free(cos_alloc);
                                    (void) ggml_sycl::unified_free(sin_alloc);
                                    fast_path_ok = false;
                                    break;
                                }
                                d_cos = static_cast<float *>(cos_alloc.ptr);
                                d_sin = static_cast<float *>(sin_alloc.ptr);
                                // Batch both uploads (in-order queue ensures completion before kernel)
                                q->memcpy(d_cos, cos_cache.data(), half_dim * sizeof(float));
                                q->memcpy(d_sin, sin_cache.data(), half_dim * sizeof(float));
                                kernel.add_temp_device_alloc_handle(cos_alloc);
                                kernel.add_temp_device_alloc_handle(sin_alloc);
                                rope_cache_by_pos.emplace(rope_cache_key, std::make_pair(d_cos, d_sin));
                            }

                            void * input_rope  = const_cast<void *>(resolve_input_ptr_no_materialize(node->src[0]));
                            void * output_rope = resolve_output_ptr(op_idx, node);
                            if (!input_rope || !output_rope || !ggml_is_contiguous(node)) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::ROPE) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input      = input_rope;
                            op_desc.output     = output_rope;
                            op_desc.weights    = d_cos;
                            op_desc.aux        = d_sin;
                            op_desc.M          = position;
                            op_desc.N          = n_heads_rope;
                            op_desc.K          = head_dim_rope;
                            op_desc.scale      = is_neox ? 1.0f : 0.0f;
                            op_desc.n_kv_heads = 0;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = output_rope;
                            if (building_recipe) {
                                recipe_entries.push_back({op_idx, OperationType::ROPE,
                                                          PtrSource::SCRATCH_OP, PtrSource::SCRATCH_OP,
                                                          PtrSource::STABLE, PtrSource::STABLE,
                                                          i, -1});
                            }
                            op_idx++;
                            break;
                        }

                    case GGML_OP_SOFT_MAX:
                        {
                            const ggml_tensor * src0  = node->src[0];
                            const ggml_tensor * mask  = node->src[1];
                            const ggml_tensor * sinks = node->src[2];
                            if (!src0 || sinks != nullptr || src0->type != GGML_TYPE_F32 ||
                                node->type != GGML_TYPE_F32) {
                                fast_path_ok = false;
                                break;
                            }

                            float scale    = 1.0f;
                            float max_bias = 0.0f;
                            std::memcpy(&scale, (const float *) node->op_params + 0, sizeof(float));
                            std::memcpy(&max_bias, (const float *) node->op_params + 1, sizeof(float));
                            if (max_bias != 0.0f) {
                                fast_path_ok = false;
                                break;
                            }

                            const void * input  = resolve_input_ptr_no_materialize(src0);
                            void *       output = resolve_output_ptr(op_idx, node);
                            if (!input || !output || !ggml_is_contiguous(node)) {
                                fast_path_ok = false;
                                break;
                            }

                            int          mask_type = -1;
                            int64_t      mask_nb0 = 0, mask_nb1 = 0, mask_nb2 = 0, mask_nb3 = 0;
                            int          mask_ne2 = 1, mask_ne3 = 1;
                            const void * mask_ptr = nullptr;
                            if (mask) {
                                if (mask->type != GGML_TYPE_F16 && mask->type != GGML_TYPE_F32) {
                                    fast_path_ok = false;
                                    break;
                                }
                                int64_t mask_nb[GGML_MAX_DIMS] = {};
                                mask_ptr                       = resolve_input_ptr_with_nb(mask, layer, mask_nb, true);
                                if (!mask_ptr) {
                                    fast_path_ok = false;
                                    break;
                                }
                                mask_ptr = ensure_device_access_ptr(mask, mask_ptr, "SOFT_MAX mask");
                                if (!mask_ptr) {
                                    fast_path_ok = false;
                                    break;
                                }
                                mask_type = (mask->type == GGML_TYPE_F16) ? 1 : 0;
                                mask_nb0  = mask_nb[0];
                                mask_nb1  = mask_nb[1];
                                mask_nb2  = mask_nb[2];
                                mask_nb3  = mask_nb[3];
                                mask_ne2  = (int) mask->ne[2];
                                mask_ne3  = (int) mask->ne[3];
                            }

                            const int64_t n_rows = ggml_nrows(src0);
                            const int64_t n_cols = src0->ne[0];
                            if (n_rows <= 0 || n_cols <= 0 || n_rows > std::numeric_limits<int>::max() ||
                                n_cols > std::numeric_limits<int>::max()) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::SOFTMAX) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input     = input;
                            op_desc.mask      = mask_ptr;
                            op_desc.aux       = nullptr;
                            op_desc.output    = output;
                            op_desc.M         = (int) n_rows;
                            op_desc.N         = (int) n_cols;
                            op_desc.K         = (int) src0->ne[1];
                            op_desc.q_nb0     = (int64_t) src0->ne[1];
                            op_desc.q_nb1     = (int64_t) src0->ne[2];
                            op_desc.q_nb2     = (int64_t) src0->ne[3];
                            op_desc.scale     = scale;
                            op_desc.eps       = max_bias;
                            op_desc.mask_type = mask_type;
                            op_desc.mask_nb0  = mask_nb0;
                            op_desc.mask_nb1  = mask_nb1;
                            op_desc.mask_nb2  = mask_nb2;
                            op_desc.mask_nb3  = mask_nb3;
                            op_desc.mask_ne2  = mask_ne2;
                            op_desc.mask_ne3  = mask_ne3;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = output;
                            if (building_recipe && mask) {
                                recipe_entries.push_back({op_idx, OperationType::SOFTMAX,
                                                          PtrSource::SCRATCH_OP, PtrSource::SCRATCH_OP,
                                                          PtrSource::STABLE, PtrSource::GGML_TENSOR,
                                                          i, -1});
                            }
                            op_idx++;
                            break;
                        }

                    case GGML_OP_FLASH_ATTN_EXT:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_ATTN") != nullptr ||
                                std::getenv("GGML_SYCL_PERSISTENT_TG_SKIP_ATTN") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const ggml_tensor * Q_fa             = node->src[0];
                            const ggml_tensor * K_fa             = node->src[1];
                            const ggml_tensor * V_fa             = node->src[2];
                            const ggml_tensor * mask             = node->src[3];
                            const ggml_tensor * sinks            = node->src[4];
                            const ggml_tensor * q_seq_ids        = node->src[5];
                            const ggml_tensor * kv_seq_ids       = node->src[6];
                            const ggml_tensor * block_table      = node->src[7];
                            const ggml_tensor * seq_lens         = node->src[8];
                            const int32_t       use_paged_layout = ((int32_t *) node->op_params)[4];
                            if (!Q_fa || !K_fa || !V_fa || sinks || q_seq_ids || kv_seq_ids || block_table ||
                                seq_lens || use_paged_layout != 0) {
                                fast_path_ok = false;
                                break;
                            }
                            if (Q_fa->type != GGML_TYPE_F32 || K_fa->type != V_fa->type) {
                                fast_path_ok = false;
                                break;
                            }

                            int64_t      q_nb[GGML_MAX_DIMS] = {};
                            int64_t      k_nb[GGML_MAX_DIMS] = {};
                            int64_t      v_nb[GGML_MAX_DIMS] = {};
                            const void * q_ptr               = resolve_input_ptr_with_nb(Q_fa, layer, q_nb, true);
                            const void * k_ptr               = resolve_input_ptr_with_nb(K_fa, layer, k_nb, true);
                            const void * v_ptr               = resolve_input_ptr_with_nb(V_fa, layer, v_nb, true);
                            void *       out_ptr             = resolve_output_ptr(op_idx, node);
                            if (!q_ptr || !k_ptr || !v_ptr || !out_ptr || !ggml_is_contiguous(node)) {
                                fast_path_ok = false;
                                break;
                            }

                            auto find_axis_for_dim = [](const ggml_tensor * t, int dim) -> int {
                                if (!t || dim <= 0) {
                                    return -1;
                                }
                                for (int d = 0; d < GGML_MAX_DIMS; ++d) {
                                    if ((int) t->ne[d] == dim) {
                                        return d;
                                    }
                                }
                                return -1;
                            };
                            auto pick_seq_axis = [](const ggml_tensor * t, int head_axis) -> int {
                                if (!t) {
                                    return -1;
                                }
                                int     best_axis = -1;
                                int64_t best_ne   = -1;
                                for (int d = 1; d < GGML_MAX_DIMS; ++d) {
                                    if (d == head_axis) {
                                        continue;
                                    }
                                    if (t->ne[d] > best_ne) {
                                        best_ne   = t->ne[d];
                                        best_axis = d;
                                    }
                                }
                                return best_axis;
                            };

                            const int head_dim_attn = (int) Q_fa->ne[0];
                            int       q_head_axis   = find_axis_for_dim(Q_fa, n_heads);
                            if (q_head_axis < 0) {
                                q_head_axis = 2;
                            }
                            int k_head_axis = find_axis_for_dim(K_fa, n_kv_heads);
                            if (k_head_axis < 0) {
                                k_head_axis = 2;
                            }
                            int v_head_axis = find_axis_for_dim(V_fa, n_kv_heads);
                            if (v_head_axis < 0) {
                                v_head_axis = k_head_axis;
                            }
                            int k_seq_axis = pick_seq_axis(K_fa, k_head_axis);
                            if (k_seq_axis < 0) {
                                k_seq_axis = 1;
                            }
                            int v_seq_axis = pick_seq_axis(V_fa, v_head_axis);
                            if (v_seq_axis < 0) {
                                v_seq_axis = k_seq_axis;
                            }
                            if (v_head_axis != k_head_axis || v_seq_axis != k_seq_axis) {
                                v_head_axis = k_head_axis;
                                v_seq_axis  = k_seq_axis;
                            }

                            const int n_heads_attn    = (int) Q_fa->ne[q_head_axis];
                            const int n_kv_heads_attn = (int) K_fa->ne[k_head_axis];
                            int       seq_len_attn    = (int) K_fa->ne[k_seq_axis];
                            if (decode_kv_pos_hint >= 0 && decode_kv_pos_hint + 1 < (int64_t) seq_len_attn) {
                                seq_len_attn = (int) (decode_kv_pos_hint + 1);
                            }

                            float scale_attn    = 1.0f;
                            float max_bias      = 0.0f;
                            float logit_softcap = 0.0f;
                            memcpy(&scale_attn, (const float *) node->op_params + 0, sizeof(float));
                            memcpy(&max_bias, (const float *) node->op_params + 1, sizeof(float));
                            memcpy(&logit_softcap, (const float *) node->op_params + 2, sizeof(float));
                            if (max_bias != 0.0f || logit_softcap != 0.0f) {
                                fast_path_ok = false;
                                break;
                            }

                            const bool kv_f16 = (K_fa->type == GGML_TYPE_F16);
                            const bool kv_f32 = (K_fa->type == GGML_TYPE_F32);
                            if (!kv_f16 && !kv_f32) {
                                fast_path_ok = false;
                                break;
                            }

                            const void * mask_ptr  = nullptr;
                            int          mask_type = -1;
                            int64_t      mask_nb0 = 0, mask_nb1 = 0, mask_nb2 = 0, mask_nb3 = 0;
                            int          mask_ne2 = 0, mask_ne3 = 0;
                            if (mask) {
                                if (mask->type == GGML_TYPE_F16) {
                                    mask_type = 1;
                                } else if (mask->type == GGML_TYPE_F32) {
                                    mask_type = 0;
                                } else {
                                    fast_path_ok = false;
                                    break;
                                }
                                int64_t mask_nb[GGML_MAX_DIMS] = {};
                                mask_ptr                       = resolve_input_ptr_with_nb(mask, layer, mask_nb, true);
                                if (!mask_ptr) {
                                    fast_path_ok = false;
                                    break;
                                }
                                mask_ptr = ensure_device_access_ptr(mask, mask_ptr, "FLASH_ATTN mask");
                                if (!mask_ptr) {
                                    fast_path_ok = false;
                                    break;
                                }
                                mask_nb0 = mask_nb[0];
                                mask_nb1 = mask_nb[1];
                                mask_nb2 = mask_nb[2];
                                mask_nb3 = mask_nb[3];
                                mask_ne2 = (int) mask->ne[2];
                                mask_ne3 = (int) mask->ne[3];
                            }

                            if (!kernel.get_op_descriptor(op_idx, op_desc) ||
                                (op_desc.type != OperationType::ATTENTION_F16 &&
                                 op_desc.type != OperationType::ATTENTION_F32)) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input      = q_ptr;
                            op_desc.weights    = k_ptr;
                            op_desc.aux        = const_cast<void *>(v_ptr);
                            op_desc.mask       = mask_ptr;
                            op_desc.output     = out_ptr;
                            op_desc.M          = seq_len_attn;
                            op_desc.N          = n_heads_attn;
                            op_desc.K          = head_dim_attn;
                            op_desc.n_kv_heads = n_kv_heads_attn;
                            op_desc.scale      = scale_attn;
                            op_desc.q_nb0      = q_nb[0];
                            op_desc.q_nb1      = q_nb[1];
                            op_desc.q_nb2      = q_nb[q_head_axis];
                            op_desc.q_nb3      = q_nb[3];
                            op_desc.k_nb0      = k_nb[0];
                            op_desc.k_nb1      = k_nb[k_seq_axis];
                            op_desc.k_nb2      = k_nb[k_head_axis];
                            op_desc.k_nb3      = k_nb[3];
                            op_desc.v_nb0      = v_nb[0];
                            op_desc.v_nb1      = v_nb[v_seq_axis];
                            op_desc.v_nb2      = v_nb[v_head_axis];
                            op_desc.v_nb3      = v_nb[3];
                            op_desc.mask_type  = mask_type;
                            op_desc.mask_nb0   = mask_nb0;
                            op_desc.mask_nb1   = mask_nb1;
                            op_desc.mask_nb2   = mask_nb2;
                            op_desc.mask_nb3   = mask_nb3;
                            op_desc.mask_ne2   = mask_ne2;
                            op_desc.mask_ne3   = mask_ne3;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            materialized_ptrs[node] = out_ptr;
                            if (building_recipe) {
                                recipe_entries.push_back({op_idx,
                                                          (K_fa->type == GGML_TYPE_F16) ? OperationType::ATTENTION_F16
                                                                                        : OperationType::ATTENTION_F32,
                                                          PtrSource::SCRATCH_OP, PtrSource::SCRATCH_OP,
                                                          PtrSource::KV_CACHE, PtrSource::GGML_TENSOR,
                                                          i, -1});
                            }
                            op_idx++;
                            break;
                        }

                    case GGML_OP_SET_ROWS:
                        {
                            if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_SET_ROWS") != nullptr ||
                                std::getenv("GGML_SYCL_PERSISTENT_TG_SKIP_SET_ROWS") != nullptr) {
                                fast_path_ok = false;
                                break;
                            }
                            const ggml_tensor * src0 = node->src[0];
                            const ggml_tensor * src1 = node->src[1];
                            if (!src0 || !src1 || !ggml_is_contiguous_rows(src0)) {
                                fast_path_ok = false;
                                break;
                            }
                            const int32_t src_type =
                                (src0->type == GGML_TYPE_F16) ? 1 : (src0->type == GGML_TYPE_F32 ? 0 : -1);
                            const int32_t dst_type =
                                (node->type == GGML_TYPE_F16) ? 1 : (node->type == GGML_TYPE_F32 ? 0 : -1);
                            const int32_t idx_type =
                                (src1->type == GGML_TYPE_I64) ? 1 : (src1->type == GGML_TYPE_I32 ? 0 : -1);
                            if (src_type < 0 || dst_type < 0 || idx_type < 0) {
                                fast_path_ok = false;
                                break;
                            }
                            const void * src_ptr = resolve_input_ptr_no_materialize(src0);
                            if (!src_ptr) {
                                src_ptr = get_tensor_ptr_view_fast(src0);
                            }
                            const void * idx_ptr = get_tensor_ptr_view_fast(src1);
                            void *       dst_ptr = get_tensor_ptr_view_fast(node);
                            if (!dst_ptr && node->src[2]) {
                                dst_ptr = get_tensor_ptr_view_fast(node->src[2]);
                            }
                            if (!src_ptr || !idx_ptr || !dst_ptr) {
                                fast_path_ok = false;
                                break;
                            }
                            idx_ptr = ensure_device_access_ptr(src1, idx_ptr, "SET_ROWS indices");
                            if (!idx_ptr) {
                                fast_path_ok = false;
                                break;
                            }
                            if (decode_kv_pos_hint < 0) {
                                if (idx_type == 1) {
                                    int64_t idx0 = read_i64_host_or_d2h(idx_ptr);
                                    if (idx0 >= 0) {
                                        decode_kv_pos_hint = idx0;
                                    }
                                } else {
                                    int32_t idx0 = read_i32_host_or_d2h(static_cast<const int32_t *>(idx_ptr));
                                    if (idx0 >= 0) {
                                        decode_kv_pos_hint = idx0;
                                    }
                                }
                            }

                            if (!kernel.get_op_descriptor(op_idx, op_desc) || op_desc.type != OperationType::SET_ROWS) {
                                fast_path_ok = false;
                                break;
                            }

                            SetRowsMeta meta = {};
                            meta.nc          = src0->ne[0];
                            meta.nr          = src0->ne[1];
                            meta.ne1         = node->ne[1];
                            meta.ne02        = src0->ne[2];
                            meta.ne03        = src0->ne[3];
                            meta.ne11        = src1->ne[1];
                            meta.ne12        = src1->ne[2];
                            meta.nb00        = (int64_t) src0->nb[0];
                            meta.nb01        = (int64_t) src0->nb[1];
                            meta.nb02        = (int64_t) src0->nb[2];
                            meta.nb03        = (int64_t) src0->nb[3];
                            meta.nb0         = (int64_t) node->nb[0];
                            meta.nb1         = (int64_t) node->nb[1];
                            meta.nb2         = (int64_t) node->nb[2];
                            meta.nb3         = (int64_t) node->nb[3];
                            meta.nb10        = (int64_t) src1->nb[0];
                            meta.nb11        = (int64_t) src1->nb[1];
                            meta.nb12        = (int64_t) src1->nb[2];
                            meta.src_type    = src_type;
                            meta.dst_type    = dst_type;
                            meta.idx_type    = idx_type;
                            meta.pad         = 0;

                            const int64_t n_elements = meta.nc * meta.nr * meta.ne02 * meta.ne03;
                            if (n_elements <= 0 || n_elements > std::numeric_limits<int>::max()) {
                                fast_path_ok = false;
                                break;
                            }
                            const int elem_size = (meta.dst_type == 1) ? (int) sizeof(sycl::half) : (int) sizeof(float);
                            const int64_t last  = (meta.nc > 0 ? (meta.nc - 1) * meta.nb0 : 0) +
                                                 (meta.ne1 > 0 ? (meta.ne1 - 1) * meta.nb1 : 0) +
                                                 (meta.ne02 > 0 ? (meta.ne02 - 1) * meta.nb2 : 0) +
                                                 (meta.ne03 > 0 ? (meta.ne03 - 1) * meta.nb3 : 0);
                            op_desc.input            = src_ptr;
                            op_desc.aux              = const_cast<void *>(idx_ptr);
                            op_desc.output           = dst_ptr;
                            op_desc.mask             = nullptr;
                            op_desc.M                = (int) n_elements;
                            op_desc.output_bytes     = last + elem_size;
                            op_desc.set_rows_meta    = meta;
                            op_desc.has_embedded_meta = true;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            if (building_recipe) {
                                recipe_entries.push_back({op_idx, OperationType::SET_ROWS,
                                                          PtrSource::SCRATCH_OP, PtrSource::GGML_TENSOR,
                                                          PtrSource::GGML_TENSOR, PtrSource::STABLE,
                                                          i, -1});
                            }
                            op_idx++;
                            break;
                        }

                    case GGML_OP_VIEW:
                    case GGML_OP_RESHAPE:
                    case GGML_OP_PERMUTE:
                        break;

                    case GGML_OP_CONT:
                        {
                            if (!node->src[0] || node->type != node->src[0]->type || !ggml_is_contiguous(node)) {
                                fast_path_ok = false;
                                break;
                            }
                            const void * src_ptr = get_tensor_ptr_view_fast(node->src[0]);
                            void *       dst_ptr = get_tensor_ptr_view_fast(node);
                            if (!src_ptr || !dst_ptr) {
                                fast_path_ok = false;
                                break;
                            }
                            if (!kernel.get_op_descriptor(op_idx, op_desc) ||
                                op_desc.type != OperationType::STRIDED_COPY) {
                                fast_path_ok = false;
                                break;
                            }
                            StridedCopyMeta meta = {};
                            for (int d = 0; d < GGML_MAX_DIMS; d++) {
                                meta.ne[d] = node->src[0]->ne[d];
                                meta.nb[d] = (int64_t) node->src[0]->nb[d];
                            }
                            meta.type_size = (int32_t) ggml_type_size(node->type);
                            meta.pad       = 0;

                            const int64_t n_elements = ggml_nelements(node->src[0]);
                            if (n_elements <= 0 || n_elements > std::numeric_limits<int>::max()) {
                                fast_path_ok = false;
                                break;
                            }
                            op_desc.input             = src_ptr;
                            op_desc.output            = dst_ptr;
                            op_desc.M                 = (int) n_elements;
                            op_desc.output_bytes      = n_elements * meta.type_size;
                            op_desc.strided_copy_meta = meta;
                            op_desc.has_embedded_meta = true;
                            if (!kernel.update_op_descriptor(op_idx, op_desc)) {
                                fast_path_ok = false;
                                break;
                            }
                            if (building_recipe) {
                                recipe_entries.push_back({op_idx, OperationType::STRIDED_COPY,
                                                          PtrSource::GGML_TENSOR, PtrSource::GGML_TENSOR,
                                                          PtrSource::STABLE, PtrSource::STABLE,
                                                          i, -1});
                            }
                            op_idx++;
                            break;
                        }

                    case GGML_OP_CPY:
                        {
                            if (!node->src[0] || !node->src[1]) {
                                fast_path_ok = false;
                                break;
                            }
                            // Defer CPY until after persistent kernel execution.
                            // Source op is the last plan op before this CPY node.
                            int source_op_idx = op_idx > 0 ? op_idx - 1 : -1;
                            void * src_ptr = ggml_sycl_get_data_ptr(node->src[0], ctx.device);
                            void * dst_ptr = ggml_sycl_get_data_ptr(node->src[1], ctx.device);
                            size_t nbytes  = ggml_nbytes(node->src[0]);
                            kernel.add_deferred_copy(source_op_idx, src_ptr, dst_ptr, nbytes);
                            if (building_recipe) {
                                // Use GET_ROWS type with get_rows_idx=-2 as sentinel for CPY
                                recipe_entries.push_back({source_op_idx, OperationType::GET_ROWS,
                                                          PtrSource::STABLE, PtrSource::STABLE,
                                                          PtrSource::STABLE, PtrSource::STABLE,
                                                          i, -2});
                            }
                            break;
                        }

                    default:
                        fast_path_ok = false;
                        break;
                }
            }

            if (fast_path_ok && op_idx == kernel.cached_op_count()) {
                kernel.finish_plan_update();
                // Reset DAG per-token scheduling state (topology is static across tokens).
                // Skip for micro-graph path: it uses per-op tile counters + generation
                // counter, not DAG counters. Saves 4 queue ops + blocking wait per token.
                if (kernel.has_dag() && !kernel.uses_micro_graph()) {
                    kernel.reset_dag_counters();
                }
                // Build update recipe on first successful fast-path
                if (building_recipe && !recipe_entries.empty()) {
                    int n_gr = 0, n_rope = 0, n_sm = 0, n_attn = 0, n_sr = 0, n_sc = 0, n_cpy = 0;
                    for (const auto & e : recipe_entries) {
                        if (e.get_rows_idx == -2)              n_cpy++;
                        else if (e.op_type == OperationType::GET_ROWS)      n_gr++;
                        else if (e.op_type == OperationType::ROPE)          n_rope++;
                        else if (e.op_type == OperationType::SOFTMAX)       n_sm++;
                        else if (e.op_type == OperationType::ATTENTION_F16 ||
                                 e.op_type == OperationType::ATTENTION_F32) n_attn++;
                        else if (e.op_type == OperationType::SET_ROWS)      n_sr++;
                        else if (e.op_type == OperationType::STRIDED_COPY)  n_sc++;
                    }
                    GGML_LOG_INFO("[PERSISTENT-TG] Built update recipe: %zu mutable ops "
                                  "(gr=%d rope=%d sm=%d attn=%d sr=%d sc=%d cpy=%d) "
                                  "of %d plan ops, %d graph nodes\n",
                                  recipe_entries.size(), n_gr, n_rope, n_sm, n_attn, n_sr, n_sc, n_cpy,
                                  op_idx, cgraph->n_nodes);
                    kernel.set_update_recipe(std::move(recipe_entries));
                }
                GGML_SYCL_DEBUG("[PERSISTENT-TG] Using cached plan: %d ops\n", op_idx);
                return true;
            }

            GGML_SYCL_DEBUG("[PERSISTENT-TG] Fast update fallback to full rebuild (ok=%d op_idx=%d cached=%d)\n",
                            fast_path_ok ? 1 : 0, op_idx, kernel.cached_op_count());
            kernel.invalidate_plan_cache();
            kernel.cancel_persistent();
        }
    }

full_build:
    // 2. Begin building the persistent plan
    kernel.begin_persistent(n_layers, 1 /* batch_size */, hidden_dim, intermediate_dim, n_heads, n_kv_heads, head_dim,
                            quant_type);

    // 3. Walk graph and add operations
    int                                          last_layer        = -1;
    int                                          min_layer_seen    = std::numeric_limits<int>::max();
    int                                          max_layer_seen    = -1;
    int                                          get_rows_counter  = 0;
    // DAG construction: track which graph node produced which op index
    std::unordered_map<const ggml_tensor *, int> tensor_to_op;
    std::vector<int>                             node_to_last_op(cgraph->n_nodes, -1);
    std::vector<int>                             op_to_graph_node;  // reverse: op index → graph node index

    // Helper: find the plan op index that produces the given ggml tensor.
    // Follows view chains (VIEW/RESHAPE/PERMUTE don't produce ops).
    // Returns -1 if the tensor comes from an external source (weights, embeddings, KV cache).
    auto find_source_op = [&](const ggml_tensor * tensor) -> int {
        if (!tensor) return -1;
        const ggml_tensor * origin = tensor;
        int depth = 0;
        while (origin) {
            auto it = tensor_to_op.find(origin);
            if (it != tensor_to_op.end()) {
                return it->second;
            }
            if (origin->view_src) {
                depth++;
                origin = origin->view_src;
            } else {
                // External input (weight, embedding, KV cache) - no source op
                GGML_SYCL_DEBUG("[FIND-SRC] external tensor='%s' op=%d depth=%d\n",
                                tensor->name, tensor->op, depth);
                return -1;  // external input (weight, embedding, KV cache)
            }
        }
        return -1;
    };

    for (int i = 0; i < cgraph->n_nodes; i++) {
        ggml_tensor * node       = cgraph->nodes[i];
        const int     ops_before = ops_added;  // track if this node adds an op
        const auto    node_start = profile_build ? clock_t::now() : clock_t::time_point{};
        if (max_ops_limit > 0 && ops_added >= max_ops_limit) {
            if (g_ggml_sycl_debug) {
                GGML_SYCL_DEBUG("[PERSISTENT-TG] Max ops limit reached (%d), truncating plan\n", max_ops_limit);
            }
            break;
        }
        if (g_ggml_sycl_debug && node) {
            graph_op_counts[node->op]++;
        }
        int layer = -1;

        // Try to get layer index from the node or its source chain
        // Walk up the source chain to find "blk.N" in tensor names
        if (node->name[0] != '\0') {
            layer = extract_layer_index(node->name);
        }
        for (int s = 0; s < GGML_MAX_SRC && layer < 0; s++) {
            if (!node->src[s]) {
                break;
            }
            if (node->src[s]->name[0] != '\0') {
                layer = extract_layer_index(node->src[s]->name);
            }
            // Also check src's sources (2 levels deep)
            if (layer < 0 && node->src[s]->src[0] && node->src[s]->src[0]->name[0] != '\0') {
                layer = extract_layer_index(node->src[s]->src[0]->name);
            }
        }
        if (layer < 0) {
            layer = (last_layer >= 0) ? last_layer : 0;
        } else {
            last_layer = layer;
        }

        if (layer >= 0) {
            min_layer_seen = std::min(min_layer_seen, layer);
            max_layer_seen = std::max(max_layer_seen, layer);
        }
        if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
            const char * name = (node->name[0] != '\0') ? node->name : "(unnamed)";
            GGML_LOG_INFO("[PERSISTENT-TG] node[%d] op=%s layer=%d name=%s ops_added=%d\n", i, ggml_op_name(node->op),
                          layer, name, ops_added);
        }

        switch (node->op) {
            case GGML_OP_GET_ROWS:
                {
                    if (!node->src[0] || !node->src[1]) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GET_ROWS missing src\n");
                        return false;
                    }
                    if (node->src[1]->type != GGML_TYPE_I32 || node->type != GGML_TYPE_F32) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GET_ROWS unsupported types src1=%d dst=%d\n",
                                       node->src[1]->type, node->type);
                        return false;
                    }
                    // Only pre-execute GET_ROWS that read from weight tensors (token
                    // embedding lookup).  GET_ROWS from computed intermediates (e.g.
                    // attn_out-N, l_out-N) read stale ggml buffer data because the
                    // persistent kernel computes those into scratch.  Skip them so
                    // downstream ops resolve their inputs from the kernel's scratch
                    // pool via the normal materialized_ptrs chain.
                    const bool is_weight_lookup = ggml_sycl_tensor_is_weight(node->src[0]);
                    if (!is_weight_lookup) {
                        // Non-weight GET_ROWS: row extraction from a computed intermediate.
                        // In TG mode (M=1), the source tensor has 1 row so GET_ROWS extracts
                        // row 0 -- an identity operation.  Forward the source pointer directly.
                        const void * src_ptr = resolve_input_ptr_no_materialize(node->src[0]);
                        if (src_ptr) {
                            materialized_ptrs[node] = const_cast<void *>(src_ptr);
                            GGML_SYCL_DEBUG("[PERSISTENT-TG] Non-weight GET_ROWS forwarded: %s -> %s (ptr=%p)\n",
                                            node->src[0]->name[0] ? node->src[0]->name : "(unnamed)",
                                            node->name[0] ? node->name : "(unnamed)",
                                            src_ptr);
                            // Register this GET_ROWS passthrough in tensor_to_op so that
                            // downstream find_source_op() can trace through it.  The GET_ROWS
                            // is an identity op — its output is produced by whatever plan op
                            // produced src[0].  Without this, build_scratch_pool() can't remap
                            // downstream inputs because their source_op stays -1.
                            int src_op = find_source_op(node->src[0]);
                            if (src_op >= 0) {
                                tensor_to_op[node] = src_op;
                            }
                        } else {
                            GGML_LOG_ERROR("[PERSISTENT-TG] Non-weight GET_ROWS: cannot resolve src0=%s\n",
                                          node->src[0]->name[0] ? node->src[0]->name : "(unnamed)");
                            return false;
                        }
                        break;
                    }
                    // Keep GET_ROWS outside persistent execution for now.
                    // The in-kernel GET_ROWS path is unstable on B-series Xe and can trigger
                    // UR_RESULT_ERROR_DEVICE_LOST; pre-executing keeps decode robust while the
                    // persistent GET_ROWS kernel is debugged separately.
                    ggml_sycl_op_get_rows(ctx, node);
                    // In-order queue: trace hash and D2D memcpy serialize after GET_ROWS
                    if (g_sycl_tg_trace_hash) {
                        void * out_ptr = get_tensor_ptr_view_fast(node);
                        ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                    node->op);
                    }
                    if (ggml_is_contiguous(node) && !ggml_is_permuted(node)) {
                        const size_t bytes      = ggml_nbytes(node);
                        const int    gr_idx     = get_rows_counter++;
                        void *       stable_ptr = kernel.get_rows_stable_ptr(gr_idx, bytes);
                        if (!stable_ptr) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] GET_ROWS stable alloc failed (slot=%d, %zu bytes)\n", gr_idx, bytes);
                            return false;
                        }
                        const void * out_ptr = get_tensor_ptr_view_fast(node);
                        if (!out_ptr) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] GET_ROWS output ptr missing\n");
                            return false;
                        }
                        q->memcpy(stable_ptr, out_ptr, bytes);
                        materialized_ptrs[node] = stable_ptr;
                    }
                    executed_get_rows++;
                    break;
                }
            case GGML_OP_RMS_NORM:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_RMS_NORM") != nullptr) {
                        ggml_sycl_op_rms_norm(ctx, node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    // In ggml, RMS_NORM only has src[0] (input). The norm weights
                    // are applied via a separate GGML_OP_MUL node that follows.
                    // We pass weights=nullptr; the weight scaling MUL will be
                    // skipped (not added as silu_mul) since we handle it here.
                    const void * input  = resolve_input_ptr(node->src[0], layer);
                    void *       output = get_tensor_ptr_view_fast(node);
                    if (!input || !ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] RMS_NORM input/output not contiguous\n");
                        return false;
                    }
                    input = ensure_device_access_ptr(node->src[0], input, "RMS_NORM input");
                    if (!input) {
                        return false;
                    }
                    output = const_cast<void *>(
                        ensure_device_access_ptr(node, output, "RMS_NORM output", ggml_nbytes(node)));
                    if (!output) {
                        return false;
                    }
                    float eps = 1e-5f;
                    memcpy(&eps, node->op_params, sizeof(float));
                    const int rms_dim              = node->src[0] ? (int) node->src[0]->ne[0] : 0;
                    int       current_rms_instance = -1;
                    if (rms_dump_instance >= 0 && layer >= 0 && layer < (int) rms_seen_per_layer.size()) {
                        current_rms_instance = rms_seen_per_layer[layer]++;
                    }
                    bool capture_rms = g_persistent_rms_dbg.enabled && !g_persistent_rms_dbg.captured && rms_dim > 0;
                    if (capture_rms) {
                        const char * name_env = std::getenv("GGML_SYCL_TG_DUMP_RMS_NAME");
                        if (name_env && *name_env) {
                            if (!node->name || std::strstr(node->name, name_env) == nullptr) {
                                capture_rms = false;
                            }
                        }
                    }
                    if (capture_rms) {
                        int dump_layer = -1;
                        if (const char * layer_env = std::getenv("GGML_SYCL_TG_DUMP_RMS_LAYER")) {
                            if (*layer_env) {
                                char *     end = nullptr;
                                const long val = std::strtol(layer_env, &end, 10);
                                if (end && end != layer_env) {
                                    dump_layer = (int) val;
                                }
                            }
                        }
                        if (dump_layer >= 0 && layer != dump_layer) {
                            capture_rms = false;
                        }
                    }
                    if (capture_rms && rms_dump_instance >= 0) {
                        if (current_rms_instance != rms_dump_instance) {
                            capture_rms = false;
                        }
                    }
                    if (capture_rms) {
                        const size_t total_floats = static_cast<size_t>(rms_dim) * 2u;
                        float *      dbg          = sycl::malloc_shared<float>(total_floats, *q);
                        int *        flag         = sycl::malloc_shared<int>(1, *q);
                        if (dbg && flag) {
                            std::fill_n(dbg, total_floats, 0.0f);
                            *flag                           = 0;
                            g_persistent_rms_dbg.captured   = true;
                            g_persistent_rms_dbg.node       = node;
                            g_persistent_rms_dbg.debug_ptr  = dbg;
                            g_persistent_rms_dbg.debug_flag = flag;
                            g_persistent_rms_dbg.hidden_dim = rms_dim;
                            g_persistent_rms_dbg.eps        = eps;
                            g_persistent_rms_dbg.layer      = layer;
                            kernel.set_persistent_debug_rms(dbg, layer, rms_dim, flag);
                            GGML_SYCL_DEBUG("[PERSISTENT-TG] RMS debug capture enabled: layer=%d dim=%d floats=%zu\n",
                                            layer, rms_dim, total_floats);
                        } else {
                            if (dbg) {
                                sycl::free(dbg, *q);
                            }
                            if (flag) {
                                sycl::free(flag, *q);
                            }
                            GGML_LOG_WARN("[PERSISTENT-TG] RMS debug buffer alloc failed (dim=%d)\n", rms_dim);
                        }
                    }
                    // ── RMS_NORM + MUL fusion ──────────────────────────────────
                    // In ggml graphs, RMS_NORM computes x/rms(x), then a following
                    // MUL node applies the norm weight: y = rms_norm(x) * weight.
                    // The persistent RMS_NORM kernel already supports fused weight
                    // multiplication (output[i] = input[i] * scale * w). By passing
                    // the weight pointer directly, we eliminate the separate MUL op
                    // AND the device-scope barrier between them.
                    // NOTE: Benchmarking shows fusion is ~5% slower on Arc B580 due
                    // to increased memory traffic in the fused RMS_NORM kernel
                    // (reading weight tensor) outweighing the barrier savings.
                    // Enable with: GGML_SYCL_PERSISTENT_TG_RMS_FUSION=1
                    static const bool rms_fusion_enabled =
                        (std::getenv("GGML_SYCL_PERSISTENT_TG_RMS_FUSION") != nullptr);
                    const void * rms_weights   = nullptr;
                    void *       fused_output  = output;
                    bool         fused_rms_mul = false;
                    if (rms_fusion_enabled && i + 1 < cgraph->n_nodes) {
                        const ggml_tensor * next = cgraph->nodes[i + 1];
                        // Pattern: MUL(rms_norm_output, norm_weight) where norm_weight
                        // is a 1D weight tensor (same shape as hidden dim).
                        if (next && next->op == GGML_OP_MUL && next->src[0] == node && next->src[1] &&
                            ggml_are_same_shape(next->src[0], next->src[1]) && next->src[1]->type == GGML_TYPE_F32 &&
                            ggml_is_contiguous(next)) {
                            const void * wptr = resolve_input_ptr(next->src[1], layer);
                            if (wptr) {
                                wptr = ensure_device_access_ptr(next->src[1], wptr, "RMS_NORM fused weight");
                                if (wptr) {
                                    rms_weights   = wptr;
                                    fused_output  = get_tensor_ptr_view_fast(next);
                                    fused_output  = const_cast<void *>(ensure_device_access_ptr(
                                        next, fused_output, "RMS_NORM fused output", ggml_nbytes(next)));
                                    fused_rms_mul = (fused_output != nullptr);
                                }
                            }
                        }
                    }
                    kernel.add_rms_norm(layer, rms_weights, input, fused_rms_mul ? fused_output : output, eps, rms_dim,
                                        fused_rms_mul ? ggml_nbytes(cgraph->nodes[i + 1]) : ggml_nbytes(node));
                    log_op("RMS_NORM", layer, node, fused_rms_mul ? fused_output : output);
                    ops_added++;
                    record_trace(node->op, node, fused_rms_mul ? fused_output : output, ops_added - 1);
                    if (fused_rms_mul) {
                        // Record fused MUL node in DAG tracking so downstream
                        // consumers resolve the fused op as their producer.
                        const int     fused_op_idx = ops_added - 1;
                        ggml_tensor * mul_node     = cgraph->nodes[i + 1];
                        tensor_to_op[mul_node]     = fused_op_idx;
                        node_to_last_op[i + 1]     = fused_op_idx;
                        // Record trace entry for the MUL's output
                        record_trace(mul_node->op, mul_node, fused_output, fused_op_idx);
                        // Map the fused op to BOTH graph nodes (RMS_NORM and MUL)
                        if ((int) op_to_graph_node.size() <= fused_op_idx) {
                            op_to_graph_node.resize(fused_op_idx + 1, -1);
                        }
                        // The op is already mapped to the RMS_NORM graph node (i).
                        // For DAG purposes, both nodes i and i+1 produce the same op.
                        i++;  // Skip the MUL node
                        GGML_SYCL_DEBUG(
                            "[PERSISTENT-TG]   RMS_NORM+MUL fused: layer=%d input=%p output=%p weights=%p\n", layer,
                            input, fused_output, rms_weights);
                    } else {
                        GGML_SYCL_DEBUG("[PERSISTENT-TG]   RMS_NORM: layer=%d input=%p output=%p\n", layer, input,
                                        output);
                    }
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_RMS_NORM]++;
                    }
                    break;
                }

            case GGML_OP_MUL_MAT:
                {
                    bool use_base_matmul = (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MATMUL") != nullptr);
                    if (!use_base_matmul) {
                        const char * base_name = std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MATMUL_NAME");
                        if (base_name && *base_name && node->name && std::strstr(node->name, base_name) != nullptr) {
                            int base_layer = -1;
                            if (const char * layer_env = std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MATMUL_LAYER")) {
                                if (*layer_env) {
                                    char *     end = nullptr;
                                    const long val = std::strtol(layer_env, &end, 10);
                                    if (end && end != layer_env) {
                                        base_layer = (int) val;
                                    }
                                }
                            }
                            if (base_layer < 0 || base_layer == layer) {
                                use_base_matmul = true;
                            }
                        }
                    }
                    if (use_base_matmul) {
                        ggml_sycl_mul_mat(ctx, node->src[0], node->src[1], node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    // src[0] = weight matrix, src[1] = input activation, dst = output
                    const ggml_tensor * weight_tensor = node->src[0];
                    if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
                        log_tensor("MUL_MAT src0", weight_tensor);
                        log_tensor("MUL_MAT src1", node->src[1]);
                        log_tensor("MUL_MAT dst", node);
                    }
                    const int    weight_type         = weight_tensor->type;
                    const bool   is_quantized_weight = (weight_type == GGML_TYPE_Q4_0 || weight_type == GGML_TYPE_Q6_K);
                    const bool   is_f16_weight       = (weight_type == GGML_TYPE_F16);
                    layout_mode  weight_layout       = GGML_LAYOUT_AOS;
                    const void * preferred_layout_ptr = nullptr;

                    if (is_quantized_weight) {
                        if (ggml_sycl_tensor_is_weight(weight_tensor)) {
                            layout_mode chosen = GGML_LAYOUT_AOS;
                            if (ggml_sycl_get_layout_choice_for_tensor(weight_tensor, ctx.device, &chosen)) {
                                weight_layout = chosen;
                            }
                        }
                        if (weight_layout != GGML_LAYOUT_AOS && weight_layout != GGML_LAYOUT_SOA) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] MUL_MAT unsupported weight layout=%d\n",
                                           (int) weight_layout);
                            return false;
                        }
                    }

                    // Persistent Q4_0/Q6_K path is materially faster with SoA than AoS.
                    // Try to promote AoS -> SoA for this path only, with safe rollback
                    // if SoA is unavailable for the tensor.
                    // NOTE: Q6_K SOA promotion requires micro-graph mode
                    // (GGML_SYCL_PERSISTENT_TG_MICRO_GRAPH=1) because the monolithic
                    // persistent kernel's compute_matmul_tile_q6k is AOS-only.
                    // The micro-graph path dispatches via mmvq_submit_q6_k_soa which
                    // correctly handles SOA weight layout.
                    const bool q6k_soa_eligible = (weight_type == GGML_TYPE_Q6_K) &&
                                                   persistent_tg_micro_graph_enabled();
                    if (is_quantized_weight &&
                        (weight_type == GGML_TYPE_Q4_0 || q6k_soa_eligible) &&
                        weight_layout == GGML_LAYOUT_AOS && persistent_tg_prefer_soa_layout()) {
                        const layout_mode soa_layout =
                            ggml_sycl_adjust_layout_for_tensor(weight_tensor, GGML_LAYOUT_SOA, ctx.device);
                        if (soa_layout == GGML_LAYOUT_SOA) {
                            ggml_sycl_cache_id cache_key =
                                ggml_backend_sycl_get_weight_cache_key(weight_tensor, ctx.device);
                            if (cache_key.valid) {
                                ggml_sycl_register_layout_choice(cache_key, ctx.device, GGML_LAYOUT_SOA,
                                                                 weight_tensor->type, weight_tensor->name);
                            }

                            // Prefer a concrete SoA pointer for persistent DMMV. If it is not
                            // materialized yet, request it from the unified cache.
                            preferred_layout_ptr =
                                ggml_sycl_get_layout_ptr_for(weight_tensor, ctx.device, GGML_LAYOUT_SOA);
                            if (!preferred_layout_ptr) {
                                preferred_layout_ptr =
                                    ggml_sycl_get_weight_layout_ptr(weight_tensor, ctx.device, GGML_LAYOUT_SOA);
                            }
                            if (!preferred_layout_ptr) {
                                preferred_layout_ptr =
                                    ggml_sycl_get_layout_ptr_for(weight_tensor, ctx.device, GGML_LAYOUT_SOA);
                            }

                            if (preferred_layout_ptr != nullptr) {
                                weight_layout = GGML_LAYOUT_SOA;
                            } else if (cache_key.valid) {
                                ggml_sycl_register_layout_choice(cache_key, ctx.device, GGML_LAYOUT_AOS,
                                                                 weight_tensor->type, weight_tensor->name);
                            }
                        }
                    }

                    const void * weight       = nullptr;
                    int64_t      weight_nb[4] = { 0, 0, 0, 0 };
                    int64_t      input_nb[4]  = { 0, 0, 0, 0 };
                    int64_t      output_nb[4] = {
                        (int64_t) node->nb[0],
                        (int64_t) node->nb[1],
                        (int64_t) node->nb[2],
                        (int64_t) node->nb[3],
                    };
                    if (is_quantized_weight) {
                        if (weight_layout != GGML_LAYOUT_AOS) {
                            weight = preferred_layout_ptr ?
                                         preferred_layout_ptr :
                                         ggml_sycl_get_layout_ptr_for(weight_tensor, ctx.device, weight_layout);
                            if (!weight) {
                                GGML_SYCL_DEBUG(
                                    "[PERSISTENT-TG] Weight layout %d unavailable for %s, falling back to AoS\n",
                                    (int) weight_layout, weight_tensor->name ? weight_tensor->name : "(null)");
                                weight_layout = GGML_LAYOUT_AOS;
                            }
                        }
                        if (!weight) {
                            weight = get_tensor_ptr_view_fast(weight_tensor);
                        }
                    } else if (is_f16_weight) {
                        weight = resolve_input_ptr_with_nb(weight_tensor, layer, weight_nb, true);
                    } else {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL_MAT unsupported weight type=%d\n", weight_type);
                        return false;
                    }
                    if (log_ops) {
                        const ggml_tensor_layout * w_layout      = ggml_sycl_get_layout_info(weight_tensor);
                        const layout_mode          tensor_layout = w_layout ? w_layout->mode : GGML_LAYOUT_AOS;
                        GGML_LOG_INFO(
                            "[PERSISTENT-TG]   MUL_MAT weight=%s type=%d chosen_layout=%s tensor_layout=%s "
                            "layout_ptr=%p data_ptr=%p\n",
                            weight_tensor->name ? weight_tensor->name : "(null)", (int) weight_tensor->type,
                            ggml_sycl_layout_mode_name(weight_layout), ggml_sycl_layout_mode_name(tensor_layout),
                            ggml_sycl_get_layout_ptr_for(weight_tensor, ctx.device, weight_layout),
                            get_tensor_ptr_view_fast(weight_tensor));
                    }
                    const void * input  = nullptr;
                    void *       output = get_tensor_ptr_view_fast(node);
                    if (is_quantized_weight) {
                        input = resolve_input_ptr(node->src[1], layer);
                    } else {
                        input = resolve_input_ptr_with_nb(node->src[1], layer, input_nb, true);
                    }
                    if (!weight || !input || !output) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL_MAT missing data pointers\n");
                        return false;
                    }
                    if (is_quantized_weight && !ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL_MAT input/output not contiguous\n");
                        return false;
                    }

                    MatmulType mtype = classify_matmul(weight_tensor->name);

                    // Matrix dimensions: C = A * B^T where A=weight (NxK), B=input (MxK)
                    int M        = (int) node->src[1]->ne[1];   // Output rows (batch size, typically 1)
                    int N        = (int) weight_tensor->ne[1];  // Output cols
                    int K        = (int) weight_tensor->ne[0];  // Inner dimension
                    int src0_ne2 = 1;
                    int src0_ne3 = 1;
                    int src1_ne2 = 1;
                    int src1_ne3 = 1;
                    if (is_f16_weight) {
                        if (node->src[1]->type != GGML_TYPE_F32 || node->type != GGML_TYPE_F32) {
                            GGML_LOG_ERROR(
                                "[PERSISTENT-TG] F16 MUL_MAT only supports F32 input/output (src1=%d dst=%d)\n",
                                node->src[1]->type, node->type);
                            return false;
                        }
                        src0_ne2 = (int) weight_tensor->ne[2];
                        src0_ne3 = (int) weight_tensor->ne[3];
                        src1_ne2 = (int) node->src[1]->ne[2];
                        src1_ne3 = (int) node->src[1]->ne[3];
                        if (src0_ne2 <= 0 || src0_ne3 <= 0 || src1_ne2 <= 0 || src1_ne3 <= 0) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] F16 MUL_MAT invalid batch dims src0=[%d,%d] src1=[%d,%d]\n",
                                           src0_ne2, src0_ne3, src1_ne2, src1_ne3);
                            return false;
                        }
                        if (src1_ne2 % src0_ne2 != 0 || src1_ne3 % src0_ne3 != 0) {
                            GGML_LOG_ERROR(
                                "[PERSISTENT-TG] F16 MUL_MAT unsupported broadcast src0.ne23=[%d,%d] "
                                "src1.ne23=[%d,%d]\n",
                                src0_ne2, src0_ne3, src1_ne2, src1_ne3);
                            return false;
                        }
                    }

                    bool         matmul_dbg_match = true;
                    const char * dbg_name_env     = std::getenv("GGML_SYCL_TG_DUMP_MATMUL_NAME");
                    if (dbg_name_env && *dbg_name_env) {
                        if (!node->name || std::strstr(node->name, dbg_name_env) == nullptr) {
                            matmul_dbg_match = false;
                        }
                    } else if (mtype != MatmulType::Q_PROJ) {
                        // Default to Q projection if no explicit name filter is set.
                        matmul_dbg_match = false;
                    }
                    if (matmul_dbg_match) {
                        if (const char * layer_env = std::getenv("GGML_SYCL_TG_DUMP_MATMUL_LAYER")) {
                            if (*layer_env) {
                                char *     end = nullptr;
                                const long val = std::strtol(layer_env, &end, 10);
                                if (end && end != layer_env) {
                                    const int dump_layer = (int) val;
                                    if (dump_layer >= 0 && layer != dump_layer) {
                                        matmul_dbg_match = false;
                                    }
                                }
                            }
                        }
                    }

                    if (g_persistent_matmul_dbg.enabled && !g_persistent_matmul_dbg.captured && matmul_dbg_match &&
                        M == 1 && N > 0) {
                        float * dbg  = sycl::malloc_shared<float>((size_t) N, *q);
                        int *   flag = sycl::malloc_shared<int>(1, *q);
                        if (dbg && flag) {
                            std::fill_n(dbg, (size_t) N, 0.0f);
                            *flag                              = 0;
                            g_persistent_matmul_dbg.captured   = true;
                            g_persistent_matmul_dbg.node       = node;
                            g_persistent_matmul_dbg.debug_ptr  = dbg;
                            g_persistent_matmul_dbg.debug_flag = flag;
                            g_persistent_matmul_dbg.out_dim    = N;
                            g_persistent_matmul_dbg.layer      = layer;
                            g_persistent_matmul_dbg.mtype      = mtype;
                            kernel.set_persistent_debug_matmul(dbg, layer, mtype, N, flag);
                            GGML_SYCL_DEBUG("[PERSISTENT-TG] MATMUL debug capture enabled: layer=%d type=%d dim=%d\n",
                                            layer, (int) mtype, N);
                        } else {
                            if (dbg) {
                                sycl::free(dbg, *q);
                            }
                            if (flag) {
                                sycl::free(flag, *q);
                            }
                            GGML_LOG_WARN("[PERSISTENT-TG] MATMUL debug buffer alloc failed (dim=%d)\n", N);
                        }
                    }

                    kernel.add_matmul(layer, weight, input, output, mtype, M, N, K, weight_type, (int) weight_layout,
                                      is_f16_weight ? weight_nb : nullptr, is_f16_weight ? input_nb : nullptr,
                                      is_f16_weight ? output_nb : nullptr, src0_ne2, src0_ne3, src1_ne2, src1_ne3,
                                      ggml_nbytes(node));
                    log_op("MUL_MAT", layer, node, output);
                    ops_added++;
                    record_trace(node->op, node, output, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_MUL_MAT]++;
                    }
                    break;
                }

            case GGML_OP_MUL:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_MUL") != nullptr) {
                        ggml_sycl_mul(ctx, node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    // MUL is used for two purposes in the transformer graph:
                    // 1. RMS_NORM weight scaling: RMS_NORM output * norm weights
                    // 2. SiLU gating: gate * up (after SiLU activation)
                    if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
                        log_tensor("MUL src0", node->src[0]);
                        log_tensor("MUL src1", node->src[1]);
                        log_tensor("MUL dst", node);
                    }
                    if (node->type != GGML_TYPE_F32 || node->src[0]->type != GGML_TYPE_F32 ||
                        node->src[1]->type != GGML_TYPE_F32) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL only supports F32\n");
                        return false;
                    }
                    if (!ggml_are_same_shape(node->src[0], node->src[1])) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL broadcast not supported\n");
                        return false;
                    }
                    if (!ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL output not contiguous\n");
                        return false;
                    }
                    const void * src0 = resolve_input_ptr(node->src[0], layer);
                    const void * src1 = resolve_input_ptr(node->src[1], layer);
                    if (!src0 || !src1) {
                        return false;
                    }
                    if (log_ops && (max_ops_limit <= 0 || ops_added >= max_ops_limit - 2)) {
                        GGML_LOG_INFO("[PERSISTENT-TG] MUL ptrs: src0=%p src1=%p dst=%p\n", src0, src1,
                                      get_tensor_ptr_view_fast(node));
                    }
                    const int64_t n_elements = ggml_nelements(node);
                    if (n_elements > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] MUL tensor too large: %lld elements\n", (long long) n_elements);
                        return false;
                    }
                    void * mul_out = get_tensor_ptr_view_fast(node);
                    if (g_persistent_mul_dbg.enabled && !g_persistent_mul_dbg.captured && node->type == GGML_TYPE_F32 &&
                        node->ne[1] >= 1) {
                        const char * name_env = std::getenv("GGML_SYCL_TG_DUMP_MUL_NAME");
                        if (!name_env || !*name_env || (node->name && std::strstr(node->name, name_env) != nullptr)) {
                            int dump_layer = -1;
                            if (const char * layer_env = std::getenv("GGML_SYCL_TG_DUMP_MUL_LAYER")) {
                                if (*layer_env) {
                                    char *     end = nullptr;
                                    const long val = std::strtol(layer_env, &end, 10);
                                    if (end && end != layer_env) {
                                        dump_layer = (int) val;
                                    }
                                }
                            }
                            if (dump_layer < 0 || dump_layer == layer) {
                                g_persistent_mul_dbg.captured = true;
                                g_persistent_mul_dbg.node     = node;
                                g_persistent_mul_dbg.out_dim  = (int) n_elements;
                                g_persistent_mul_dbg.layer    = layer;
                            }
                        }
                    }
                    kernel.add_mul(layer, src0, src1, mul_out, (int) n_elements, ggml_nbytes(node));
                    log_op("MUL", layer, node, mul_out);
                    ops_added++;
                    record_trace(node->op, node, mul_out, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_MUL]++;
                    }
                    break;
                }

            case GGML_OP_ADD:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_ADD") != nullptr) {
                        ggml_sycl_add(ctx, node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    if (node->type != GGML_TYPE_F32 || node->src[0]->type != GGML_TYPE_F32 ||
                        node->src[1]->type != GGML_TYPE_F32) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ADD only supports F32\n");
                        return false;
                    }
                    if (!ggml_are_same_shape(node->src[0], node->src[1])) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ADD broadcast not supported\n");
                        return false;
                    }
                    if (!ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ADD output not contiguous\n");
                        return false;
                    }
                    const void * src0 = resolve_input_ptr(node->src[0], layer);
                    const void * src1 = resolve_input_ptr(node->src[1], layer);
                    if (!src0 || !src1) {
                        return false;
                    }
                    const int64_t n_elements = ggml_nelements(node);
                    if (n_elements > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ADD tensor too large: %lld elements\n", (long long) n_elements);
                        return false;
                    }
                    void * add_out = get_tensor_ptr_view_fast(node);
                    if (g_persistent_add_dbg.enabled && !g_persistent_add_dbg.captured && node->type == GGML_TYPE_F32 &&
                        node->ne[1] >= 1) {
                        const char * name_env = std::getenv("GGML_SYCL_TG_DUMP_ADD_NAME");
                        if (!name_env || !*name_env || (node->name && std::strstr(node->name, name_env) != nullptr)) {
                            int dump_layer = -1;
                            if (const char * layer_env = std::getenv("GGML_SYCL_TG_DUMP_ADD_LAYER")) {
                                if (*layer_env) {
                                    char *     end = nullptr;
                                    const long val = std::strtol(layer_env, &end, 10);
                                    if (end && end != layer_env) {
                                        dump_layer = (int) val;
                                    }
                                }
                            }
                            if (dump_layer < 0 || dump_layer == layer) {
                                g_persistent_add_dbg.captured = true;
                                g_persistent_add_dbg.node     = node;
                                g_persistent_add_dbg.out_dim  = (int) n_elements;
                                g_persistent_add_dbg.layer    = layer;
                            }
                        }
                    }
                    kernel.add_add(layer, src0, src1, add_out, (int) n_elements, ggml_nbytes(node));
                    log_op("ADD", layer, node, add_out);
                    ops_added++;
                    record_trace(node->op, node, add_out, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_ADD]++;
                    }
                    break;
                }

            case GGML_OP_GLU:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_GLU") != nullptr) {
                        ggml_sycl_swiglu(ctx, node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    const ggml_glu_op glu_op = ggml_get_glu_op(node);
                    if (glu_op != GGML_GLU_OP_SWIGLU) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GLU op %s not supported\n", ggml_glu_op_name(glu_op));
                        return false;
                    }
                    if (node->src[1] == nullptr) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GLU split mode required (src1)\n");
                        return false;
                    }
                    if (node->type != GGML_TYPE_F32 || node->src[0]->type != GGML_TYPE_F32 ||
                        node->src[1]->type != GGML_TYPE_F32) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GLU only supports F32\n");
                        return false;
                    }
                    if (!ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GLU output not contiguous\n");
                        return false;
                    }
                    const int32_t       swapped  = ggml_get_op_params_i32(node, 1);
                    const ggml_tensor * gate_src = swapped ? node->src[1] : node->src[0];
                    const ggml_tensor * up_src   = swapped ? node->src[0] : node->src[1];
                    const void *        gate     = resolve_input_ptr(gate_src, layer);
                    const void *        up       = resolve_input_ptr(up_src, layer);
                    if (!gate || !up) {
                        return false;
                    }
                    const int64_t n_elements = ggml_nelements(node);
                    if (n_elements > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] GLU tensor too large: %lld elements\n", (long long) n_elements);
                        return false;
                    }
                    void * glu_out = get_tensor_ptr_view_fast(node);
                    kernel.add_silu_mul(layer, gate, up, glu_out, ggml_nbytes(node));
                    log_op("GLU", layer, node, glu_out);
                    ops_added++;
                    record_trace(node->op, node, glu_out, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_GLU]++;
                    }
                    break;
                }

            case GGML_OP_ROPE:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_ROPE") != nullptr) {
                        ggml_sycl_rope(ctx, node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    // RoPE: Apply rotary position embeddings to a single tensor (Q or K).
                    // In the ggml graph, ROPE is applied separately to Q and K tensors.
                    // Each ROPE op processes one tensor: src[0] = input (Q or K), src[1] = position.
                    //
                    // The persistent kernel's compute_rope_tile() can handle k_data == nullptr,
                    // so each graph ROPE op maps to one add_rope() call with only the Q field set.

                    // Extract RoPE parameters from op_params (same layout as ggml_sycl_op_rope)
                    const int n_dims = ((int32_t *) node->op_params)[1];
                    const int mode   = ((int32_t *) node->op_params)[2];

                    float freq_base;
                    memcpy(&freq_base, (int32_t *) node->op_params + 5, sizeof(float));
                    float freq_scale;
                    float ext_factor;
                    float attn_factor;
                    float beta_fast;
                    float beta_slow;
                    memcpy(&freq_scale, (int32_t *) node->op_params + 6, sizeof(float));
                    memcpy(&ext_factor, (int32_t *) node->op_params + 7, sizeof(float));
                    memcpy(&attn_factor, (int32_t *) node->op_params + 8, sizeof(float));
                    memcpy(&beta_fast, (int32_t *) node->op_params + 9, sizeof(float));
                    memcpy(&beta_slow, (int32_t *) node->op_params + 10, sizeof(float));
                    if (g_ggml_sycl_debug) {
                        static int rope_dbg = 0;
                        if (rope_dbg++ < 1) {
                            const int n_ctx_orig = ((int32_t *) node->op_params)[4];
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   ROPE params: n_ctx_orig=%d freq_base=%.4f freq_scale=%.4f "
                                "ext=%.4f attn=%.4f beta_fast=%.4f beta_slow=%.4f\n",
                                n_ctx_orig, freq_base, freq_scale, ext_factor, attn_factor, beta_fast, beta_slow);
                        }
                    }

                    // Support normal (mode=0) and neox (mode=2) RoPE modes
                    const bool is_neox   = mode & GGML_ROPE_TYPE_NEOX;
                    const bool is_normal = (mode == GGML_ROPE_TYPE_NORMAL);
                    if (!is_neox && !is_normal) {
                        GGML_SYCL_DEBUG("[PERSISTENT-TG] Skipping unsupported ROPE mode=%d\n", mode);
                        break;
                    }
                    if (freq_scale != 1.0f || ext_factor != 0.0f || attn_factor != 1.0f) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ROPE unsupported scaling: freq_scale=%g ext=%g attn=%g\n",
                                       freq_scale, ext_factor, attn_factor);
                        return false;
                    }
                    if (node->src[2] != nullptr) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ROPE unsupported freq_factors tensor\n");
                        return false;
                    }

                    // Get tensor dimensions
                    const int head_dim_rope = (int) node->src[0]->ne[0];
                    const int n_heads_rope  = (int) node->src[0]->ne[1];
                    const int half_dim      = n_dims / 2;  // n_dims may be <= head_dim
                    if (n_dims != head_dim_rope) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ROPE unsupported n_dims=%d head_dim=%d\n", n_dims,
                                       head_dim_rope);
                        return false;
                    }

                    // Read position from device (src[1] is position tensor)
                    // For TG mode (M=1), there's only one position value
                    int32_t position = rope_position_cached;
                    if (position < 0) {
                        const int32_t * pos_ptr = (const int32_t *) get_tensor_ptr_view_fast(node->src[1]);
                        if (!pos_ptr) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] ROPE position tensor missing\n");
                            return false;
                        }
                        position             = read_i32_host_or_d2h(pos_ptr);
                        rope_position_cached = position;
                    }

                    const uint64_t rope_cache_key = (static_cast<uint64_t>(static_cast<uint32_t>(position)) << 32) |
                                                    static_cast<uint64_t>(static_cast<uint32_t>(n_dims));

                    float * d_cos   = nullptr;
                    float * d_sin   = nullptr;
                    auto    rope_it = rope_cache_by_pos.find(rope_cache_key);
                    if (rope_it != rope_cache_by_pos.end()) {
                        d_cos = rope_it->second.first;
                        d_sin = rope_it->second.second;
                    } else {
                        // Build and upload RoPE cos/sin once per (position, n_dims).
                        std::vector<float> cos_cache(half_dim);
                        std::vector<float> sin_cache(half_dim);
                        for (int j = 0; j < half_dim; j++) {
                            const float theta = (float) position * powf(freq_base, -2.0f * (float) j / (float) n_dims);
                            cos_cache[j]      = cosf(theta);
                            sin_cache[j]      = sinf(theta);
                        }

                        ggml_sycl::alloc_request rope_req;
                        rope_req.queue                          = q;
                        rope_req.device                         = ctx.device;
                        rope_req.size                           = half_dim * sizeof(float);
                        rope_req.intent.role                    = ggml_sycl::alloc_role::GRAPH_TMP;
                        rope_req.intent.category                = ggml_sycl::runtime_category::GRAPH;
                        rope_req.intent.constraints.must_device = true;
                        ggml_sycl::alloc_handle cos_alloc{};
                        ggml_sycl::alloc_handle sin_alloc{};
                        if (!ggml_sycl::unified_alloc(rope_req, &cos_alloc) ||
                            !ggml_sycl::unified_alloc(rope_req, &sin_alloc) || cos_alloc.ptr == nullptr ||
                            sin_alloc.ptr == nullptr) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] ROPE cache alloc failed (half_dim=%d)\n", half_dim);
                            (void) ggml_sycl::unified_free(cos_alloc);
                            (void) ggml_sycl::unified_free(sin_alloc);
                            return false;
                        }
                        d_cos = static_cast<float *>(cos_alloc.ptr);
                        d_sin = static_cast<float *>(sin_alloc.ptr);
                        // Batch both uploads (in-order queue ensures completion before kernel)
                        q->memcpy(d_cos, cos_cache.data(), half_dim * sizeof(float));
                        q->memcpy(d_sin, sin_cache.data(), half_dim * sizeof(float));

                        kernel.add_temp_device_alloc_handle(cos_alloc);
                        kernel.add_temp_device_alloc_handle(sin_alloc);
                        rope_cache_by_pos.emplace(rope_cache_key, std::make_pair(d_cos, d_sin));
                    }

                    // Each graph ROPE op processes a single tensor (Q or K)
                    // src[0] is the input tensor, dst is the output tensor
                    void * input_rope  = const_cast<void *>(resolve_input_ptr(node->src[0], layer));
                    void * output_rope = get_tensor_ptr_view_fast(node);
                    if (!input_rope || !ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] ROPE input/output not contiguous\n");
                        return false;
                    }

                    RopeDescriptor desc = {};
                    desc.q              = input_rope;   // Source data (read from src[0])
                    desc.k              = nullptr;      // Single-tensor mode: no K
                    desc.rope_dst       = output_rope;  // Destination data (write to dst)
                    desc.cos_cache      = d_cos;
                    desc.sin_cache      = d_sin;
                    desc.n_heads        = n_heads_rope;
                    desc.head_dim       = head_dim_rope;
                    desc.position       = position;
                    desc.is_neox        = is_neox;
                    kernel.add_rope(layer, desc, ggml_nbytes(node));
                    log_op("ROPE", layer, node, output_rope);
                    ops_added++;
                    record_trace(node->op, node, output_rope, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_ROPE]++;
                    }

                    GGML_SYCL_DEBUG("[PERSISTENT-TG]   ROPE: heads=%d head_dim=%d n_dims=%d pos=%d\n", n_heads_rope,
                                    head_dim_rope, n_dims, position);
                    break;
                }

            case GGML_OP_SOFT_MAX:
                {
                    const ggml_tensor * src0  = node->src[0];
                    const ggml_tensor * mask  = node->src[1];
                    const ggml_tensor * sinks = node->src[2];

                    if (!src0) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX missing src0\n");
                        return false;
                    }
                    if (src0->type != GGML_TYPE_F32 || node->type != GGML_TYPE_F32) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX only supports F32 src/dst (src=%d dst=%d)\n",
                                       src0->type, node->type);
                        return false;
                    }
                    if (sinks != nullptr) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX sinks tensor not supported in persistent path\n");
                        return false;
                    }

                    float scale    = 1.0f;
                    float max_bias = 0.0f;
                    std::memcpy(&scale, (const float *) node->op_params + 0, sizeof(float));
                    std::memcpy(&max_bias, (const float *) node->op_params + 1, sizeof(float));
                    if (max_bias != 0.0f) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX max_bias=%g not supported in persistent path\n",
                                       max_bias);
                        return false;
                    }

                    const void * input  = resolve_input_ptr(src0, layer);
                    void *       output = get_tensor_ptr_view_fast(node);
                    if (!input || !output || !ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR(
                            "[PERSISTENT-TG] SOFT_MAX input/output not available or output not contiguous\n");
                        return false;
                    }

                    int          mask_type = -1;
                    int64_t      mask_nb0  = 0;
                    int64_t      mask_nb1  = 0;
                    int64_t      mask_nb2  = 0;
                    int64_t      mask_nb3  = 0;
                    int          mask_ne2  = 1;
                    int          mask_ne3  = 1;
                    const void * mask_ptr  = nullptr;
                    if (mask) {
                        if (mask->type != GGML_TYPE_F16 && mask->type != GGML_TYPE_F32) {
                            GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX unsupported mask type=%d\n", mask->type);
                            return false;
                        }
                        int64_t mask_nb[GGML_MAX_DIMS] = {};
                        mask_ptr                       = resolve_input_ptr_with_nb(mask, layer, mask_nb, true);
                        if (!mask_ptr) {
                            return false;
                        }
                        mask_ptr = ensure_device_access_ptr(mask, mask_ptr, "SOFT_MAX mask");
                        if (!mask_ptr) {
                            return false;
                        }
                        mask_type = (mask->type == GGML_TYPE_F16) ? 1 : 0;
                        mask_nb0  = mask_nb[0];
                        mask_nb1  = mask_nb[1];
                        mask_nb2  = mask_nb[2];
                        mask_nb3  = mask_nb[3];
                        mask_ne2  = (int) mask->ne[2];
                        mask_ne3  = (int) mask->ne[3];
                    }

                    const int64_t n_rows = ggml_nrows(src0);
                    const int64_t n_cols = src0->ne[0];
                    if (n_rows <= 0 || n_cols <= 0 || n_rows > std::numeric_limits<int>::max() ||
                        n_cols > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX invalid shape rows=%lld cols=%lld\n",
                                       (long long) n_rows, (long long) n_cols);
                        return false;
                    }
                    if (src0->ne[1] > std::numeric_limits<int>::max() ||
                        src0->ne[2] > std::numeric_limits<int>::max() ||
                        src0->ne[3] > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SOFT_MAX shape exceeds int range ne=[%lld,%lld,%lld,%lld]\n",
                                       (long long) src0->ne[0], (long long) src0->ne[1], (long long) src0->ne[2],
                                       (long long) src0->ne[3]);
                        return false;
                    }

                    kernel.add_softmax(layer, input, mask_ptr, nullptr, output, (int) n_rows, (int) n_cols,
                                       (int) src0->ne[1], (int) src0->ne[2], (int) src0->ne[3], scale, max_bias,
                                       mask_type, mask_nb0, mask_nb1, mask_nb2, mask_nb3, mask_ne2, mask_ne3,
                                       ggml_nbytes(node));
                    log_op("SOFT_MAX", layer, node, output);
                    ops_added++;
                    record_trace(node->op, node, output, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_SOFT_MAX]++;
                    }
                    break;
                }

            case GGML_OP_FLASH_ATTN_EXT:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_ATTN") != nullptr) {
                        ggml_sycl_flash_attn_ext(ctx, node);
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_SKIP_ATTN") != nullptr) {
                        if (g_ggml_sycl_debug) {
                            GGML_SYCL_DEBUG("[PERSISTENT-TG]   FLASH_ATTN skipped via env\n");
                        }
                        break;
                    }
                    // Flash attention: src[0]=Q, src[1]=K, src[2]=V, dst=output
                    // Q dimensions: ne[0]=head_dim, ne[1]=n_queries, ne[2]=n_heads
                    // K dimensions: ne[0]=head_dim, ne[1]=n_kv (seq_len), ne[2]=n_kv_heads
                    const ggml_tensor * Q_fa        = node->src[0];
                    const ggml_tensor * K_fa        = node->src[1];
                    const ggml_tensor * V_fa        = node->src[2];
                    const ggml_tensor * mask        = node->src[3];
                    const ggml_tensor * sinks       = node->src[4];
                    const ggml_tensor * q_seq_ids   = node->src[5];
                    const ggml_tensor * kv_seq_ids  = node->src[6];
                    const ggml_tensor * block_table = node->src[7];
                    const ggml_tensor * seq_lens    = node->src[8];

                    const int32_t use_paged_layout = ((int32_t *) node->op_params)[4];
                    if (sinks || q_seq_ids || kv_seq_ids || block_table || seq_lens || use_paged_layout != 0) {
                        GGML_LOG_ERROR(
                            "[PERSISTENT-TG] FLASH_ATTN unsupported extras: sinks=%p q_seq=%p kv_seq=%p "
                            "block_table=%p seq_lens=%p paged=%d\n",
                            (const void *) sinks, (const void *) q_seq_ids, (const void *) kv_seq_ids,
                            (const void *) block_table, (const void *) seq_lens, (int) use_paged_layout);
                        return false;
                    }

                    log_tensor("ATTN Q", Q_fa);
                    log_tensor("ATTN K", K_fa);
                    log_tensor("ATTN V", V_fa);
                    log_tensor("ATTN mask", mask);

                    if (Q_fa->type != GGML_TYPE_F32) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] FLASH_ATTN unsupported Q type=%d (expected F32)\n", Q_fa->type);
                        return false;
                    }

                    int64_t q_nb[GGML_MAX_DIMS] = {};
                    int64_t k_nb[GGML_MAX_DIMS] = {};
                    int64_t v_nb[GGML_MAX_DIMS] = {};

                    const void * q_ptr   = resolve_input_ptr_with_nb(Q_fa, layer, q_nb, true);
                    const void * k_ptr   = resolve_input_ptr_with_nb(K_fa, layer, k_nb, true);
                    const void * v_ptr   = resolve_input_ptr_with_nb(V_fa, layer, v_nb, true);
                    void *       out_ptr = get_tensor_ptr_view_fast(node);
                    if (!q_ptr || !k_ptr || !v_ptr || !ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] FLASH_ATTN input/output not contiguous\n");
                        return false;
                    }
                    const int model_n_heads    = n_heads;
                    const int model_n_kv_heads = n_kv_heads;

                    auto find_axis_for_dim = [](const ggml_tensor * t, int dim) -> int {
                        if (!t || dim <= 0) {
                            return -1;
                        }
                        for (int i = 0; i < GGML_MAX_DIMS; ++i) {
                            if ((int) t->ne[i] == dim) {
                                return i;
                            }
                        }
                        return -1;
                    };

                    auto pick_seq_axis = [](const ggml_tensor * t, int head_axis) -> int {
                        if (!t) {
                            return -1;
                        }
                        int     best_axis = -1;
                        int64_t best_ne   = -1;
                        for (int i = 1; i < GGML_MAX_DIMS; ++i) {
                            if (i == head_axis) {
                                continue;
                            }
                            if (t->ne[i] > best_ne) {
                                best_ne   = t->ne[i];
                                best_axis = i;
                            }
                        }
                        return best_axis;
                    };

                    const int head_dim_attn = (int) Q_fa->ne[0];

                    int q_head_axis = find_axis_for_dim(Q_fa, model_n_heads);
                    if (q_head_axis < 0) {
                        q_head_axis = 2;
                    }
                    int k_head_axis = find_axis_for_dim(K_fa, model_n_kv_heads);
                    if (k_head_axis < 0) {
                        k_head_axis = 2;
                    }
                    int v_head_axis = find_axis_for_dim(V_fa, model_n_kv_heads);
                    if (v_head_axis < 0) {
                        v_head_axis = k_head_axis;
                    }

                    int k_seq_axis = pick_seq_axis(K_fa, k_head_axis);
                    if (k_seq_axis < 0) {
                        k_seq_axis = 1;
                    }
                    int v_seq_axis = pick_seq_axis(V_fa, v_head_axis);
                    if (v_seq_axis < 0) {
                        v_seq_axis = k_seq_axis;
                    }

                    if (v_head_axis != k_head_axis || v_seq_axis != k_seq_axis) {
                        GGML_SYCL_DEBUG(
                            "[PERSISTENT-TG]   FLASH_ATTN axis mismatch: k_head=%d v_head=%d k_seq=%d v_seq=%d\n",
                            k_head_axis, v_head_axis, k_seq_axis, v_seq_axis);
                        v_head_axis = k_head_axis;
                        v_seq_axis  = k_seq_axis;
                    }

                    const int n_heads_attn          = (int) Q_fa->ne[q_head_axis];
                    const int n_kv_heads_attn       = (int) K_fa->ne[k_head_axis];
                    const int seq_len_attn_capacity = (int) K_fa->ne[k_seq_axis];
                    int       seq_len_attn          = seq_len_attn_capacity;
                    if (decode_kv_pos_hint >= 0 && decode_kv_pos_hint + 1 < (int64_t) seq_len_attn) {
                        seq_len_attn = (int) (decode_kv_pos_hint + 1);
                    }

                    if (g_ggml_sycl_debug) {
                        static int attn_dbg = 0;
                        if (attn_dbg++ < 1) {
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   FLASH_ATTN Q ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld]\n",
                                (long long) Q_fa->ne[0], (long long) Q_fa->ne[1], (long long) Q_fa->ne[2],
                                (long long) Q_fa->ne[3], (long long) Q_fa->nb[0], (long long) Q_fa->nb[1],
                                (long long) Q_fa->nb[2], (long long) Q_fa->nb[3]);
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   FLASH_ATTN K ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld]\n",
                                (long long) K_fa->ne[0], (long long) K_fa->ne[1], (long long) K_fa->ne[2],
                                (long long) K_fa->ne[3], (long long) K_fa->nb[0], (long long) K_fa->nb[1],
                                (long long) K_fa->nb[2], (long long) K_fa->nb[3]);
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   FLASH_ATTN V ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld]\n",
                                (long long) V_fa->ne[0], (long long) V_fa->ne[1], (long long) V_fa->ne[2],
                                (long long) V_fa->ne[3], (long long) V_fa->nb[0], (long long) V_fa->nb[1],
                                (long long) V_fa->nb[2], (long long) V_fa->nb[3]);
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   FLASH_ATTN axes: q_head=%d k_head=%d k_seq=%d v_head=%d v_seq=%d "
                                "model_heads=%d model_kv_heads=%d\n",
                                q_head_axis, k_head_axis, k_seq_axis, v_head_axis, v_seq_axis, model_n_heads,
                                model_n_kv_heads);
                            GGML_SYCL_DEBUG("[PERSISTENT-TG]   FLASH_ATTN ptrs: q=%p k=%p v=%p out=%p\n", q_ptr, k_ptr,
                                            v_ptr, out_ptr);
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   FLASH_ATTN seq_len: capacity=%d effective=%d kv_pos_hint=%lld\n",
                                seq_len_attn_capacity, seq_len_attn, (long long) decode_kv_pos_hint);
                        }
                    }
                    static bool logged_attn_shapes = false;
                    if (!logged_attn_shapes) {
                        const char * log_env = std::getenv("GGML_SYCL_PERSISTENT_TG_LOG_ATTN");
                        if (log_env && std::atoi(log_env) != 0) {
                            logged_attn_shapes = true;
                            GGML_LOG_INFO("[PERSISTENT-TG] ATTN Q ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld]\n",
                                          (long long) Q_fa->ne[0], (long long) Q_fa->ne[1], (long long) Q_fa->ne[2],
                                          (long long) Q_fa->ne[3], (long long) Q_fa->nb[0], (long long) Q_fa->nb[1],
                                          (long long) Q_fa->nb[2], (long long) Q_fa->nb[3]);
                            GGML_LOG_INFO("[PERSISTENT-TG] ATTN K ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld]\n",
                                          (long long) K_fa->ne[0], (long long) K_fa->ne[1], (long long) K_fa->ne[2],
                                          (long long) K_fa->ne[3], (long long) K_fa->nb[0], (long long) K_fa->nb[1],
                                          (long long) K_fa->nb[2], (long long) K_fa->nb[3]);
                            GGML_LOG_INFO("[PERSISTENT-TG] ATTN V ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld]\n",
                                          (long long) V_fa->ne[0], (long long) V_fa->ne[1], (long long) V_fa->ne[2],
                                          (long long) V_fa->ne[3], (long long) V_fa->nb[0], (long long) V_fa->nb[1],
                                          (long long) V_fa->nb[2], (long long) V_fa->nb[3]);
                            if (mask) {
                                GGML_LOG_INFO(
                                    "[PERSISTENT-TG] ATTN mask ne=[%lld,%lld,%lld,%lld] nb=[%lld,%lld,%lld,%lld] "
                                    "type=%d\n",
                                    (long long) mask->ne[0], (long long) mask->ne[1], (long long) mask->ne[2],
                                    (long long) mask->ne[3], (long long) mask->nb[0], (long long) mask->nb[1],
                                    (long long) mask->nb[2], (long long) mask->nb[3], (int) mask->type);
                            } else {
                                GGML_LOG_INFO("[PERSISTENT-TG] ATTN mask: none\n");
                            }
                            GGML_LOG_INFO(
                                "[PERSISTENT-TG] ATTN axes: q_head=%d k_head=%d k_seq=%d v_head=%d v_seq=%d n_heads=%d "
                                "n_kv_heads=%d seq_len=%d\n",
                                q_head_axis, k_head_axis, k_seq_axis, v_head_axis, v_seq_axis, n_heads_attn,
                                n_kv_heads_attn, seq_len_attn);
                        }
                    }

                    if (K_fa->type != V_fa->type) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] FLASH_ATTN KV type mismatch K=%d V=%d\n", K_fa->type,
                                       V_fa->type);
                        return false;
                    }
                    KvCacheType kv_type;
                    if (K_fa->type == GGML_TYPE_F16) {
                        kv_type = KvCacheType::F16;
                    } else if (K_fa->type == GGML_TYPE_F32) {
                        kv_type = KvCacheType::F32;
                    } else {
                        GGML_LOG_ERROR("[PERSISTENT-TG] FLASH_ATTN unsupported KV type=%d\n", K_fa->type);
                        return false;
                    }

                    // Scale/max_bias/logit_softcap from op_params[0..2]
                    float scale_attn;
                    float max_bias;
                    float logit_softcap;
                    memcpy(&scale_attn, (const float *) node->op_params, sizeof(float));
                    memcpy(&max_bias, (const float *) node->op_params + 1, sizeof(float));
                    memcpy(&logit_softcap, (const float *) node->op_params + 2, sizeof(float));
                    if (max_bias != 0.0f || logit_softcap != 0.0f) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] FLASH_ATTN unsupported bias/softcap: max_bias=%g softcap=%g\n",
                                       max_bias, logit_softcap);
                        return false;
                    }

                    const void * mask_ptr  = nullptr;
                    int          mask_type = -1;
                    int64_t      mask_nb0  = 0;
                    int64_t      mask_nb1  = 0;
                    int64_t      mask_nb2  = 0;
                    int64_t      mask_nb3  = 0;
                    int          mask_ne2  = 0;
                    int          mask_ne3  = 0;
                    if (mask) {
                        if (mask->type == GGML_TYPE_F16) {
                            mask_type = 1;
                        } else if (mask->type == GGML_TYPE_F32) {
                            mask_type = 0;
                        } else {
                            GGML_LOG_ERROR("[PERSISTENT-TG] FLASH_ATTN unsupported mask type=%d\n", mask->type);
                            return false;
                        }
                        int64_t mask_nb[GGML_MAX_DIMS] = {};
                        mask_ptr                       = resolve_input_ptr_with_nb(mask, layer, mask_nb, true);
                        if (!mask_ptr) {
                            return false;
                        }
                        mask_ptr = ensure_device_access_ptr(mask, mask_ptr, "FLASH_ATTN mask");
                        if (!mask_ptr) {
                            return false;
                        }
                        mask_nb0 = mask_nb[0];
                        mask_nb1 = mask_nb[1];
                        mask_nb2 = mask_nb[2];
                        mask_nb3 = mask_nb[3];
                        mask_ne2 = (int) mask->ne[2];
                        mask_ne3 = (int) mask->ne[3];
                    }
                    if (g_ggml_sycl_debug) {
                        if (mask) {
                            GGML_SYCL_DEBUG(
                                "[PERSISTENT-TG]   FLASH_ATTN mask: type=%d ne=[%lld,%lld,%lld,%lld] "
                                "nb=[%lld,%lld,%lld,%lld]\n",
                                mask->type, (long long) mask->ne[0], (long long) mask->ne[1], (long long) mask->ne[2],
                                (long long) mask->ne[3], (long long) mask->nb[0], (long long) mask->nb[1],
                                (long long) mask->nb[2], (long long) mask->nb[3]);
                            static int mask_dbg = 0;
                            if (mask_dbg++ < 1) {
                                const int sample_idx[] = { 0, 1, 2, 15, 16, 63, 127, 255 };
                                const int n_samples    = (int) (sizeof(sample_idx) / sizeof(sample_idx[0]));
                                for (int si = 0; si < n_samples; si++) {
                                    const int p = sample_idx[si];
                                    if (p >= seq_len_attn) {
                                        continue;
                                    }
                                    const int64_t mask_off = (int64_t) p * mask_nb0;
                                    float         mask_val = 0.0f;
                                    if (mask_type == 1) {
                                        sycl::half tmp;
                                        q->memcpy(&tmp, (const char *) mask_ptr + mask_off, sizeof(tmp)).wait();
                                        mask_val = (float) tmp;
                                    } else if (mask_type == 0) {
                                        float tmp;
                                        q->memcpy(&tmp, (const char *) mask_ptr + mask_off, sizeof(tmp)).wait();
                                        mask_val = tmp;
                                    }
                                    GGML_SYCL_DEBUG("[PERSISTENT-TG]   FLASH_ATTN mask[%d]=%.6f\n", p, mask_val);
                                }
                            }
                        } else {
                            GGML_SYCL_DEBUG("[PERSISTENT-TG]   FLASH_ATTN mask: none\n");
                        }
                    }

                    const char * attn_env_local     = std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_ATTN");
                    const bool   attn_debug_enabled = (attn_env_local && std::atoi(attn_env_local) != 0);
                    static bool  logged_attn_state  = false;
                    if (!logged_attn_state) {
                        logged_attn_state = true;
                        GGML_SYCL_DEBUG("[PERSISTENT-TG] ATTN debug state: enabled=%d captured=%d\n",
                                        attn_debug_enabled ? 1 : 0, g_persistent_attn_dbg.captured ? 1 : 0);
                    }
                    if (attn_debug_enabled && !g_persistent_attn_dbg.captured) {
                        GGML_SYCL_DEBUG("[PERSISTENT-TG] ATTN debug capture path entered\n");
                        const int dbg_head_dim = head_dim_attn;
                        const int dbg_seq_len  = seq_len_attn;
                        if (dbg_head_dim > 0 && dbg_seq_len > 0) {
                            const size_t kv_elems =
                                static_cast<size_t>(dbg_head_dim) * static_cast<size_t>(dbg_seq_len);
                            const size_t overhead =
                                4u + 2u * static_cast<size_t>(dbg_head_dim) + static_cast<size_t>(dbg_seq_len);
                            const size_t max_size = std::numeric_limits<size_t>::max();
                            if (kv_elems > (max_size - overhead) / 2u) {
                                GGML_LOG_WARN(
                                    "[PERSISTENT-TG] ATTN debug buffer size overflow (head_dim=%d seq_len=%d)\n",
                                    dbg_head_dim, dbg_seq_len);
                            } else {
                                const size_t total_floats = overhead + 2u * kv_elems;
                                if (total_floats > static_cast<size_t>(std::numeric_limits<int>::max())) {
                                    GGML_LOG_WARN("[PERSISTENT-TG] ATTN debug buffer too large: %zu floats\n",
                                                  total_floats);
                                } else {
                                    float * dbg = sycl::malloc_shared<float>(total_floats, *q);
                                    if (dbg) {
                                        std::fill_n(dbg, total_floats, 0.0f);
                                        g_persistent_attn_dbg.captured     = true;
                                        g_persistent_attn_dbg.node         = node;
                                        g_persistent_attn_dbg.layer        = layer;
                                        g_persistent_attn_dbg.debug_ptr    = dbg;
                                        g_persistent_attn_dbg.debug_floats = static_cast<int>(total_floats);
                                        kernel.set_persistent_debug_attn(dbg, layer, static_cast<int>(total_floats));
                                        GGML_SYCL_DEBUG(
                                            "[PERSISTENT-TG] ATTN debug capture enabled: layer=%d head_dim=%d "
                                            "seq_len=%d floats=%zu\n",
                                            layer, dbg_head_dim, dbg_seq_len, total_floats);
                                    } else {
                                        GGML_LOG_WARN("[PERSISTENT-TG] ATTN debug buffer alloc failed (%zu floats)\n",
                                                      total_floats);
                                    }
                                }
                            }
                        }
                    }

                    AttentionDescriptor attn_desc = {};
                    attn_desc.q                   = q_ptr;
                    attn_desc.k_cache             = k_ptr;
                    attn_desc.v_cache             = v_ptr;
                    attn_desc.mask                = mask_ptr;
                    attn_desc.output              = out_ptr;
                    attn_desc.kv_type             = kv_type;
                    attn_desc.n_heads             = n_heads_attn;
                    attn_desc.n_kv_heads          = n_kv_heads_attn;
                    attn_desc.head_dim            = head_dim_attn;
                    attn_desc.seq_len             = seq_len_attn;
                    attn_desc.q_nb0               = q_nb[0];
                    attn_desc.q_nb1               = q_nb[1];
                    attn_desc.q_nb2               = q_nb[q_head_axis];
                    attn_desc.q_nb3               = q_nb[3];
                    attn_desc.k_nb0               = k_nb[0];
                    attn_desc.k_nb1               = k_nb[k_seq_axis];
                    attn_desc.k_nb2               = k_nb[k_head_axis];
                    attn_desc.k_nb3               = k_nb[3];
                    attn_desc.v_nb0               = v_nb[0];
                    attn_desc.v_nb1               = v_nb[v_seq_axis];
                    attn_desc.v_nb2               = v_nb[v_head_axis];
                    attn_desc.v_nb3               = v_nb[3];
                    attn_desc.scale               = scale_attn;
                    attn_desc.mask_type           = mask_type;
                    attn_desc.mask_nb0            = mask_nb0;
                    attn_desc.mask_nb1            = mask_nb1;
                    attn_desc.mask_nb2            = mask_nb2;
                    attn_desc.mask_nb3            = mask_nb3;
                    attn_desc.mask_ne2            = mask_ne2;
                    attn_desc.mask_ne3            = mask_ne3;
                    kernel.add_attention(layer, attn_desc, ggml_nbytes(node));
                    log_op("FLASH_ATTN_EXT", layer, node, out_ptr);
                    ops_added++;
                    record_trace(node->op, node, out_ptr, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_FLASH_ATTN_EXT]++;
                    }

                    GGML_SYCL_DEBUG(
                        "[PERSISTENT-TG]   FLASH_ATTN: heads=%d kv_heads=%d "
                        "head_dim=%d seq_len=%d scale=%.4f\n",
                        n_heads_attn, n_kv_heads_attn, head_dim_attn, seq_len_attn, scale_attn);
                    break;
                }

            case GGML_OP_SET_ROWS:
                {
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_USE_BASE_SET_ROWS") != nullptr) {
                        ggml_sycl_op_set_rows(ctx, node);
                        // Keep ordering deterministic for subsequent persistent ops.
                        q->wait_and_throw();
                        if (g_sycl_tg_trace_hash) {
                            void * out_ptr = get_tensor_ptr_view_fast(node);
                            ggml_sycl_trace_tensor_hash(ctx, node, out_ptr, "persist-pre", g_sycl_trace_op_index++,
                                                        node->op);
                        }
                        break;
                    }
                    if (std::getenv("GGML_SYCL_PERSISTENT_TG_SKIP_SET_ROWS") != nullptr) {
                        if (g_ggml_sycl_debug) {
                            GGML_SYCL_DEBUG("[PERSISTENT-TG]   SET_ROWS skipped via env\n");
                        }
                        break;
                    }
                    const ggml_tensor * src0 = node->src[0];
                    const ggml_tensor * src1 = node->src[1];
                    if (!src0 || !src1) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SET_ROWS missing src\n");
                        return false;
                    }
                    if (!ggml_is_contiguous_rows(src0)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SET_ROWS requires contiguous rows in src0\n");
                        return false;
                    }
                    const int32_t src_type = (src0->type == GGML_TYPE_F16) ? 1 : (src0->type == GGML_TYPE_F32 ? 0 : -1);
                    const int32_t dst_type = (node->type == GGML_TYPE_F16) ? 1 : (node->type == GGML_TYPE_F32 ? 0 : -1);
                    const int32_t idx_type = (src1->type == GGML_TYPE_I64) ? 1 : (src1->type == GGML_TYPE_I32 ? 0 : -1);
                    if (src_type < 0 || dst_type < 0 || idx_type < 0) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SET_ROWS unsupported types src=%d dst=%d idx=%d\n", src0->type,
                                       node->type, src1->type);
                        return false;
                    }
                    // Use the original tensor layout for SET_ROWS. It relies on src0 strides,
                    // so materializing to a contiguous buffer would corrupt indexing.
                    const void * src_ptr = get_tensor_ptr_view_fast(src0);
                    const void * idx_ptr = get_tensor_ptr_view_fast(src1);
                    // GGML_OP_SET_ROWS writes through the op output view (dst/node), not the
                    // src[2] root tensor base. Using src[2] here can drop view offsets.
                    void *       dst_ptr = get_tensor_ptr_view_fast(node);
                    if (!dst_ptr && node->src[2]) {
                        dst_ptr = get_tensor_ptr_view_fast(node->src[2]);
                    }
                    if (!src_ptr || !idx_ptr || !dst_ptr) {
                        return false;
                    }

                    idx_ptr = ensure_device_access_ptr(src1, idx_ptr, "SET_ROWS indices");
                    if (!idx_ptr) {
                        return false;
                    }

                    // Decode-phase hint: SET_ROWS indices encode which KV row is written.
                    // Later FLASH_ATTN uses this to clamp seq_len to the live KV extent.
                    if (decode_kv_pos_hint < 0) {
                        if (idx_type == 1) {
                            int64_t idx0 = read_i64_host_or_d2h(idx_ptr);
                            if (idx0 >= 0) {
                                decode_kv_pos_hint = idx0;
                            }
                        } else if (idx_type == 0) {
                            int32_t idx0 = read_i32_host_or_d2h(static_cast<const int32_t *>(idx_ptr));
                            if (idx0 >= 0) {
                                decode_kv_pos_hint = idx0;
                            }
                        }
                    }

                    SetRowsMeta meta = {};
                    meta.nc          = src0->ne[0];
                    meta.nr          = src0->ne[1];
                    meta.ne1         = node->ne[1];
                    meta.ne02        = src0->ne[2];
                    meta.ne03        = src0->ne[3];
                    meta.ne11        = src1->ne[1];
                    meta.ne12        = src1->ne[2];
                    meta.nb00        = (int64_t) src0->nb[0];
                    meta.nb01        = (int64_t) src0->nb[1];
                    meta.nb02        = (int64_t) src0->nb[2];
                    meta.nb03        = (int64_t) src0->nb[3];
                    meta.nb0         = (int64_t) node->nb[0];
                    meta.nb1         = (int64_t) node->nb[1];
                    meta.nb2         = (int64_t) node->nb[2];
                    meta.nb3         = (int64_t) node->nb[3];
                    meta.nb10        = (int64_t) src1->nb[0];
                    meta.nb11        = (int64_t) src1->nb[1];
                    meta.nb12        = (int64_t) src1->nb[2];
                    meta.src_type    = src_type;
                    meta.dst_type    = dst_type;
                    meta.idx_type    = idx_type;
                    meta.pad         = 0;

                    const int64_t n_elements = meta.nc * meta.nr * meta.ne02 * meta.ne03;
                    if (n_elements > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] SET_ROWS tensor too large: %lld elements\n",
                                       (long long) n_elements);
                        return false;
                    }
                    void * debug_ptr = nullptr;
                    if (g_persistent_set_rows_dbg.enabled && !g_persistent_set_rows_dbg.captured) {
                        g_persistent_set_rows_dbg.captured = true;
                        g_persistent_set_rows_dbg.src_ptr  = src_ptr;
                        g_persistent_set_rows_dbg.idx_ptr  = idx_ptr;
                        g_persistent_set_rows_dbg.dst_ptr  = dst_ptr;
                        g_persistent_set_rows_dbg.meta     = meta;

                        if (std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_SET_ROWS") != nullptr) {
                            constexpr int k_sample = 8;
                            float *       dbg      = sycl::malloc_shared<float>(2 * k_sample + 1, *q);
                            if (dbg) {
                                std::fill_n(dbg, 2 * k_sample + 1, 0.0f);
                                g_persistent_set_rows_dbg.debug_ptr   = dbg;
                                g_persistent_set_rows_dbg.debug_count = k_sample;
                                debug_ptr                             = dbg;
                            } else {
                                GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS debug alloc failed\n");
                            }
                        }
                    }
                    const int     elem_size = (meta.dst_type == 1) ? (int) sizeof(sycl::half) : (int) sizeof(float);
                    const int64_t last      = (meta.nc > 0 ? (meta.nc - 1) * meta.nb0 : 0) +
                                         (meta.ne1 > 0 ? (meta.ne1 - 1) * meta.nb1 : 0) +
                                         (meta.ne02 > 0 ? (meta.ne02 - 1) * meta.nb2 : 0) +
                                         (meta.ne03 > 0 ? (meta.ne03 - 1) * meta.nb3 : 0);
                    const int64_t output_bytes = last + elem_size;
                    kernel.add_set_rows(layer, src_ptr, idx_ptr, dst_ptr, meta, (int) n_elements, debug_ptr,
                                        output_bytes);
                    log_op("SET_ROWS", layer, node, dst_ptr);
                    ops_added++;
                    record_trace(node->op, node, dst_ptr, ops_added - 1);
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_SET_ROWS]++;
                    }
                    break;
                }

            case GGML_OP_VIEW:
            case GGML_OP_RESHAPE:
            case GGML_OP_PERMUTE:
                if (g_ggml_sycl_debug) {
                    if (node->op == GGML_OP_VIEW) {
                        skipped_view++;
                    } else if (node->op == GGML_OP_RESHAPE) {
                        skipped_reshape++;
                    } else {
                        skipped_permute++;
                    }
                }
                // Views/reshapes are materialized on-demand when used as inputs.
                break;

            case GGML_OP_CONT:
                {
                    if (!node->src[0]) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] CONT missing src0\n");
                        return false;
                    }
                    if (node->type != node->src[0]->type) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] CONT type mismatch src=%d dst=%d\n", node->src[0]->type,
                                       node->type);
                        return false;
                    }
                    if (!ggml_is_contiguous(node)) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] CONT output not contiguous\n");
                        return false;
                    }
                    const void * src_ptr = get_tensor_ptr_view_fast(node->src[0]);
                    void *       dst_ptr = get_tensor_ptr_view_fast(node);
                    if (!src_ptr || !dst_ptr) {
                        return false;
                    }
                    StridedCopyMeta meta = {};
                    for (int d = 0; d < GGML_MAX_DIMS; d++) {
                        meta.ne[d] = node->src[0]->ne[d];
                        meta.nb[d] = (int64_t) node->src[0]->nb[d];
                    }
                    meta.type_size = (int32_t) ggml_type_size(node->type);
                    meta.pad       = 0;

                    const int64_t n_elements = ggml_nelements(node->src[0]);
                    if (n_elements > std::numeric_limits<int>::max()) {
                        GGML_LOG_ERROR("[PERSISTENT-TG] CONT tensor too large: %lld elements\n",
                                       (long long) n_elements);
                        return false;
                    }
                    const int64_t output_bytes = n_elements * meta.type_size;
                    kernel.add_strided_copy(layer, src_ptr, dst_ptr, meta, (int) n_elements, output_bytes);
                    log_op("STRIDED_COPY", layer, node, dst_ptr);
                    ops_added++;
                    if (g_ggml_sycl_debug) {
                        plan_op_counts[GGML_OP_CONT]++;
                    }
                    break;
                }

            case GGML_OP_CPY:
                // Defer CPY until after persistent kernel execution.  The source
                // is identified by plan op index so build_scratch_pool() remap is
                // handled transparently via scratch_outputs_.
                if (!node->src[0] || !node->src[1]) {
                    GGML_LOG_ERROR("[PERSISTENT-TG] CPY missing src\n");
                    return false;
                }
                {
                    // Find which plan op produced the CPY source data.
                    // Follow view_src chain (VIEW/RESHAPE/PERMUTE skip plan ops).
                    const ggml_tensor * origin = node->src[0];
                    while (origin && tensor_to_op.find(origin) == tensor_to_op.end()) {
                        if (origin->view_src) {
                            origin = origin->view_src;
                        } else {
                            origin = nullptr;
                        }
                    }
                    int source_op_idx = (origin) ? tensor_to_op[origin] : -1;

                    void * src_ptr = ggml_sycl_get_data_ptr(node->src[0], ctx.device);
                    void * dst_ptr = ggml_sycl_get_data_ptr(node->src[1], ctx.device);
                    size_t nbytes  = ggml_nbytes(node->src[0]);
                    kernel.add_deferred_copy(source_op_idx, src_ptr, dst_ptr, nbytes);
                    GGML_SYCL_DEBUG("[PERSISTENT-TG] Deferred CPY: %s -> %s (%zu bytes, source_op=%d)\n",
                                    node->src[0]->name ? node->src[0]->name : "?",
                                    node->src[1]->name ? node->src[1]->name : "?", nbytes, source_op_idx);
                }
                executed_cpy++;
                break;

            default:
                GGML_LOG_ERROR("[PERSISTENT-TG] Unsupported op in extraction: %s (%s)\n", ggml_op_name(node->op),
                               node->name ? node->name : "(null)");
                return false;
        }
        // DAG tracking: record which ops this graph node produced
        if (ops_added > ops_before) {
            node_to_last_op[i] = ops_added - 1;
            tensor_to_op[node] = ops_added - 1;
            // Record reverse mapping for all ops from this node
            for (int o = ops_before; o < ops_added; o++) {
                if ((int) op_to_graph_node.size() <= o) {
                    op_to_graph_node.resize(o + 1, -1);
                }
                op_to_graph_node[o] = i;
            }

            // Scratch pool linkage: annotate each produced op with the plan
            // operation indices of its input/aux producers.  This replaces the
            // broken pointer-based remap in build_scratch_pool() that fails
            // when ggml's allocator recycles buffer addresses.
            //
            // For single-op nodes (the common case), the mapping is:
            //   input ← src that was used for op.input (varies by op type)
            //   aux   ← src that was used for op.aux   (varies by op type)
            //
            // We determine the mapping from the ggml op type:
            if (node && ops_added == ops_before + 1) {
                auto & last_op = kernel.get_plan_operations_mut().back();
                switch (node->op) {
                    case GGML_OP_ADD:
                        // input = src[0], aux = src[1]
                        last_op.input_source_op = find_source_op(node->src[0]);
                        last_op.aux_source_op   = find_source_op(node->src[1]);
                        break;
                    case GGML_OP_MUL:
                        // input = src[0], aux = src[1] (the norm weights are external)
                        last_op.input_source_op = find_source_op(node->src[0]);
                        last_op.aux_source_op   = find_source_op(node->src[1]);
                        break;
                    case GGML_OP_RMS_NORM:
                        // input = src[0] (the input hidden state)
                        last_op.input_source_op = find_source_op(node->src[0]);
                        break;
                    case GGML_OP_MUL_MAT:
                        // input = src[1] (activations), weights = src[0] (external)
                        last_op.input_source_op = find_source_op(node->src[1]);
                        break;
                    case GGML_OP_GLU:
                        {
                            // GLU: input = gate, aux = up.  The full-build code uses
                            // the 'swapped' op_param to decide which src is gate vs up.
                            // Match that logic so scratch-pool remaps to the correct buffers.
                            const int32_t       swapped  = ggml_get_op_params_i32(node, 1);
                            const ggml_tensor * gate_src = swapped ? node->src[1] : node->src[0];
                            const ggml_tensor * up_src   = swapped ? node->src[0] : node->src[1];
                            last_op.input_source_op = find_source_op(gate_src);
                            last_op.aux_source_op   = find_source_op(up_src);
                        }
                        break;
                    case GGML_OP_ROPE:
                        // input = src[0]
                        last_op.input_source_op = find_source_op(node->src[0]);
                        break;
                    case GGML_OP_SOFT_MAX:
                        // input = src[0], mask = src[1] (external KV mask)
                        last_op.input_source_op = find_source_op(node->src[0]);
                        break;
                    case GGML_OP_FLASH_ATTN_EXT:
                        // Q = src[0], K = src[1] (KV cache), V = src[2] (KV cache)
                        last_op.input_source_op = find_source_op(node->src[0]);
                        break;
                    case GGML_OP_SET_ROWS:
                        // input = src[0] (data to write to KV cache, e.g. ROPE'd K or V_PROJ output)
                        // SET_ROWS writes src[0] into dst at positions given by src[1].
                        // When scratch pool remaps the source op's output to scratch,
                        // SET_ROWS must read from scratch (not the stale ggml buffer).
                        last_op.input_source_op = find_source_op(node->src[0]);
                        break;
                    default:
                        break;
                }
            }
        }
        if (profile_build && node) {
            build_ms_by_op[node->op] += std::chrono::duration<double, std::milli>(clock_t::now() - node_start).count();
        }
    }

    if (max_layer_seen >= n_layers) {
        GGML_LOG_ERROR("[PERSISTENT-TG] Layer index out of range: max=%d expected<%d\n", max_layer_seen, n_layers);
        return false;
    }
    if (g_sycl_tg_trace_hash && ops_added > 0) {
        const size_t max_ops = (size_t) ops_added;
        uint64_t *   dbg     = sycl::malloc_shared<uint64_t>(max_ops, *q);
        if (dbg) {
            std::fill_n(dbg, max_ops, 0ull);
            g_persistent_debug_hash_ptr = dbg;
            kernel.set_persistent_debug_hash(dbg, (int) g_sycl_tg_trace_max_bytes);
        } else {
            GGML_LOG_WARN("[PERSISTENT-TG] debug hash alloc failed (%zu entries)\n", max_ops);
        }
    }
    if (g_ggml_sycl_debug) {
        GGML_SYCL_DEBUG("[PERSISTENT-TG] Layer range: min=%d max=%d expected=%d\n",
                        min_layer_seen == std::numeric_limits<int>::max() ? -1 : min_layer_seen, max_layer_seen,
                        n_layers);
    }
    if (profile_build) {
        const double build_ms = std::chrono::duration<double, std::milli>(clock_t::now() - build_start).count();
        GGML_LOG_INFO("[PERSISTENT-TG] build profile: total=%.3f ms nodes=%d ops=%d\n", build_ms, cgraph->n_nodes,
                      ops_added);
        GGML_LOG_INFO(
            "[PERSISTENT-TG] build profile ops ms: MUL_MAT=%.3f RMS_NORM=%.3f MUL=%.3f "
            "ADD=%.3f SET_ROWS=%.3f FLASH_ATTN=%.3f SOFT_MAX=%.3f GET_ROWS=%.3f\n",
            build_ms_by_op[GGML_OP_MUL_MAT], build_ms_by_op[GGML_OP_RMS_NORM], build_ms_by_op[GGML_OP_MUL],
            build_ms_by_op[GGML_OP_ADD], build_ms_by_op[GGML_OP_SET_ROWS], build_ms_by_op[GGML_OP_FLASH_ATTN_EXT],
            build_ms_by_op[GGML_OP_SOFT_MAX], build_ms_by_op[GGML_OP_GET_ROWS]);
    }

    GGML_SYCL_DEBUG("[PERSISTENT-TG] Built persistent plan: %d ops from %d graph nodes\n", ops_added, cgraph->n_nodes);
    if (g_ggml_sycl_debug) {
        GGML_SYCL_DEBUG(
            "[PERSISTENT-TG] Graph ops: MUL_MAT=%d RMS_NORM=%d MUL=%d ADD=%d GLU=%d SET_ROWS=%d "
            "ROPE=%d FLASH_ATTN=%d VIEW=%d RESHAPE=%d PERMUTE=%d CONT=%d GET_ROWS=%d CPY=%d\n",
            graph_op_counts[GGML_OP_MUL_MAT], graph_op_counts[GGML_OP_RMS_NORM], graph_op_counts[GGML_OP_MUL],
            graph_op_counts[GGML_OP_ADD], graph_op_counts[GGML_OP_GLU], graph_op_counts[GGML_OP_SET_ROWS],
            graph_op_counts[GGML_OP_ROPE], graph_op_counts[GGML_OP_FLASH_ATTN_EXT], graph_op_counts[GGML_OP_VIEW],
            graph_op_counts[GGML_OP_RESHAPE], graph_op_counts[GGML_OP_PERMUTE], graph_op_counts[GGML_OP_CONT],
            graph_op_counts[GGML_OP_GET_ROWS], graph_op_counts[GGML_OP_CPY]);
        GGML_SYCL_DEBUG(
            "[PERSISTENT-TG] Plan ops:  MUL_MAT=%d RMS_NORM=%d MUL=%d ADD=%d GLU=%d SET_ROWS=%d "
            "ROPE=%d FLASH_ATTN=%d CONT=%d | skipped VIEW=%d RESHAPE=%d PERMUTE=%d | exec GET_ROWS=%d CPY=%d\n",
            plan_op_counts[GGML_OP_MUL_MAT], plan_op_counts[GGML_OP_RMS_NORM], plan_op_counts[GGML_OP_MUL],
            plan_op_counts[GGML_OP_ADD], plan_op_counts[GGML_OP_GLU], plan_op_counts[GGML_OP_SET_ROWS],
            plan_op_counts[GGML_OP_ROPE], plan_op_counts[GGML_OP_FLASH_ATTN_EXT], plan_op_counts[GGML_OP_CONT],
            skipped_view, skipped_reshape, skipped_permute, executed_get_rows, executed_cpy);
    }

    // ─── DAG construction: build dependency edges for barrier-free scheduling ───
    if (ops_added > 0) {
        const int                     n_ops = ops_added;
        std::vector<std::vector<int>> successors(n_ops);
        std::vector<int>              in_degree(n_ops, 0);

        // 1. Intra-node chains: ops from the same graph node must execute sequentially.
        //    E.g. STRIDED_COPY (materialization) → MUL_MAT (main op) within one node.
        for (int i = 0; i < cgraph->n_nodes; i++) {
            if (node_to_last_op[i] < 0) {
                continue;
            }
            // Find the first op from this node by scanning op_to_graph_node
            int first_op = -1;
            for (int o = 0; o < n_ops; o++) {
                if (o < (int) op_to_graph_node.size() && op_to_graph_node[o] == i) {
                    if (first_op < 0) {
                        first_op = o;
                    } else {
                        // Chain: previous op → this op
                        int prev_op = o - 1;
                        if (prev_op >= 0 && prev_op < (int) op_to_graph_node.size() && op_to_graph_node[prev_op] == i) {
                            successors[prev_op].push_back(o);
                            in_degree[o]++;
                        }
                    }
                }
            }
        }

        // 2. Inter-node edges: for each graph node that produced ops, look at its
        //    src[] tensors and find the producing op via tensor_to_op.
        //    Follow view_src chains for VIEW/RESHAPE/PERMUTE nodes that don't produce ops.
        for (int i = 0; i < cgraph->n_nodes; i++) {
            if (node_to_last_op[i] < 0) {
                continue;
            }
            const ggml_tensor * node = cgraph->nodes[i];

            // The first op from this node depends on source tensor producers
            int first_op_of_node = -1;
            for (int o = 0; o < n_ops && o < (int) op_to_graph_node.size(); o++) {
                if (op_to_graph_node[o] == i) {
                    first_op_of_node = o;
                    break;
                }
            }
            if (first_op_of_node < 0) {
                continue;
            }

            for (int s = 0; s < GGML_MAX_SRC; s++) {
                const ggml_tensor * src = node->src[s];
                if (!src) {
                    continue;
                }

                // Follow view chains: VIEW/RESHAPE/PERMUTE don't produce ops,
                // so trace through view_src to find the actual producing tensor.
                const ggml_tensor * origin = src;
                while (origin && tensor_to_op.find(origin) == tensor_to_op.end()) {
                    if (origin->view_src) {
                        origin = origin->view_src;
                    } else {
                        origin = nullptr;  // external input (weight, embedding)
                    }
                }
                if (!origin) {
                    continue;  // no producer in graph
                }

                int pred_op = tensor_to_op[origin];
                if (pred_op < 0 || pred_op == first_op_of_node) {
                    continue;
                }

                // For multi-op nodes, the predecessor's LAST op feeds our FIRST op.
                // tensor_to_op already stores the last op index for the producing node.
                // Deduplicate edges
                auto & succ_list = successors[pred_op];
                if (std::find(succ_list.begin(), succ_list.end(), first_op_of_node) == succ_list.end()) {
                    succ_list.push_back(first_op_of_node);
                    in_degree[first_op_of_node]++;
                }
            }
        }

        // 2b. Fill missing edges from source_op linkage (catches SET_ROWS, GLU, etc.)
        //     The tensor_to_op approach above may miss edges when src tensors go through
        //     view chains that tensor_to_op can't fully resolve.  The input_source_op /
        //     aux_source_op fields on each OperationDescriptor are populated via
        //     find_source_op() during plan building and are authoritative.
        {
            const auto & ops = kernel.get_plan_operations();
            for (int o = 0; o < n_ops && o < (int) ops.size(); o++) {
                auto check_source = [&](int src_op) {
                    if (src_op >= 0 && src_op < n_ops && src_op != o) {
                        auto & succ = successors[src_op];
                        if (std::find(succ.begin(), succ.end(), o) == succ.end()) {
                            succ.push_back(o);
                            in_degree[o]++;
                        }
                    }
                };
                check_source(ops[o].input_source_op);
                check_source(ops[o].aux_source_op);
            }
        }

        // 3. Build the device-side DAG (reads tile counts from current_plan_ internally)
        kernel.build_dag(successors, in_degree);
        // 3b. Also build phase schedule (topological levels) for O(1) tile claiming
        kernel.build_phase_schedule(successors, in_degree);

        if (g_ggml_sycl_debug) {
            int total_edges = 0;
            int max_in = 0, max_out = 0;
            int n_roots = 0;
            for (int o = 0; o < n_ops; o++) {
                total_edges += (int) successors[o].size();
                max_out = std::max(max_out, (int) successors[o].size());
                max_in  = std::max(max_in, in_degree[o]);
                if (in_degree[o] == 0) {
                    n_roots++;
                }
            }
            GGML_SYCL_DEBUG(
                "[PERSISTENT-TG] DAG: %d ops, %d edges, %d roots, "
                "max_in=%d max_out=%d\n",
                n_ops, total_edges, n_roots, max_in, max_out);
        }
    }

    return ops_added > 0;
}

// ---------------------------------------------------------------------------
// Split-aware persistent plan builder for multi-device persistent TG.
// Builds TWO plans from a single graph:
//   - Primary (B580): all operations, matmuls compute rows [0, N_primary)
//   - Secondary (B50): only matmul operations, rows [N_primary, N)
// The secondary device writes partial results to host-pinned merge buffers.
// ---------------------------------------------------------------------------
static bool is_persistent_matmul_type(OperationType t) {
    return t == OperationType::MATMUL_Q_PROJ  || t == OperationType::MATMUL_K_PROJ  ||
           t == OperationType::MATMUL_V_PROJ  || t == OperationType::MATMUL_OUT_PROJ ||
           t == OperationType::MATMUL_GATE    || t == OperationType::MATMUL_UP       ||
           t == OperationType::MATMUL_DOWN    || t == OperationType::MATMUL_GATE_UP_SILU;
}

static MatmulType op_type_to_matmul_type(OperationType t) {
    switch (t) {
        case OperationType::MATMUL_Q_PROJ:       return MatmulType::Q_PROJ;
        case OperationType::MATMUL_K_PROJ:       return MatmulType::K_PROJ;
        case OperationType::MATMUL_V_PROJ:       return MatmulType::V_PROJ;
        case OperationType::MATMUL_OUT_PROJ:     return MatmulType::OUT_PROJ;
        case OperationType::MATMUL_GATE:         return MatmulType::GATE;
        case OperationType::MATMUL_UP:           return MatmulType::UP;
        case OperationType::MATMUL_DOWN:         return MatmulType::DOWN;
        case OperationType::MATMUL_GATE_UP_SILU: return MatmulType::GENERIC;
        default:                                  return MatmulType::GENERIC;
    }
}

// Per-matmul split metadata: stored side-band for T3 (launch orchestration) to
// populate DeviceOperation multi-device fields during kernel launch.
// Indexed by plan operation index (not matmul counter).
static int g_split_n_devices = 0;  // 0 = no split active

static bool extract_persistent_plan_split(
        ggml_sycl::UnifiedKernel &  primary_kernel,
        ggml_sycl::UnifiedKernel &  secondary_kernel,
        ggml_backend_sycl_context & ctx,
        ggml_cgraph *               cgraph,
        const split_device_config & split_cfg,
        std::vector<secondary_matmul_info> & secondary_ops_out) {

    // Step 1: Build the primary plan using the existing single-device builder.
    //         This populates primary_kernel.current_plan_ with ALL operations.
    if (!extract_persistent_plan(primary_kernel, ctx, cgraph)) {
        return false;
    }

    // Step 1b: Collect MUL_MAT weight tensors from the graph in node order.
    //          This lets us map plan matmul index -> graph weight tensor for
    //          resolve_split_weight_ptr (which needs the ggml_tensor* for cache lookup).
    std::vector<const ggml_tensor *> matmul_weight_tensors;
    for (int i = 0; i < cgraph->n_nodes; i++) {
        const ggml_tensor * node = cgraph->nodes[i];
        if (node && node->op == GGML_OP_MUL_MAT && node->src[0]) {
            matmul_weight_tensors.push_back(node->src[0]);
        }
    }

    // Step 2: Scan the primary plan to count matmul ops and find max dims.
    int n_total_ops  = 0;
    int n_matmul_ops = 0;
    int max_N        = 0;
    int max_K        = 0;
    OperationDescriptor desc;
    for (int i = 0; primary_kernel.get_op_descriptor(i, desc); i++) {
        n_total_ops++;
        if (is_persistent_matmul_type(desc.type)) {
            n_matmul_ops++;
            if (desc.N > max_N) {
                max_N = desc.N;
            }
            if (desc.K > max_K) {
                max_K = desc.K;
            }
        }
    }

    if (n_matmul_ops == 0) {
        GGML_LOG_WARN("[PERSISTENT-TG-SPLIT] No matmul ops found in plan, cannot split\n");
        return false;
    }

    const int n_devices = split_cfg.gpu_count;
    if (n_devices < 2 || !split_cfg.queue[1]) {
        GGML_LOG_WARN("[PERSISTENT-TG-SPLIT] Split requires 2 GPUs but gpu_count=%d\n", n_devices);
        return false;
    }

    // Step 3: Ensure shared host-pinned resources and device counters are allocated.
    ensure_split_persistent_resources(*split_cfg.queue[0], *split_cfg.queue[1],
                                     n_matmul_ops, max_N, max_K, n_devices);
    if (!g_split_persistent.allocated) {
        GGML_LOG_WARN("[PERSISTENT-TG-SPLIT] Failed to allocate shared resources\n");
        return false;
    }

    // Step 4: Build primary KernelSplitConfig with device-local counters
    ggml_sycl::KernelSplitConfig primary_split;
    primary_split.progress_counter = g_split_persistent.progress_counter;
    primary_split.merge_complete   = g_split_persistent.merge_complete;
    primary_split.device_idx = 0;
    primary_split.n_devices  = n_devices;
    primary_split.op_meta.assign(n_total_ops, {});

    g_split_n_devices = n_devices;

    int matmul_counter   = 0;
    int secondary_ops    = 0;
    const float ratio_primary = split_cfg.ratio[0];
    constexpr int tile_cols = 64;  // persistent matmul tile alignment

    secondary_ops_out.clear();

    for (int i = 0; primary_kernel.get_op_descriptor(i, desc); i++) {
        if (!is_persistent_matmul_type(desc.type)) {
            // Non-matmul: no split metadata (all zeros = single-device)
            continue;
        }

        const int N_total           = desc.N;
        const int N_primary_raw     = (int)(N_total * ratio_primary);
        const int N_primary_aligned = ((N_primary_raw + tile_cols - 1) / tile_cols) * tile_cols;
        const int N_secondary       = N_total - N_primary_aligned;

        if (N_secondary <= 0) {
            // All rows on primary -- no split for this op
            matmul_counter++;
            continue;
        }

        // Primary metadata: rows [0, N_primary_aligned), merge secondary's output
        float * merge_dst = static_cast<float *>(desc.output) + N_primary_aligned;  // stride=1 since M=1 in TG
        ggml_sycl::SplitOpMeta primary_meta = {};
        primary_meta.op_idx        = matmul_counter;
        primary_meta.row_start     = 0;
        primary_meta.row_count     = N_primary_aligned;
        primary_meta.merge_count   = N_secondary;
        primary_meta.merge_src     = g_split_persistent.merge_buf;
        primary_meta.merge_dst     = merge_dst;
        primary_meta.input_staging = g_split_persistent.activation_buf;
        primary_meta.input_K       = desc.K;
        primary_split.op_meta[i]   = primary_meta;

        // NOTE: Do NOT override desc.N in the plan. op.N must remain as
        // N_total for correct SOA weight addressing (d_offset = N_total *
        // k_blocks * QK4_0_PACKED). The SplitOpMeta.row_count already tells
        // the kernel how many rows to compute; see compute_matmul_tile.

        // Secondary: resolve weight pointer for B50
        const void * secondary_weight = (matmul_counter < (int) matmul_weight_tensors.size())
            ? resolve_split_weight_ptr(
                  matmul_weight_tensors[matmul_counter],
                  1,                                                   // secondary device id
                  ctx.device,                                          // primary device id
                  static_cast<layout_mode>(desc.weight_layout),
                  N_primary_aligned,
                  N_secondary)
            : nullptr;

        // Build host coordinator dispatch info for this matmul
        secondary_matmul_info info = {};
        info.op_idx        = matmul_counter;
        info.plan_op_idx   = i;                    // Plan operation index (for scratch_output lookup)
        info.N_secondary   = N_secondary;
        info.N_total       = N_total;
        info.K             = desc.K;
        info.quant_type    = desc.quant_type;
        info.weight_layout = desc.weight_layout;
        info.weight_ptr    = secondary_weight;
        info.layout_base      = secondary_weight;  // SOA base is the weight pointer itself
        info.input_device_ptr = desc.input;        // Primary device pointer to matmul activation
        info.merge_dst        = merge_dst;
        info.row_start        = N_primary_aligned;
        secondary_ops_out.push_back(info);

        secondary_ops++;
        matmul_counter++;
    }

    // Apply split config to primary kernel (consumed during launch_persistent_kernel)
    primary_kernel.set_split_config(primary_split);

    GGML_LOG_INFO("[PERSISTENT-TG-SPLIT] Host-mediated split plan: primary=%d total ops (%d matmul), "
                  "secondary=%d matmul ops, tile_align=%d, ratio=%.0f%%/%.0f%%\n",
                  n_total_ops, n_matmul_ops, secondary_ops,
                  tile_cols, ratio_primary * 100, split_cfg.ratio[1] * 100);

    return secondary_ops > 0;
}

static void debug_check_persistent_set_rows(ggml_backend_sycl_context & ctx) {
    const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_CHECK_SET_ROWS");
    if (!env || std::atoi(env) == 0) {
        return;
    }

    if (!g_persistent_set_rows_dbg.captured || !g_persistent_set_rows_dbg.src_ptr ||
        !g_persistent_set_rows_dbg.idx_ptr || !g_persistent_set_rows_dbg.dst_ptr) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS debug requested but no capture available\n");
        return;
    }

    sycl::queue * q       = ctx.stream();
    int64_t       idx_val = 0;
    if (g_persistent_set_rows_dbg.meta.idx_type == 1) {
        q->memcpy(&idx_val, g_persistent_set_rows_dbg.idx_ptr, sizeof(int64_t)).wait();
    } else {
        int32_t idx32 = 0;
        q->memcpy(&idx32, g_persistent_set_rows_dbg.idx_ptr, sizeof(int32_t)).wait();
        idx_val = idx32;
    }
    if (idx_val < 0 || idx_val >= g_persistent_set_rows_dbg.meta.ne1) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS debug: index out of range (%lld)\n", (long long) idx_val);
        return;
    }

    const int64_t sample        = std::min<int64_t>(g_persistent_set_rows_dbg.meta.nc, 8);
    const size_t  src_elem_size = (g_persistent_set_rows_dbg.meta.src_type == 1) ? sizeof(sycl::half) : sizeof(float);
    const size_t  dst_elem_size = (g_persistent_set_rows_dbg.meta.dst_type == 1) ? sizeof(sycl::half) : sizeof(float);

    const int64_t src_off = 0 * g_persistent_set_rows_dbg.meta.nb01 + 0 * g_persistent_set_rows_dbg.meta.nb02 +
                            0 * g_persistent_set_rows_dbg.meta.nb03;
    const int64_t dst_off = idx_val * g_persistent_set_rows_dbg.meta.nb1 + 0 * g_persistent_set_rows_dbg.meta.nb2 +
                            0 * g_persistent_set_rows_dbg.meta.nb3;

    std::vector<uint8_t> src_bytes(sample * src_elem_size);
    std::vector<uint8_t> dst_bytes(sample * dst_elem_size);
    q->memcpy(src_bytes.data(), (const char *) g_persistent_set_rows_dbg.src_ptr + src_off, src_bytes.size()).wait();
    q->memcpy(dst_bytes.data(), (const char *) g_persistent_set_rows_dbg.dst_ptr + dst_off, dst_bytes.size()).wait();

    GGML_LOG_INFO("[PERSISTENT-TG] SET_ROWS debug: idx=%lld sample=%lld src_type=%d dst_type=%d\n", (long long) idx_val,
                  (long long) sample, g_persistent_set_rows_dbg.meta.src_type, g_persistent_set_rows_dbg.meta.dst_type);
    for (int64_t i = 0; i < sample; i++) {
        float src_val = 0.0f;
        float dst_val = 0.0f;
        if (g_persistent_set_rows_dbg.meta.src_type == 1) {
            const sycl::half * in = reinterpret_cast<const sycl::half *>(src_bytes.data() + i * src_elem_size);
            src_val               = (float) *in;
        } else {
            const float * in = reinterpret_cast<const float *>(src_bytes.data() + i * src_elem_size);
            src_val          = *in;
        }
        if (g_persistent_set_rows_dbg.meta.dst_type == 1) {
            const sycl::half * out = reinterpret_cast<const sycl::half *>(dst_bytes.data() + i * dst_elem_size);
            dst_val                = (float) *out;
        } else {
            const float * out = reinterpret_cast<const float *>(dst_bytes.data() + i * dst_elem_size);
            dst_val           = *out;
        }
        GGML_LOG_INFO("[PERSISTENT-TG]   SET_ROWS[%lld]: src=%.6f dst=%.6f\n", (long long) i, src_val, dst_val);
    }
}

static void debug_validate_persistent_set_rows(ggml_backend_sycl_context & ctx) {
    const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_SET_ROWS");
    if (!env || std::atoi(env) == 0) {
        return;
    }

    sycl::queue * q         = ctx.stream();
    float *       dbg       = static_cast<float *>(g_persistent_set_rows_dbg.debug_ptr);
    const int     dbg_count = g_persistent_set_rows_dbg.debug_count;
    if (dbg && dbg_count > 0) {
        const int idx_debug = (int) dbg[2 * dbg_count];
        GGML_LOG_INFO("[PERSISTENT-TG] SET_ROWS debug (kernel): idx=%d sample=%d\n", idx_debug, dbg_count);
        for (int i = 0; i < dbg_count; ++i) {
            GGML_LOG_INFO("[PERSISTENT-TG]   SET_ROWS[%d]: src=%.6f dst=%.6f\n", i, dbg[i], dbg[dbg_count + i]);
        }
        sycl::free(dbg, *q);
        g_persistent_set_rows_dbg.debug_ptr   = nullptr;
        g_persistent_set_rows_dbg.debug_count = 0;
    }
    if (!g_persistent_set_rows_dbg.captured || !g_persistent_set_rows_dbg.src_ptr ||
        !g_persistent_set_rows_dbg.idx_ptr || !g_persistent_set_rows_dbg.dst_ptr) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate requested but no capture available\n");
        return;
    }
    if (g_persistent_set_rows_dbg.meta.src_type != 0) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate skipped: src_type=%d (expected F32)\n",
                      g_persistent_set_rows_dbg.meta.src_type);
        return;
    }
    if (g_persistent_set_rows_dbg.meta.dst_type != 0 && g_persistent_set_rows_dbg.meta.dst_type != 1) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate skipped: dst_type=%d\n",
                      g_persistent_set_rows_dbg.meta.dst_type);
        return;
    }
    if (g_persistent_set_rows_dbg.meta.idx_type != 0 && g_persistent_set_rows_dbg.meta.idx_type != 1) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate skipped: idx_type=%d\n",
                      g_persistent_set_rows_dbg.meta.idx_type);
        return;
    }

    const auto & meta = g_persistent_set_rows_dbg.meta;
    if (meta.nc <= 0 || meta.nr <= 0 || meta.ne1 <= 0 || meta.ne02 <= 0 || meta.ne03 <= 0) {
        GGML_LOG_WARN(
            "[PERSISTENT-TG] SET_ROWS validate skipped: invalid dims nc=%lld nr=%lld ne1=%lld ne02=%lld ne03=%lld\n",
            (long long) meta.nc, (long long) meta.nr, (long long) meta.ne1, (long long) meta.ne02,
            (long long) meta.ne03);
        return;
    }

    ggml_tensor src0 = {};
    ggml_tensor src1 = {};
    ggml_tensor dst  = {};

    src0.type  = GGML_TYPE_F32;
    src0.data  = const_cast<void *>(g_persistent_set_rows_dbg.src_ptr);
    src0.ne[0] = meta.nc;
    src0.ne[1] = meta.nr;
    src0.ne[2] = meta.ne02;
    src0.ne[3] = meta.ne03;
    src0.nb[0] = (size_t) meta.nb00;
    src0.nb[1] = (size_t) meta.nb01;
    src0.nb[2] = (size_t) meta.nb02;
    src0.nb[3] = (size_t) meta.nb03;

    src1.type  = (meta.idx_type == 1) ? GGML_TYPE_I64 : GGML_TYPE_I32;
    src1.data  = const_cast<void *>(g_persistent_set_rows_dbg.idx_ptr);
    src1.ne[0] = meta.nr;
    src1.ne[1] = meta.ne11 > 0 ? meta.ne11 : 1;
    src1.ne[2] = meta.ne12 > 0 ? meta.ne12 : 1;
    src1.ne[3] = 1;
    src1.nb[0] = (size_t) meta.nb10;
    src1.nb[1] = (size_t) meta.nb11;
    src1.nb[2] = (size_t) meta.nb12;
    src1.nb[3] = (size_t) (meta.nb12 * (meta.ne12 > 0 ? meta.ne12 : 1));

    dst.type   = (meta.dst_type == 1) ? GGML_TYPE_F16 : GGML_TYPE_F32;
    dst.ne[0]  = meta.nc;
    dst.ne[1]  = meta.ne1;
    dst.ne[2]  = meta.ne02;
    dst.ne[3]  = meta.ne03;
    dst.nb[0]  = (size_t) meta.nb0;
    dst.nb[1]  = (size_t) meta.nb1;
    dst.nb[2]  = (size_t) meta.nb2;
    dst.nb[3]  = (size_t) meta.nb3;
    dst.src[0] = &src0;
    dst.src[1] = &src1;

    const size_t dst_bytes = ggml_nbytes(&dst);
    if (dst_bytes == 0) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate skipped: zero-sized dst buffer\n");
        return;
    }
    ggml_sycl::alloc_request tmp_req;
    tmp_req.queue                          = q;
    tmp_req.device                         = ctx.device;
    tmp_req.size                           = dst_bytes;
    tmp_req.intent.role                    = ggml_sycl::alloc_role::GRAPH_TMP;
    tmp_req.intent.category                = ggml_sycl::runtime_category::GRAPH;
    tmp_req.intent.constraints.must_device = true;
    ggml_sycl::scoped_unified_alloc tmp_alloc(tmp_req);
    if (!tmp_alloc) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate skipped: alloc %zu bytes failed\n", dst_bytes);
        return;
    }
    void * tmp_dst = tmp_alloc.get();
    dst.data       = tmp_dst;
    q->memset(tmp_dst, 0, dst_bytes).wait();

    GGML_LOG_INFO("[PERSISTENT-TG] SET_ROWS validate: replaying reference kernel on current buffers\n");
    ggml_sycl_op_set_rows(ctx, &dst);
    q->wait_and_throw();

    int64_t idx_val = 0;
    if (meta.idx_type == 1) {
        q->memcpy(&idx_val, g_persistent_set_rows_dbg.idx_ptr, sizeof(int64_t)).wait();
    } else {
        int32_t idx32 = 0;
        q->memcpy(&idx32, g_persistent_set_rows_dbg.idx_ptr, sizeof(int32_t)).wait();
        idx_val = idx32;
    }
    if (idx_val < 0 || idx_val >= meta.ne1) {
        GGML_LOG_WARN("[PERSISTENT-TG] SET_ROWS validate: index out of range (%lld)\n", (long long) idx_val);
        return;
    }

    const int64_t sample        = std::min<int64_t>(meta.nc, 8);
    const size_t  dst_elem_size = (meta.dst_type == 1) ? sizeof(sycl::half) : sizeof(float);
    const int64_t dst_off       = idx_val * meta.nb1 + 0 * meta.nb2 + 0 * meta.nb3;

    std::vector<uint8_t> expected_bytes(sample * dst_elem_size);
    std::vector<uint8_t> actual_bytes(sample * dst_elem_size);
    q->memcpy(expected_bytes.data(), (const char *) tmp_dst + dst_off, expected_bytes.size()).wait();
    q->memcpy(actual_bytes.data(), (const char *) g_persistent_set_rows_dbg.dst_ptr + dst_off, actual_bytes.size())
        .wait();

    GGML_LOG_INFO("[PERSISTENT-TG] SET_ROWS validate: idx=%lld sample=%lld dst_type=%d\n", (long long) idx_val,
                  (long long) sample, meta.dst_type);
    for (int64_t i = 0; i < sample; i++) {
        float expected = 0.0f;
        float actual   = 0.0f;
        if (meta.dst_type == 1) {
            expected = (float) *reinterpret_cast<const sycl::half *>(expected_bytes.data() + i * dst_elem_size);
            actual   = (float) *reinterpret_cast<const sycl::half *>(actual_bytes.data() + i * dst_elem_size);
        } else {
            expected = *reinterpret_cast<const float *>(expected_bytes.data() + i * dst_elem_size);
            actual   = *reinterpret_cast<const float *>(actual_bytes.data() + i * dst_elem_size);
        }
        GGML_LOG_INFO("[PERSISTENT-TG]   SET_ROWS[%lld]: expected=%.6f actual=%.6f diff=%.6f\n", (long long) i,
                      expected, actual, expected - actual);
    }
}

/**
 * Check if the compute graph represents a decode phase (M=1 for all matmuls).
 */
static bool is_decode_phase_graph(ggml_cgraph * cgraph) {
    if (!cgraph || cgraph->n_nodes == 0) {
        return false;
    }
    bool found_mul_mat = false;
    for (int i = 0; i < cgraph->n_nodes; i++) {
        ggml_tensor * node = cgraph->nodes[i];
        if (node->op == GGML_OP_MUL_MAT) {
            found_mul_mat = true;
            // src[1] is the activation tensor, ne[1] is the M dimension (batch size)
            if (node->src[1] && node->src[1]->ne[1] != 1) {
                return false;  // Not decode phase if any matmul has M > 1
            }
        }
    }
    return found_mul_mat;  // Must have at least one MUL_MAT
}

static void debug_validate_persistent_attention(ggml_backend_sycl_context & ctx) {
    const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_ATTN");
    if (!env || std::atoi(env) == 0) {
        return;
    }
    float *   dbg        = g_persistent_attn_dbg.debug_ptr;
    const int dbg_floats = g_persistent_attn_dbg.debug_floats;
    if (!dbg || dbg_floats <= 0) {
        static bool warned = false;
        if (!warned) {
            warned = true;
            GGML_LOG_WARN("[PERSISTENT-TG] ATTN validate: no debug buffer captured\n");
        }
        return;
    }

    sycl::queue * q = ctx.stream();
    try {
        q->wait_and_throw();
    } catch (const sycl::exception & exc) {
        GGML_LOG_ERROR("[PERSISTENT-TG] ATTN validate: queue wait failed: %s\n", exc.what());
        return;
    }

    if (dbg[0] == 0.0f) {
        GGML_LOG_WARN("[PERSISTENT-TG] ATTN validate: debug buffer not captured\n");
        sycl::free(dbg, *q);
        g_persistent_attn_dbg.debug_ptr    = nullptr;
        g_persistent_attn_dbg.debug_floats = 0;
        return;
    }

    const int   head_dim = static_cast<int>(dbg[1]);
    const int   seq_len  = static_cast<int>(dbg[2]);
    const float scale    = dbg[3];
    if (head_dim <= 0 || seq_len <= 0) {
        GGML_LOG_WARN("[PERSISTENT-TG] ATTN validate: invalid dims head_dim=%d seq_len=%d\n", head_dim, seq_len);
        sycl::free(dbg, *q);
        g_persistent_attn_dbg.debug_ptr    = nullptr;
        g_persistent_attn_dbg.debug_floats = 0;
        return;
    }

    const size_t kv_elems = static_cast<size_t>(head_dim) * static_cast<size_t>(seq_len);
    const size_t expected_floats =
        4u + 2u * static_cast<size_t>(head_dim) + static_cast<size_t>(seq_len) + 2u * kv_elems;
    if (expected_floats > static_cast<size_t>(dbg_floats)) {
        GGML_LOG_WARN("[PERSISTENT-TG] ATTN validate: debug buffer too small (%d < %zu)\n", dbg_floats,
                      expected_floats);
        sycl::free(dbg, *q);
        g_persistent_attn_dbg.debug_ptr    = nullptr;
        g_persistent_attn_dbg.debug_floats = 0;
        return;
    }

    const float * q_vec = dbg + 4;
    const float * k_vec = q_vec + head_dim;
    const float * v_vec = k_vec + kv_elems;
    const float * mask  = v_vec + kv_elems;
    const float * out   = mask + seq_len;

    double max_score = -1e30;
    for (int p = 0; p < seq_len; p++) {
        double       dot  = 0.0;
        const size_t base = static_cast<size_t>(p) * static_cast<size_t>(head_dim);
        for (int d = 0; d < head_dim; d++) {
            dot += static_cast<double>(q_vec[d]) * static_cast<double>(k_vec[base + d]);
        }
        const double score = dot * static_cast<double>(scale) + static_cast<double>(mask[p]);
        if (score > max_score) {
            max_score = score;
        }
    }

    double sum_exp = 0.0;
    for (int p = 0; p < seq_len; p++) {
        double       dot  = 0.0;
        const size_t base = static_cast<size_t>(p) * static_cast<size_t>(head_dim);
        for (int d = 0; d < head_dim; d++) {
            dot += static_cast<double>(q_vec[d]) * static_cast<double>(k_vec[base + d]);
        }
        const double score = dot * static_cast<double>(scale) + static_cast<double>(mask[p]);
        sum_exp += std::exp(score - max_score);
    }

    std::vector<float> ref_out(head_dim, 0.0f);
    if (sum_exp > 0.0) {
        const double inv_sum = 1.0 / sum_exp;
        for (int d = 0; d < head_dim; d++) {
            double acc = 0.0;
            for (int p = 0; p < seq_len; p++) {
                double       dot  = 0.0;
                const size_t base = static_cast<size_t>(p) * static_cast<size_t>(head_dim);
                for (int dd = 0; dd < head_dim; dd++) {
                    dot += static_cast<double>(q_vec[dd]) * static_cast<double>(k_vec[base + dd]);
                }
                const double score = dot * static_cast<double>(scale) + static_cast<double>(mask[p]);
                const double prob  = std::exp(score - max_score) * inv_sum;
                acc += prob * static_cast<double>(v_vec[base + d]);
            }
            ref_out[d] = static_cast<float>(acc);
        }
    }

    float max_abs = 0.0f;
    int   max_idx = 0;
    for (int d = 0; d < head_dim; d++) {
        const float diff = std::fabs(out[d] - ref_out[d]);
        if (diff > max_abs) {
            max_abs = diff;
            max_idx = d;
        }
    }

    GGML_SYCL_DEBUG("[PERSISTENT-TG] ATTN validate: head_dim=%d seq_len=%d scale=%.6f max_abs=%.6f idx=%d\n", head_dim,
                    seq_len, scale, max_abs, max_idx);
    const int sample = std::min(head_dim, 8);
    for (int i = 0; i < sample; i++) {
        const float diff = out[i] - ref_out[i];
        GGML_SYCL_DEBUG("[PERSISTENT-TG]   ATTN[%d]: expected=%.6f actual=%.6f diff=%.6f\n", i, ref_out[i], out[i],
                        diff);
    }

    sycl::free(dbg, *q);
    g_persistent_attn_dbg.debug_ptr    = nullptr;
    g_persistent_attn_dbg.debug_floats = 0;
}

static void debug_validate_persistent_rms_norm(ggml_backend_sycl_context & ctx) {
    const char * env = std::getenv("GGML_SYCL_PERSISTENT_TG_VALIDATE_RMS_NORM");
    if (!env || std::atoi(env) == 0) {
        return;
    }
    if (!g_persistent_rms_dbg.debug_ptr || g_persistent_rms_dbg.hidden_dim <= 0) {
        static bool warned = false;
        if (!warned) {
            warned = true;
            GGML_LOG_WARN("[PERSISTENT-TG] RMS validate: no debug buffer captured\n");
        }
        return;
    }

    sycl::queue * q = ctx.stream();
    try {
        q->wait_and_throw();
    } catch (const sycl::exception & exc) {
        GGML_LOG_ERROR("[PERSISTENT-TG] RMS validate: queue wait failed: %s\n", exc.what());
        return;
    }

    const int     dim    = g_persistent_rms_dbg.hidden_dim;
    const float   eps    = g_persistent_rms_dbg.eps;
    float *       dbg    = g_persistent_rms_dbg.debug_ptr;
    const float * input  = dbg;
    const float * output = dbg + dim;

    double sum_sq = 0.0;
    for (int i = 0; i < dim; i++) {
        const double v = input[i];
        sum_sq += v * v;
    }
    const float mean  = (dim > 0) ? static_cast<float>(sum_sq / (double) dim) : 0.0f;
    const float scale = 1.0f / std::sqrt(mean + eps);

    float max_abs = 0.0f;
    int   max_idx = 0;
    for (int i = 0; i < dim; i++) {
        const float ref = input[i] * scale;
        const float err = std::fabs(output[i] - ref);
        if (err > max_abs) {
            max_abs = err;
            max_idx = i;
        }
    }

    GGML_LOG_INFO(
        "[PERSISTENT-TG] RMS validate: layer=%d dim=%d eps=%.6g max_abs=%.6g idx=%d "
        "in0=%.6g out0=%.6g ref0=%.6g\n",
        g_persistent_rms_dbg.layer, dim, eps, max_abs, max_idx, (double) input[0], (double) output[0],
        (double) (input[0] * scale));
    const char * dump_env = std::getenv("GGML_SYCL_TG_DUMP_RMS");
    if (dump_env && std::atoi(dump_env) != 0) {
        const char * path = ggml_sycl_dump_rms_path("GGML_SYCL_TG_DUMP_RMS_PERSIST_PATH", "/tmp/tg_rms_persist.bin");
        ggml_sycl_dump_rms_buffer(path, input, output, dim);
        GGML_LOG_INFO("[PERSISTENT-TG] RMS dump: layer=%d dim=%d path=%s\n", g_persistent_rms_dbg.layer, dim, path);
    }

    if (g_persistent_rms_dbg.debug_ptr) {
        sycl::free(g_persistent_rms_dbg.debug_ptr, *q);
    }
    if (g_persistent_rms_dbg.debug_flag) {
        sycl::free(g_persistent_rms_dbg.debug_flag, *q);
    }
    g_persistent_rms_dbg = {};
}

